/* AUTO-GENERATED — North Carolina Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["NC"] = {"code":"NC","name":"North Carolina","agency":"North Carolina DMV","agencyShort":"DMV","handbook":"https://www.ncdot.gov/dmv/license-id/driver-licenses/new-drivers/Documents/commercial-driver-manual.pdf","links":{},"en":[{"q":"On North Carolina highways, what is the maximum legal width of a commercial vehicle or its load without an oversize permit?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"North Carolina limits total outside width of a vehicle or its load to 102 inches (8 feet 6 inches) on all roads; anything wider requires a permit. Source: N.C. Gen. Stat. 20-116(a) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height on North Carolina highways without a permit?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"answer":2,"explanation":"North Carolina law sets the maximum vehicle height, unladen or with load, at 14 feet. Source: N.C. Gen. Stat. 20-116(c) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"In North Carolina, what is the maximum gross weight allowed on a single axle?","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"answer":1,"explanation":"North Carolina caps single-axle weight at 20,000 pounds, matching the federal standard. Source: N.C. Gen. Stat. 20-118(b)(1) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"In North Carolina, what is the maximum gross weight allowed on a tandem axle?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"answer":2,"explanation":"North Carolina sets the tandem-axle maximum at 38,000 pounds (the federal cap is 34,000; North Carolina's statutory figure is 38,000). Source: N.C. Gen. Stat. 20-118(b)(2) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"What is the maximum overall length of a single vehicle (two or more axles) in North Carolina without a permit?","options":["35 feet","40 feet","45 feet","53 feet"],"answer":1,"explanation":"A single vehicle having two or more axles may not exceed 40 feet overall, inclusive of front and rear bumpers. Source: N.C. Gen. Stat. 20-116(d)(1) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"What is the general maximum length for a combination of two vehicles coupled together in North Carolina?","options":["55 feet","60 feet","65 feet","75 feet"],"answer":1,"explanation":"No combination of two vehicles may exceed a total length of 60 feet inclusive of front and rear bumpers, except as otherwise provided. Source: N.C. Gen. Stat. 20-116(e) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"In North Carolina, a truck-tractor pulling a single semitrailer is exempt from the 60-foot combination length limit as long as the semitrailer does not exceed what length?","options":["48 feet","50 feet","53 feet","57 feet"],"answer":2,"explanation":"A truck-tractor (power unit) pulling one semitrailer of not more than 53 feet may exceed the 60-foot overall maximum on all North Carolina roads. Source: N.C. Gen. Stat. 20-116(e) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight for a typical five-axle tractor-semitrailer on North Carolina highways without an overweight permit?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"answer":2,"explanation":"North Carolina's maximum gross vehicle weight is 80,000 pounds, subject to axle and bridge-formula limits. Source: N.C. Gen. Stat. 20-118 and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"How does North Carolina determine the allowable gross weight based on axle spacing on its highways?","options":["By a flat per-axle multiplier set by the county","By the federal bridge formula based on the extreme axle measurement","By the vehicle's manufacturer GVWR only","By the number of tires touching the road"],"answer":1,"explanation":"Gross weight is determined by the extreme axle measurement under the federal bridge formula (bridge law). The 23 U.S.C. 127 allowance applies to all state roads unless posted. Source: N.C. Gen. Stat. 20-118(c)(19) and NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"Which North Carolina agency issues oversize/overweight permits for vehicles exceeding legal size or weight limits?","options":["The N.C. Division of Motor Vehicles (DMV)","The N.C. Department of Transportation (NCDOT) Oversize/Overweight Permit Unit","The N.C. State Highway Patrol","The county sheriff's office where travel begins"],"answer":1,"explanation":"Oversize/overweight permits are issued by the NCDOT Oversize/Overweight Permit Unit (Central Permit Office in Garner, NC). Source: NCDOT Oversize/Overweight Permit Handbook.","handbook":"","hbref":""},{"q":"A North Carolina single-trip oversize/overweight permit is valid for how long?","options":["5 calendar days for one trip","10 calendar days for one single trip","30 calendar days for one trip","One year from the effective date"],"answer":1,"explanation":"A single-trip permit is valid for 10 calendar days for one single trip; the state fee ranges from $12 to $48. Source: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit).","handbook":"","hbref":""},{"q":"Under a North Carolina single-trip permit, what is the maximum weight allowed on a tandem axle group (axle weights, not gross)?","options":["44,000 pounds","46,000 pounds","50,000 pounds","60,000 pounds"],"answer":2,"explanation":"On a single-trip permit, allowable axle weights are: steer 20,000; single 25,000; tandem 50,000; tridem 60,000; and four-or-more-axle group 68,000 pounds. Source: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit axle weights).","handbook":"","hbref":""},{"q":"To qualify for a North Carolina overweight permit allowing movement up to 90,000 pounds for one item, the vehicle generally must have at least what minimum wheelbase?","options":["41-foot wheelbase","48-foot wheelbase","51-foot wheelbase","57-foot wheelbase"],"answer":2,"explanation":"A vehicle combination with a minimum 51-foot wheelbase can qualify for movement up to 90,000 pounds; over 90,000 pounds the permit is route-specific. Source: NCDOT Oversize/Overweight Permit Handbook (Annual Permit / Overweight).","handbook":"","hbref":""},{"q":"In North Carolina, a load exceeding what gross weight is classified as a 'superload' requiring a written superload application and bridge engineering review?","options":["Gross weight exceeds 90,000 pounds","Gross weight exceeds 112,000 pounds","Gross weight exceeds 122,000 pounds","Gross weight exceeds 132,000 pounds"],"answer":3,"explanation":"A superload permit is required when gross weight exceeds 132,000 pounds (or steer-axle weight exceeds 20,000 pounds, or width exceeds 16 feet). It carries a $100 non-refundable application fee plus additional charges. Source: NCDOT Oversize/Overweight Permit Handbook (Superload Permit).","handbook":"","hbref":""},{"q":"When a North Carolina permitted load has a rear overhang greater than 4 feet, what must be displayed for daytime travel?","options":["An amber flashing light on the rear","An 18-inch-square red flag","A 'WIDE LOAD' banner","A red triangle reflector"],"answer":1,"explanation":"A rear overhang in excess of 4 feet must display an 18-inch-square red flag for daytime travel and clearance lights at night; the load may not extend more than 14 feet beyond the rear of the vehicle, and maximum overhang is 14 feet. Source: NCDOT Oversize/Overweight Permit Handbook (Overhang).","handbook":"","hbref":""},{"q":"On a North Carolina permit, warning flags marking the widest point of an overwidth load must be what size and color?","options":["12 inches square, yellow","16 inches square, orange only","18 inches square, red or orange","24 inches square, red only"],"answer":2,"explanation":"Flags must be 18 inches square, red or orange, placed at the widest point of overwidth or as specified on the permit. Source: NCDOT Oversize/Overweight Permit Handbook (Flags).","handbook":"","hbref":""},{"q":"On a North Carolina two-lane, two-way highway, a front escort vehicle is generally required when a permitted load exceeds what width?","options":["10 feet wide","12 feet wide","14 feet wide","16 feet wide"],"answer":1,"explanation":"A front escort is required for permitted loads more than 12 feet wide on two-lane, two-way highways, with a rear escort on multi-lane highways or as stated on the permit. Source: NCDOT Oversize/Overweight Permit Handbook (Escorts).","handbook":"","hbref":""},{"q":"Under North Carolina permit rules, a front escort is required for any permitted load whose weight is greater than what threshold?","options":["Greater than 80,000 pounds","Greater than 112,000 pounds","Greater than 132,000 pounds","Greater than 149,999 pounds"],"answer":3,"explanation":"A front escort is required for weight greater than 149,999 pounds; front and rear escorts are required for overall length of 150 feet or greater. Source: NCDOT Oversize/Overweight Permit Handbook (Escorts).","handbook":"","hbref":""},{"q":"North Carolina law provides a higher off-Interstate weight variance for agricultural and forest products. What is the increased single-axle limit under this variance?","options":["20,000 pounds","21,500 pounds","22,000 pounds","26,000 pounds"],"answer":2,"explanation":"For qualifying agricultural and forest products hauled off the Interstate system, North Carolina allows up to 22,000 pounds single axle, 42,000 pounds tandem axle, and 90,000 pounds gross. Source: N.C. Gen. Stat. 20-118(c)(12).","handbook":"","hbref":""},{"q":"North Carolina's 10 percent weight tolerance allowance applies to which limits?","options":["The single-axle and tandem-axle limits","The 80,000-pound gross limit and Interstate axle limits","Axle-group weights only, excluding single/tandem axles, the 80,000-pound gross cap, posted bridges, and Interstates","All posted bridge weight limits statewide"],"answer":2,"explanation":"The 10 percent tolerance applies to axle-group (bridge-formula) weights only; it does not apply to the single-axle or tandem-axle limits, the 80,000-pound gross maximum, posted bridges, or Interstate highways. Source: N.C. Gen. Stat. 20-118(h).","handbook":"","hbref":""},{"q":"In North Carolina, which CDL class is required to operate a combination of vehicles with a gross vehicle weight rating (GVWR) of 26,001 pounds or more, provided the vehicle being towed has a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"North Carolina follows the federal classification: a Class A CDL is required for any combination of vehicles with a GVWR of 26,001 lbs or more where the towed unit(s) exceed 10,000 lbs GVWR. Source: NCDMV Commercial Driver License page and N.C. Commercial Driver License Manual.","handbook":"","hbref":""},{"q":"Under North Carolina rules, a single vehicle with a GVWR of 26,001 pounds or more, towing a unit not exceeding 10,000 pounds GVWR, requires which CDL class?","options":["Class A","Class B","Class C","Class E"],"answer":1,"explanation":"A Class B CDL covers a single vehicle rated at 26,001 lbs GVWR or more, plus any towed vehicle not exceeding 10,000 lbs GVWR. Source: NCDMV Commercial Driver License page and N.C. CDL Manual.","handbook":"","hbref":""},{"q":"Which North Carolina CDL class applies to a vehicle that does not meet Class A or B weight thresholds but is designed to transport 16 or more passengers (including the driver) or carries placarded hazardous materials?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"In North Carolina a Class C CDL is required for vehicles not meeting Class A or B that are designed to carry 16 or more people (including the driver) or that transport placarded hazardous materials. Source: NCDMV Commercial Driver License page and N.C. CDL Manual.","handbook":"","hbref":""},{"q":"In North Carolina, what is the minimum age to obtain a CDL restricted to intrastate (within-state) commercial driving only?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"North Carolina allows a CDL at age 18 for intrastate operation only. Drivers must be 21 for interstate commerce or to carry hazardous materials. Source: NCDMV Commercial Driver License requirements; N.C.G.S. Chapter 20, Article 2C.","handbook":"","hbref":""},{"q":"A North Carolina driver must be at least how old to operate a commercial motor vehicle in interstate commerce or to hold a hazardous materials endorsement?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"North Carolina requires a minimum age of 21 for interstate commercial driving and for a hazardous materials (H) endorsement; 18 is the minimum for intrastate-only operation. Source: NCDMV Commercial Driver License requirements; N.C.G.S. Chapter 20, Article 2C.","handbook":"","hbref":""},{"q":"Which endorsement does a North Carolina CDL holder need to transport hazardous materials in quantities requiring placards?","options":["N endorsement","H endorsement","T endorsement","P endorsement"],"answer":1,"explanation":"The H (Hazardous Materials) endorsement is required to haul placardable quantities of hazardous materials. It requires a knowledge test plus a TSA security threat assessment. Source: NCDMV CDL endorsements; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In North Carolina, which endorsement is required to drive a tank vehicle designed to carry a liquid or gaseous load in a tank of at least 1,000 gallons capacity?","options":["H endorsement","T endorsement","N endorsement","X endorsement"],"answer":2,"explanation":"The N (Tank Vehicle) endorsement is required for tank vehicles with an individual rated capacity of 1,000 gallons or more carrying liquids or gases. Source: NCDMV CDL endorsements; N.C. CDL Manual; 49 CFR 383.5/383.93.","handbook":"","hbref":""},{"q":"A North Carolina CDL driver who pulls double or triple trailer combinations must hold which endorsement?","options":["T endorsement","N endorsement","P endorsement","S endorsement"],"answer":0,"explanation":"The T endorsement authorizes operation of double and triple trailer combinations. It is obtained by passing a knowledge test; no separate skills test is required. Source: NCDMV CDL endorsements; N.C. CDL Manual.","handbook":"","hbref":""},{"q":"Which combined endorsement appears on a North Carolina CDL when a driver is authorized to operate a tank vehicle that is also carrying hazardous materials?","options":["HT endorsement","X endorsement","NP endorsement","Z endorsement"],"answer":1,"explanation":"North Carolina issues the X endorsement to represent the combination of the tank (N) and hazardous materials (H) endorsements on one CDL. Source: NCDMV CDL endorsements/restrictions.","handbook":"","hbref":""},{"q":"In North Carolina, which CDL endorsements require passing a behind-the-wheel SKILLS test (not just a knowledge test)?","options":["H and N","N and T","P and S","H and T"],"answer":2,"explanation":"The Passenger (P) and School Bus (S) endorsements require a skills/road test in the appropriate vehicle, while H, N, and T are obtained by knowledge tests only. Source: NCDMV CDL endorsements; N.C. CDL Manual.","handbook":"","hbref":""},{"q":"Before a North Carolina applicant may obtain a School Bus (S) endorsement, which other endorsement must they first hold?","options":["H (HazMat)","N (Tank)","T (Doubles/Triples)","P (Passenger)"],"answer":3,"explanation":"Under federal and North Carolina rules, the School Bus (S) endorsement requires the driver to first qualify for the Passenger (P) endorsement. Source: NCDMV CDL endorsements; 49 CFR 383.93(b).","handbook":"","hbref":""},{"q":"How long is a North Carolina Commercial Learner Permit (CLP) valid before it must be renewed?","options":["90 days","180 days","1 year","30 days"],"answer":1,"explanation":"A North Carolina CLP is valid for 180 days and may be renewed one time for an additional 180 days without retaking the general knowledge test. Source: NCDMV Commercial Driver License page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Under federal rules adopted by North Carolina, what is the minimum time a CDL applicant must hold a Commercial Learner Permit before taking the CDL skills (road) test?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"An applicant must hold the CLP for a minimum of 14 days before being allowed to take the CDL skills test. North Carolina applies this federal requirement. Source: NCDMV CDL page; 49 CFR 383.25(e).","handbook":"","hbref":""},{"q":"When operating under a North Carolina Commercial Learner Permit, the CLP holder must be accompanied by a person who holds what credential?","options":["Any valid Class C driver license","A valid CDL of the same or higher class with the proper endorsements","A North Carolina instruction permit","No accompanying driver is required"],"answer":1,"explanation":"A CLP holder must always be accompanied by someone holding a valid CDL of the appropriate class and endorsements, seated in the front seat. Source: NCDMV CDL page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which entry-level driver training (ELDT) requirement applies in North Carolina for a person obtaining a CDL for the first time?","options":["Training from any private instructor of the driver's choice","Training from a provider listed on the FMCSA Training Provider Registry","Only an online video course approved by NCDMV","No formal training is required, only the tests"],"answer":1,"explanation":"Since Feb. 7, 2022, first-time CDL applicants (and those upgrading B to A or seeking P, S, or H endorsements) must complete ELDT from a provider on the FMCSA Training Provider Registry before testing. Source: FMCSA ELDT rule; NCDMV CDL page.","handbook":"","hbref":""},{"q":"For the North Carolina HazMat (H) endorsement, what type of ELDT must be completed and when?","options":["Theory-only training before the knowledge test","Behind-the-wheel training before the skills test","Both theory and behind-the-wheel before the road test","No ELDT is required for HazMat"],"answer":0,"explanation":"ELDT for the H endorsement is theory (knowledge) training only, completed through a Training Provider Registry provider before the state knowledge test; there is no behind-the-wheel component for H. Source: FMCSA ELDT rule (49 CFR Part 380, Subpart F).","handbook":"","hbref":""},{"q":"In addition to passing the knowledge test, what does North Carolina require before issuing a HazMat (H) endorsement?","options":["A vision waiver from NCDMV","A TSA security threat assessment including fingerprinting","Five years of driving experience","A separate behind-the-wheel skills test"],"answer":1,"explanation":"The H endorsement requires a TSA Hazmat Endorsement Threat Assessment Program background check with fingerprinting; the endorsement is generally renewed every five years. Source: NCDMV CDL page; TSA HME program; 49 CFR 1572.","handbook":"","hbref":""},{"q":"When applying for a North Carolina CDL, which set of documents must an applicant provide?","options":["Only a Social Security card","Proof of identity/age, Social Security number, North Carolina residency, and lawful presence","A passport and nothing else","Only proof of liability insurance"],"answer":1,"explanation":"NCDMV requires documentation of identity/date of birth, Social Security number, North Carolina residency, and lawful presence (U.S. citizenship or legal status), plus proof of liability insurance. Source: NCDMV Commercial Driver License document requirements.","handbook":"","hbref":""},{"q":"How many medical self-certification categories must a North Carolina CDL applicant choose from when certifying the type of commercial operation they perform?","options":["Two","Three","Four","Five"],"answer":2,"explanation":"North Carolina CDL holders self-certify into one of four categories: interstate non-excepted, interstate excepted, intrastate non-excepted, or intrastate excepted. Source: NCDMV CDL medical self-certification (Form CDL-MED-1).","handbook":"","hbref":""},{"q":"Which North Carolina CDL self-certification category requires the driver to maintain a valid medical examiner's certificate on file with NCDMV?","options":["Interstate excepted","Interstate non-excepted","Intrastate excepted","No category requires a medical certificate"],"answer":1,"explanation":"A driver certifying as Interstate Non-Excepted is subject to 49 CFR Part 391 and must obtain and maintain a medical examiner's certificate with NCDMV; excepted categories are not required to. Source: NCDMV CDL self-certification; 49 CFR 391.41 / 383.71.","handbook":"","hbref":""},{"q":"In North Carolina, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle?","options":["0.02","0.04","0.08","0.10"],"answer":1,"explanation":"North Carolina sets the CMV impairment threshold at 0.04 BAC under G.S. 20-138.2, half the 0.08 limit for ordinary drivers. The NC CDL manual lists driving a CMV with a BAC of 0.04 or more as a major offense.","handbook":"","hbref":""},{"q":"For a first major offense (such as DWI or a 0.04+ BAC) committed in a vehicle NOT carrying placarded hazardous materials, how long is a North Carolina CDL holder disqualified?","options":["60 days","120 days","1 year","3 years"],"answer":2,"explanation":"Under G.S. 20-17.4 and the NC CDL manual (mirroring 49 CFR 383.51), a first major offense disqualifies the driver for at least 1 year when no placarded hazardous materials are involved.","handbook":"","hbref":""},{"q":"If a North Carolina CDL holder commits a first major offense while operating a vehicle placarded for hazardous materials, the disqualification period increases to how long?","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"G.S. 20-17.4 and the NC CDL manual provide that a first major offense while transporting placarded hazardous materials results in a 3-year disqualification rather than the standard 1 year.","handbook":"","hbref":""},{"q":"Under North Carolina law, what is the disqualification for a CDL holder convicted of a SECOND major offense (a second DWI, refusal, or similar) arising from a separate incident?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"G.S. 20-17.4 and the NC CDL manual impose a lifetime CDL disqualification for a second major offense arising from a separate incident. A limited reinstatement may be possible after 10 years in some cases, but the disqualification itself is for life.","handbook":"","hbref":""},{"q":"A North Carolina CDL holder is stopped for impaired driving in a CMV and refuses to submit to a chemical (breath or blood) test. How is the refusal treated for CDL disqualification purposes?","options":["It carries no CDL penalty, only a personal-license penalty","It is a serious traffic violation (60-day disqualification)","It is a major offense (at least a 1-year disqualification)","It results in a lifetime disqualification on the first refusal"],"answer":2,"explanation":"Under North Carolina's implied-consent law and G.S. 20-17.4, refusing a chemical test is a major offense, disqualifying the driver for at least 1 year (3 years if hauling placarded hazmat), the same as a conviction.","handbook":"","hbref":""},{"q":"Under North Carolina's implied-consent statute, by operating a commercial vehicle on the state's roads a CDL driver is deemed to have consented to which of the following when lawfully stopped for impaired driving?","options":["A field sobriety test only","Chemical testing of breath, blood, or urine","A vehicle search without a warrant","Surrender of the CDL on the spot"],"answer":1,"explanation":"North Carolina's implied-consent law (G.S. 20-16.2) provides that any driver impliedly consents to a chemical analysis of breath, blood, or other bodily fluid when charged with an implied-consent offense; refusal triggers license revocation and CDL disqualification.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period (in a CMV) must a North Carolina CDL holder commit before facing a 60-day disqualification?","options":["1","2","3","4"],"answer":1,"explanation":"G.S. 20-17.4 and the NC CDL manual disqualify a driver for 60 days upon a SECOND serious traffic violation arising from separate incidents within 3 years.","handbook":"","hbref":""},{"q":"In North Carolina, a THIRD serious traffic violation within a 3-year period results in a CDL disqualification of how long?","options":["60 days","120 days","180 days","1 year"],"answer":1,"explanation":"Under G.S. 20-17.4 and the NC CDL manual, a third serious traffic violation (separate incidents) within 3 years results in a 120-day disqualification, served at the end of any prior disqualification.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a North Carolina CDL holder?","options":["Speeding 15 mph or more over the posted limit","A parking violation in a CMV","Driving 5 mph over the limit","An expired vehicle registration"],"answer":0,"explanation":"The NC CDL manual and 49 CFR 383.51 define excessive speeding (15 mph or more over the limit) as a serious traffic violation. Parking and registration offenses are expressly excluded from that category.","handbook":"","hbref":""},{"q":"Under North Carolina rules, which of these is NOT counted as a serious traffic violation for CDL disqualification purposes?","options":["Reckless driving","Following too closely","Improper or erratic lane changes","Driving a CMV with a burned-out headlight"],"answer":3,"explanation":"The NC CDL manual lists reckless driving, following too closely, and improper/erratic lane changes among serious traffic violations under G.S. 20-17.4 / 49 CFR 383.51. An equipment defect like a burned-out headlight is not on that list.","handbook":"","hbref":""},{"q":"Driving a CMV in North Carolina without the proper class of CDL or required endorsement is treated as which type of offense?","options":["A major offense (1-year disqualification)","A serious traffic violation","An out-of-service violation","A non-reportable equipment violation"],"answer":1,"explanation":"The NC CDL manual and 49 CFR 383.51 list driving a CMV without the proper CDL class or endorsement (or without the CDL in possession) as a serious traffic violation, which can trigger 60/120-day disqualifications when combined with other serious violations.","handbook":"","hbref":""},{"q":"For a North Carolina CDL holder, texting while driving a commercial motor vehicle is categorized as what for disqualification purposes?","options":["A major offense","A serious traffic violation","An out-of-service order violation","A railroad-crossing violation"],"answer":1,"explanation":"Under G.S. 20-137.4A and the NC CDL manual (consistent with 49 CFR 383.51 and 392.80), texting while driving a CMV is a serious traffic violation, contributing to 60/120-day disqualifications.","handbook":"","hbref":""},{"q":"North Carolina law restricts a CMV driver's use of a mobile telephone while driving to which of the following?","options":["Hands-free use only","Use only when stopped at a red light","Calls under one minute","Use of any handheld phone for voice calls"],"answer":0,"explanation":"G.S. 20-137.4A prohibits CMV operators subject to FMCSA Parts 390/392 from using a handheld mobile phone; only hands-free operation is permitted. A handheld-phone violation in a CMV is a serious traffic violation.","handbook":"","hbref":""},{"q":"What is the disqualification period for a North Carolina CDL holder's FIRST conviction for violating an out-of-service order while operating a CMV (non-hazmat)?","options":["At least 30 days","At least 60 days","At least 90 days","At least 180 days"],"answer":3,"explanation":"G.S. 20-17.4 and the NC CDL manual set a first out-of-service order violation at no less than 180 days (up to 1 year) for a standard CMV, well above the penalty for most serious violations.","handbook":"","hbref":""},{"q":"If a North Carolina CDL holder violates an out-of-service order while transporting placarded hazardous materials or 16+ passengers, the FIRST violation carries a disqualification of at least how long?","options":["90 days","180 days","1 year","3 years"],"answer":1,"explanation":"Under G.S. 20-17.4, a first out-of-service violation while hauling placarded hazmat or carrying 16 or more passengers is no less than 180 days (and up to 2 years), a longer maximum than the standard out-of-service offense.","handbook":"","hbref":""},{"q":"Under North Carolina law, a SECOND out-of-service order violation within a 10-year period disqualifies a CDL holder for what minimum period?","options":["180 days","1 year","2 years","5 years"],"answer":2,"explanation":"G.S. 20-17.4 and the NC CDL manual disqualify a driver for no less than 2 years (up to 5 years) for a second out-of-service order violation within any 10-year period.","handbook":"","hbref":""},{"q":"In North Carolina, what is the disqualification for a CDL holder's FIRST railroad-highway grade crossing violation committed in a CMV?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"G.S. 20-17.4 and the NC CDL manual impose a disqualification of no less than 60 days for a first railroad-highway grade crossing violation in a CMV.","handbook":"","hbref":""},{"q":"A North Carolina CDL holder commits a THIRD railroad-highway grade crossing violation within a 3-year period. What is the disqualification?","options":["60 days","120 days","At least 1 year","Lifetime"],"answer":2,"explanation":"Under G.S. 20-17.4 and the NC CDL manual, railroad-crossing violations carry 60 days (first), 120 days (second within 3 years), and no less than 1 year (third within 3 years).","handbook":"","hbref":""},{"q":"When a North Carolina CDL holder commits a moving traffic violation in a commercial vehicle for which points are assessed, how does the court treat the fine compared to a non-commercial driver?","options":["The fine is waived for CDL holders","The fine may be doubled","The fine is reduced by half","The fine is the same as for any driver"],"answer":1,"explanation":"Under North Carolina law, the court may double the fine for a CMV operator who commits a point-assessable motor vehicle violation, reflecting the higher standard placed on commercial drivers.","handbook":"","hbref":""},{"q":"When a North Carolina CDL driver refuses a chemical test or registers 0.04 or more in a CMV during an implied-consent stop, what immediate pretrial action typically applies to the driver's license before any conviction?","options":["A 10-day administrative hold","A 30-day civil revocation","A 90-day suspension","No action until conviction"],"answer":1,"explanation":"North Carolina's implied-consent law (G.S. 20-16.5) imposes a 30-day civil (pretrial) revocation of the driver's license upon a qualifying test result or refusal, separate from the CDL disqualification that follows a conviction.","handbook":"","hbref":""},{"q":"On a North Carolina controlled-access highway with six or more lanes, what restriction applies to a truck with a gross vehicle weight rating (GVWR) of 26,001 pounds or more?","options":["It may not operate in the left-most lane except when entering or exiting, passing, or avoiding a hazard","It must always travel in the right-most lane only","It may use any lane as long as it keeps up with traffic","It may use the left-most lane only between 9 p.m. and 6 a.m."],"answer":0,"explanation":"North Carolina G.S. 20-146 prohibits a vehicle with a GVWR of 26,001 pounds or more from operating in the left-most lane of a controlled-access highway with six or more lanes, except when entering or exiting the highway, passing, or avoiding a hazard. Source: N.C. Gen. Stat. 20-146.","handbook":"","hbref":""},{"q":"Under North Carolina's Move Over law, what must a driver do when approaching a stopped emergency or public service vehicle displaying flashing warning lights on a multi-lane road?","options":["Move into a lane that is not the lane nearest the stopped vehicle, if it can be done safely","Come to a complete stop in the current lane until the vehicle leaves","Sound the horn continuously while passing","Pass at no more than 5 mph below the posted speed limit"],"answer":0,"explanation":"Under N.C. Gen. Stat. 20-157, on a road with two or more lanes in the direction of travel, the driver must move into a lane not nearest the stopped emergency/public service vehicle when it can be done safely. On a single-lane road the driver must instead slow down and be prepared to stop. Source: N.C. Gen. Stat. 20-157.","handbook":"","hbref":""},{"q":"A North Carolina driver of a placarded hazardous-materials vehicle approaches a railroad grade crossing. Where must the driver stop?","options":["Within 50 feet of, but not closer than 15 feet to, the nearest rail","Within 25 feet of, but not closer than 5 feet to, the nearest rail","Within 100 feet of, but not closer than 50 feet to, the nearest rail","Exactly 10 feet from the nearest rail"],"answer":0,"explanation":"Buses and placarded/hazmat vehicles must stop within 50 feet of, and not closer than 15 feet to, the nearest rail before crossing, then look and listen. This federal standard (49 CFR 392.10) is taught in the North Carolina CDL manual and applies in North Carolina. Source: N.C. CDL Driver Handbook; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"On a two-lane North Carolina road (one lane each direction), a school bus stops with red lights flashing and its stop arm out to load children. Which vehicles must stop?","options":["Traffic approaching from both directions must stop","Only traffic behind the bus must stop","Only traffic in the oncoming direction must stop","No one must stop if drivers slow to 20 mph"],"answer":0,"explanation":"Under N.C. Gen. Stat. 20-217, on a two-lane roadway every vehicle approaching the stopped school bus from any direction on the same street must come to a full stop and remain stopped until the stop signal is withdrawn and the bus moves. Source: N.C. Gen. Stat. 20-217(a).","handbook":"","hbref":""},{"q":"Under North Carolina's school-bus stopping law, when does the driver of a vehicle traveling in the OPPOSITE direction from a stopped school bus NOT have to stop?","options":["When the road is divided into two roadways by an intervening space or a physical barrier (a center turn lane counts only if the road has at least four lanes)","Whenever the road has a painted center line of any kind","Whenever there is one lane in each direction","Whenever the opposing driver slows to 15 mph or less"],"answer":0,"explanation":"N.C. Gen. Stat. 20-217(c) exempts opposing traffic only where the road is divided into two roadways by an intervening space (including a center lane for left turns IF the roadway consists of at least four more lanes) or by a physical barrier. A simple painted center line on an undivided road does not qualify. Source: N.C. Gen. Stat. 20-217(c).","handbook":"","hbref":""},{"q":"What is the maximum speed limit the North Carolina DOT may establish on an interstate or controlled-access highway?","options":["70 mph","65 mph","75 mph","60 mph"],"answer":0,"explanation":"Under N.C. Gen. Stat. 20-141(b), a speed limit set on the interstate or controlled-access highway system may not exceed 70 miles per hour. Source: N.C. Gen. Stat. 20-141.","handbook":"","hbref":""},{"q":"On a North Carolina highway where the posted speed limit was made uniform for all vehicle types, how does the truck speed limit compare to the car speed limit?","options":["Trucks and cars have the same posted speed limit","Trucks are limited to 10 mph below the car limit","Trucks are limited to 55 mph regardless of the posted limit","Trucks may travel 5 mph faster than cars on grades"],"answer":0,"explanation":"North Carolina does not set a separate, lower statewide truck speed limit; G.S. 20-141(l) makes the posted limit uniformly applicable to all motor vehicle types. (A lower limit can apply to a specific vehicle moving under an oversize/overweight permit.) Source: N.C. Gen. Stat. 20-141(l).","handbook":"","hbref":""},{"q":"Why are commercial trucks prohibited on North Carolina's Blue Ridge Parkway?","options":["It is a narrow, winding two-lane scenic road with no truck lanes or runaway ramps","It is a private toll road open only to passenger cars","It crosses into another state without weigh stations","It has weight-restricted bridges every mile"],"answer":0,"explanation":"Commercial vehicles are banned from the Blue Ridge Parkway because it is a narrow, two-lane National Park Service scenic road with shifting grades, curves, limited sight distance, and no truck lanes or runaway truck ramps. Source: National Park Service / Blue Ridge Parkway regulations.","handbook":"","hbref":""},{"q":"A truck breaks down on a North Carolina divided highway. Where should the three emergency warning devices (reflective triangles) be placed?","options":["10 feet, 100 feet, and 200 feet to the rear, all toward approaching traffic","10 feet, 50 feet, and 150 feet, two to the rear and one to the front","5 feet, 75 feet, and 250 feet to the rear","25 feet, 100 feet, and 300 feet to the rear"],"answer":0,"explanation":"On a one-way or divided highway, all three warning devices are placed toward approaching traffic at 10, 100, and 200 feet from the stopped vehicle. (On a two-way road, one goes 10 ft to the rear, one 100 ft to the rear, and one 100 ft to the front.) Source: N.C. CDL Driver Handbook; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"The North Carolina Move Over law extends beyond police, fire, and ambulances to which additional category of vehicle?","options":["Utility, highway-maintenance, and disabled-vehicle/wrecker vehicles displaying amber flashing lights","Any passenger car using its four-way flashers","Only mail-delivery vehicles","Only out-of-state emergency vehicles"],"answer":0,"explanation":"N.C. Gen. Stat. 20-157 also covers 'public service vehicles' displaying amber flashing lights, including utility (electric, gas, water, communications), highway-maintenance, refuse, and disabled-vehicle/wrecker service vehicles. Drivers must move over or slow down for them. Source: N.C. Gen. Stat. 20-157.","handbook":"","hbref":""},{"q":"After stopping at a railroad crossing, a North Carolina bus or placarded-vehicle driver should do which of the following while crossing?","options":["Cross in a gear that will not require shifting on the tracks","Shift to a lower gear midway across to gain control","Stop again at the center of the tracks to recheck","Coast across in neutral to save fuel"],"answer":0,"explanation":"The North Carolina CDL manual instructs drivers to select a gear that lets them cross completely without shifting, and never to shift gears while on the tracks, to avoid stalling. Source: N.C. CDL Driver Handbook; 49 CFR 392.10/392.11.","handbook":"","hbref":""},{"q":"What is the minimum fine in North Carolina for unlawfully passing a stopped school bus that is loading or unloading children?","options":["$500 and a Class 1 misdemeanor","$100 and an infraction","$250 and a Class 3 misdemeanor","$1,000 and a Class 2 misdemeanor"],"answer":0,"explanation":"Under N.C. Gen. Stat. 20-217(e), passing a stopped school bus is a Class 1 misdemeanor carrying a minimum fine of $500, and no prayer for judgment continued is allowed. Striking a person raises it to a felony with higher minimum fines. Source: N.C. Gen. Stat. 20-217(e),(g).","handbook":"","hbref":""},{"q":"On the Triangle Expressway and other North Carolina Turnpike toll facilities (such as I-540), how are tolls collected?","options":["All-electronic tolling with no toll booths, using NC Quick Pass transponders or bill-by-mail","Cash-only toll booths at every interchange","A flat annual sticker fee for all trucks","Tolls are collected only at the state line"],"answer":0,"explanation":"North Carolina's toll roads use 100% all-electronic tolling with no booths; drivers pay via an NC Quick Pass transponder/account or receive a bill by mail. Trucks are charged more based on the number of axles. Source: NCDOT Turnpike Authority / NC Quick Pass.","handbook":"","hbref":""},{"q":"What is the standard fine for a basic violation of North Carolina's Move Over law (no injury or property damage)?","options":["$250 infraction","$50 infraction","$500 Class 1 misdemeanor","$1,000 felony"],"answer":0,"explanation":"A basic violation of N.C. Gen. Stat. 20-157 is an infraction punishable by a $250 fine. It escalates to a misdemeanor with property damage over $500 or injury, and to a Class F felony if it causes serious injury or death. Source: N.C. Gen. Stat. 20-157.","handbook":"","hbref":""},{"q":"Under North Carolina's keep-right rule, where must a vehicle traveling slower than the legal maximum speed normally be driven?","options":["In the right-hand lane available for through traffic, or as close as practicable to the right edge","In whichever lane is least crowded","In the center lane of a three-lane road","In the left lane to leave the right lane open for merging"],"answer":0,"explanation":"N.C. Gen. Stat. 20-146 requires any vehicle proceeding at less than the legal maximum speed to drive in the right-hand through lane, or as close as practicable to the right edge, except when passing or preparing for a left turn. Source: N.C. Gen. Stat. 20-146.","handbook":"","hbref":""},{"q":"For purposes of North Carolina's school-bus stop law, which of these is treated as a 'school bus' that requires other traffic to stop?","options":["A public school bus transporting senior citizens under G.S. 115C-243 and marked 'school bus' front and rear","Any yellow van used by a daycare, marked or not","A charter motorcoach with tinted windows","Any vehicle with red brake lights"],"answer":0,"explanation":"N.C. Gen. Stat. 20-217(b) defines a covered school bus to include a public school bus carrying children or personnel, a public school bus carrying senior citizens under G.S. 115C-243, or a privately owned bus carrying children, but only when it bears plainly visible 'school bus' signs on the front and rear. Source: N.C. Gen. Stat. 20-217(b).","handbook":"","hbref":""},{"q":"At which North Carolina railroad crossing is a CDL driver NOT required to stop, even when hauling placarded hazmat?","options":["A crossing where a police officer or flagger is directing traffic through","Any crossing with crossbucks but no gates","A crossing on a rural two-lane highway","A crossing with a posted speed limit over 45 mph"],"answer":0,"explanation":"A required stop is excused at crossings controlled by a police officer or flagger, at streetcar/industrial switching tracks in a business district, at crossings marked 'Exempt' or 'Abandoned,' and where a functioning highway traffic signal shows green. Source: N.C. CDL Driver Handbook; 49 CFR 392.10(b).","handbook":"","hbref":""},{"q":"A school bus stops on a North Carolina road that has two travel lanes in each direction separated only by a continuous center two-way left-turn lane (a five-lane road). Must opposing traffic stop?","options":["No, because a center left-turn lane qualifies as a dividing space when the road has at least four lanes","Yes, because a turn lane is not a physical barrier","Yes, all roads require opposing traffic to stop","No, opposing traffic never has to stop on any multi-lane road"],"answer":0,"explanation":"G.S. 20-217(c) lets opposing traffic continue when the road is divided by an intervening space, and it specifically includes a center lane for left turns IF the roadway consists of at least four lanes. A five-lane road with a center turn lane meets that test, so opposing traffic need not stop. Source: N.C. Gen. Stat. 20-217(c).","handbook":"","hbref":""},{"q":"A driver is convicted a second time within three years of passing a stopped school bus in North Carolina. What is the license consequence in addition to the fine?","options":["Revocation of the driver license for one year","A 30-day suspension only","No license action, just points","Permanent revocation on the second offense"],"answer":0,"explanation":"Under N.C. Gen. Stat. 20-217(g1), a second misdemeanor conviction under this section within a three-year period results in a one-year license revocation; a CDL holder is also disqualified from driving a commercial vehicle for that period. Source: N.C. Gen. Stat. 20-217(g1).","handbook":"","hbref":""},{"q":"North Carolina may set a lower posted speed limit for a particular commercial vehicle in which circumstance?","options":["When the vehicle is operating under a special oversize/overweight permit because of its weight or dimensions","Whenever the vehicle has more than two axles","Whenever the vehicle is registered out of state","Whenever the trailer is more than 40 feet long"],"answer":0,"explanation":"N.C. Gen. Stat. 20-141(l) allows a lower speed limit to be established for a vehicle operating under a special permit because of any weight or dimension of the vehicle or its load. Otherwise the posted limit is uniform for all vehicle types. Source: N.C. Gen. Stat. 20-141(l); NCDOT oversize/overweight permit rules.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in North Carolina?","options":["The Federal Motor Carrier Safety Administration (FMCSA)","The North Carolina Department of Public Safety","The North Carolina Department of Transportation Highway Patrol","The North Carolina Division of Motor Vehicles (NCDMV)"],"answer":3,"explanation":"In North Carolina, CDLs are issued and administered by the North Carolina Division of Motor Vehicles (NCDMV), a division of NCDOT. FMCSA sets the federal standards but does not issue licenses. Source: NCDMV Commercial Driver License page and N.C. CDL Manual, Section 1.","handbook":"","hbref":""},{"q":"To get a North Carolina CDL or commercial learner permit, what two types of tests must an applicant pass?","options":["A written test and a vehicle weight test","Knowledge tests and skills tests","A physical agility test and an endorsement test","An employer road test and a federal exam"],"answer":1,"explanation":"The N.C. CDL Manual (Section 1.1) states that to get a CDL or CLP you must pass knowledge tests and skills tests. The skills test is given in the class of vehicle you wish to be licensed for. Source: N.C. CDL Manual, Section 1.1.","handbook":"","hbref":""},{"q":"The North Carolina CDL skills test consists of which three parts?","options":["Written knowledge, vision screening, and a road test","Air brake check, coupling test, and a highway test","Vehicle (pre-trip) inspection, basic vehicle control, and on-road driving","Backing, parallel parking, and a night-driving test"],"answer":2,"explanation":"Per the N.C. CDL Manual (Section 1.1.2), the skills test has three parts: the vehicle (pre-trip) inspection test, the basic vehicle control test, and the on-road driving test. All three must be passed in the appropriate class of vehicle. Source: N.C. CDL Manual, Section 1.1.2.","handbook":"","hbref":""},{"q":"Which knowledge test must EVERY North Carolina CDL applicant take, regardless of class or endorsements?","options":["The general knowledge test","The combination vehicles test","The air brakes test","The hazardous materials test"],"answer":0,"explanation":"The N.C. CDL Manual (Section 1.1.1) states the general knowledge test is taken by all applicants. Other tests (combination, air brakes, hazmat, etc.) apply only to specific classes or endorsements. Source: N.C. CDL Manual, Section 1.1.1.","handbook":"","hbref":""},{"q":"What is the minimum passing score on each North Carolina CDL knowledge test?","options":["70% correct","80% correct","75% correct","85% correct"],"answer":1,"explanation":"North Carolina requires at least 80% correct on each CDL knowledge test (for example, 40 of 50 on the general knowledge test, 16 of 20 on combination or air brakes), scored separately. Source: NCDMV CDL knowledge testing standards (FMCSA minimum adopted by N.C.).","handbook":"","hbref":""},{"q":"How long is a North Carolina Commercial Learner Permit (CLP) valid?","options":["30 days, with no renewal allowed","180 days, with one renewal for an additional 180 days","1 year, with unlimited renewals","60 days, renewable once for 60 days"],"answer":1,"explanation":"A North Carolina CLP is valid for 180 days and may be renewed one time for an additional 180 days without retaking the general knowledge test. Source: NCDMV Commercial Driver License page; N.C. CDL Manual (CLP), consistent with 49 CFR 383.25.","handbook":"","hbref":""},{"q":"After being issued a North Carolina CLP, how long must an applicant wait before taking the CDL skills test?","options":["At least 30 days","At least 7 days","At least 60 days","At least 14 days"],"answer":3,"explanation":"A CLP holder must wait at least 14 days after the CLP is issued before taking the CDL skills test. This federal rule (49 CFR 383.25) is applied by NCDMV. Source: NCDMV Commercial Driver License page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Before a first-time North Carolina Class A or Class B applicant can take the CDL skills test, what federal training must be completed?","options":["A state-run defensive driving course at an NCDMV office","120 hours of behind-the-wheel time logged with any licensed CDL holder","Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry","An OSHA workplace safety certification"],"answer":2,"explanation":"Federal Entry-Level Driver Training (ELDT) must be completed through a provider listed on the FMCSA Training Provider Registry before testing for a first-time Class A/B CDL (and for the P, S, and H endorsements or a B-to-A upgrade). Source: NCDMV CDL page; FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"Besides first-time Class A and Class B applicants, ELDT is also required before testing for which endorsements?","options":["Tank (N), Doubles/Triples (T), and Air Brakes","Combination, Air Brakes, and Tank (N)","Passenger (P), School Bus (S), and Hazardous Materials (H)","Hazardous Materials (H) only"],"answer":2,"explanation":"ELDT applies before first-time Class A/B issuance, a B-to-A upgrade, and the Passenger (P), School Bus (S), and Hazardous Materials (H) endorsements. The H endorsement requires the theory-only ELDT. Source: NCDMV CDL page; FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"North Carolina CDL applicants must self-certify their type of commercial driving. How many self-certification categories are there?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification categories: interstate non-excepted, interstate excepted, intrastate non-excepted, and intrastate excepted. The applicant checks the box that matches their operation. Source: N.C. CDL Manual, Section 1.2.3.","handbook":"","hbref":""},{"q":"Which North Carolina self-certification category requires the driver to provide and maintain a federal DOT medical examiner's certificate?","options":["Interstate excepted","Interstate non-excepted","Intrastate excepted","Excepted private passenger"],"answer":1,"explanation":"An interstate non-excepted driver certifies they are subject to and meet the federal DOT medical requirements under 49 CFR Part 391 and must obtain a medical examiner's certificate. Most interstate CDL holders are non-excepted. Source: N.C. CDL Manual, Section 1.2.3.","handbook":"","hbref":""},{"q":"A North Carolina driver who operates only in interstate commerce but exclusively in operations excepted from 49 CFR Part 391 should self-certify as:","options":["Interstate non-excepted","Intrastate non-excepted","Interstate excepted","Intrastate excepted"],"answer":2,"explanation":"An interstate excepted driver certifies they operate in interstate commerce but engage exclusively in operations excepted under 49 CFR 390.3(f), 391.2, 391.68 or 398.3, and is NOT required to obtain a medical examiner's certificate. Source: N.C. CDL Manual, Section 1.2.3.","handbook":"","hbref":""},{"q":"Under North Carolina rules, if a driver operates in BOTH interstate and intrastate commerce, which category must they choose?","options":["Intrastate commerce","Interstate commerce (the more demanding category)","Whichever they drive most often","They may choose either one freely"],"answer":1,"explanation":"The N.C. CDL Manual (Section 1.2.1) states that a driver operating in both interstate and intrastate commerce must choose interstate commerce, because it carries the stricter qualification requirements. Source: N.C. CDL Manual, Section 1.2.1.","handbook":"","hbref":""},{"q":"Under the FMCSA National Registry process now used by North Carolina, how does a non-excepted driver's DOT medical examiner's certificate normally reach NCDMV?","options":["The driver must mail a paper copy directly to NCDMV every two years","The employer faxes the medical card to the NCDMV headquarters","The driver's doctor calls the NCDMV medical unit to report results","The certified medical examiner submits the exam results electronically to the FMCSA National Registry, which transmits them to NCDMV"],"answer":3,"explanation":"Under the FMCSA National Registry / NRII process (compliance in 2025), certified medical examiners electronically submit CDL/CLP exam results to the National Registry, and FMCSA transmits the medical certification status to the state (NCDMV). Drivers no longer need to deliver the paper card to NCDMV. Source: FMCSA National Registry rule; NCDMV medical certification guidance.","handbook":"","hbref":""},{"q":"Self-certification of a driver's commerce category in North Carolina is required at which of these times?","options":["Only one time, when the original CDL is first issued","Only when the driver changes employers","When applying for a CLP, and when renewing, upgrading, adding endorsements, or transferring a CDL","Only when the driver turns 65 years old"],"answer":2,"explanation":"Drivers must provide self-certification information to the state when applying for a CLP, and when renewing, upgrading, adding endorsements to, or transferring a CDL. Source: N.C. CDL Manual, Section 1.2 (federal medical certification requirements).","handbook":"","hbref":""},{"q":"What is the standard validity period of a North Carolina CDL (for a renewed license, for a driver under 65)?","options":["5 years","4 years","8 years","10 years"],"answer":0,"explanation":"Under N.C.G.S. 20-7, a renewed commercial driver license expires five years after the expiration date of the license being renewed. CDLs cannot be renewed online and must be renewed in person at an NCDMV office. Source: N.C.G.S. 20-7; NCDMV license renewal page.","handbook":"","hbref":""},{"q":"How does North Carolina CDL renewal differ from a standard (Class C) license renewal?","options":["A CDL can be renewed online for up to two years after expiration","A CDL is automatically renewed by the employer's motor carrier","A CDL never expires once the driver passes the road test","A CDL must be renewed in person at an NCDMV driver license office; it cannot be renewed online or by mail"],"answer":3,"explanation":"North Carolina CDLs must be renewed in person at an NCDMV driver license office and cannot be renewed online or by mail, unlike many standard licenses. Source: NCDMV license renewal/replacement page; N.C.G.S. 20-7.","handbook":"","hbref":""},{"q":"When applying for a North Carolina CLP, which of the following documents is required as part of the application?","options":["Proof of identity/age, Social Security number, residency, and proof of liability insurance","A high school diploma and a notarized employer letter","A passport only, with no other documentation","Proof of vehicle ownership and a vehicle title"],"answer":0,"explanation":"NCDMV requires a CLP applicant to present proof of identity and age, proof of Social Security number, two residency documents (legal-presence proof for non-citizens), and proof of liability insurance from a North Carolina-licensed provider. Source: NCDMV Commercial Driver License page.","handbook":"","hbref":""},{"q":"In North Carolina, how many attempts at a single CDL knowledge test are allowed in one day?","options":["One attempt per test per day","Three attempts per test per day","Unlimited attempts in one day","Two attempts per test per day"],"answer":0,"explanation":"The N.C. CDL Manual states only one attempt at each knowledge test is allowed per day. After three failed attempts at the general knowledge test, another application fee is required for the next three attempts. Source: N.C. CDL Manual, Section 1.1.","handbook":"","hbref":""},{"q":"Once passed, how long are North Carolina CDL test scores valid in NCDMV computer files?","options":["30 days from the test date","180 days from the test date","1 year from the test date","90 days from the test date"],"answer":3,"explanation":"The N.C. CDL Manual notes that all test scores are valid for 90 days from the test date in NCDMV computer files. An applicant must complete the remaining requirements within that window. Source: N.C. CDL Manual, Section 1.1.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая законом ширина коммерческого транспортного средства или его груза на дорогах Северной Каролины без разрешения на негабаритный груз?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Северная Каролина ограничивает общую наружную ширину транспортного средства или его груза до 102 inches (8 feet 6 inches) на всех дорогах; всё, что шире, требует разрешения. Источник: N.C. Gen. Stat. 20-116(a) и NCDOT Oversize/Overweight Permit Handbook."},"1":{"q":"Какова максимальная разрешённая законом высота транспортного средства на дорогах Северной Каролины без разрешения?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Закон Северной Каролины устанавливает максимальную высоту транспортного средства, без груза или с грузом, в 14 feet. Источник: N.C. Gen. Stat. 20-116(c) и NCDOT Oversize/Overweight Permit Handbook."},"2":{"q":"Какова максимальная полная нагрузка, допустимая на одиночную ось в Северной Каролине?","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"Северная Каролина ограничивает нагрузку на одиночную ось до 20,000 pounds, что соответствует федеральному стандарту. Источник: N.C. Gen. Stat. 20-118(b)(1) и NCDOT Oversize/Overweight Permit Handbook."},"3":{"q":"Какова максимальная полная нагрузка, допустимая на сдвоенную ось (тандем) в Северной Каролине?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"Северная Каролина устанавливает максимум для сдвоенной оси в 38,000 pounds (федеральный предел составляет 34,000; установленный законом показатель Северной Каролины — 38,000). Источник: N.C. Gen. Stat. 20-118(b)(2) и NCDOT Oversize/Overweight Permit Handbook."},"4":{"q":"Какова максимальная общая длина одиночного транспортного средства (с двумя или более осями) в Северной Каролине без разрешения?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Одиночное транспортное средство с двумя или более осями не может превышать 40 feet в общей длине, включая передний и задний бамперы. Источник: N.C. Gen. Stat. 20-116(d)(1) и NCDOT Oversize/Overweight Permit Handbook."},"5":{"q":"Какова общая максимальная длина для сцепки из двух транспортных средств, соединённых вместе, в Северной Каролине?","options":["55 feet","60 feet","65 feet","75 feet"],"explanation":"Никакая сцепка из двух транспортных средств не может превышать общую длину в 60 feet, включая передний и задний бамперы, за исключением случаев, предусмотренных иначе. Источник: N.C. Gen. Stat. 20-116(e) и NCDOT Oversize/Overweight Permit Handbook."},"6":{"q":"В Северной Каролине седельный тягач, тянущий один полуприцеп, освобождается от ограничения длины сцепки в 60 feet, если полуприцеп не превышает какой длины?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"Седельный тягач (силовая установка), тянущий один полуприцеп длиной не более 53 feet, может превышать общий максимум в 60 feet на всех дорогах Северной Каролины. Источник: N.C. Gen. Stat. 20-116(e) и NCDOT Oversize/Overweight Permit Handbook."},"7":{"q":"Каков максимальный полный вес типичного пятиосного автопоезда (тягач с полуприцепом) на дорогах Северной Каролины без разрешения на перевес?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"Максимальный полный вес транспортного средства в Северной Каролине составляет 80,000 pounds, с учётом ограничений по осям и формуле моста (bridge formula). Источник: N.C. Gen. Stat. 20-118 и NCDOT Oversize/Overweight Permit Handbook."},"8":{"q":"Как Северная Каролина определяет допустимый полный вес в зависимости от расстояния между осями на своих дорогах?","options":["По фиксированному множителю на ось, установленному округом","По федеральной формуле моста на основе измерения крайних осей","Только по заводскому показателю GVWR транспортного средства","По числу шин, касающихся дороги"],"explanation":"Полный вес определяется по измерению крайних осей согласно федеральной формуле моста (закон о мостах). Допуск по 23 U.S.C. 127 применяется ко всем дорогам штата, если не установлено иное. Источник: N.C. Gen. Stat. 20-118(c)(19) и NCDOT Oversize/Overweight Permit Handbook."},"9":{"q":"Какое ведомство Северной Каролины выдаёт разрешения на негабаритные/перевесные грузы для транспортных средств, превышающих установленные законом ограничения по размеру или весу?","options":["N.C. Division of Motor Vehicles (DMV)","N.C. Department of Transportation (NCDOT) Oversize/Overweight Permit Unit","N.C. State Highway Patrol","Управление шерифа округа, где начинается поездка"],"explanation":"Разрешения на негабаритные/перевесные грузы выдаёт NCDOT Oversize/Overweight Permit Unit (Central Permit Office в Garner, NC). Источник: NCDOT Oversize/Overweight Permit Handbook."},"10":{"q":"Сколько действует разрешение Северной Каролины на негабаритный/перевесный груз для одной поездки (single-trip)?","options":["5 calendar days для одной поездки","10 calendar days для одной разовой поездки","30 calendar days для одной поездки","Один год с даты вступления в силу"],"explanation":"Разрешение на одну поездку действует 10 calendar days для одной разовой поездки; сбор штата составляет от $12 до $48. Источник: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit)."},"11":{"q":"По разрешению Северной Каролины на одну поездку, каков максимальный вес, допустимый на группу сдвоенных осей (вес на оси, а не полный вес)?","options":["44,000 pounds","46,000 pounds","50,000 pounds","60,000 pounds"],"explanation":"По разрешению на одну поездку допустимые нагрузки на оси составляют: рулевая 20,000; одиночная 25,000; сдвоенная 50,000; строенная (tridem) 60,000; и группа из четырёх или более осей 68,000 pounds. Источник: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit axle weights)."},"12":{"q":"Чтобы получить в Северной Каролине разрешение на перевес, допускающее перемещение до 90,000 pounds для одного предмета, транспортное средство, как правило, должно иметь как минимум какую минимальную колёсную базу?","options":["Колёсная база 41-foot","Колёсная база 48-foot","Колёсная база 51-foot","Колёсная база 57-foot"],"explanation":"Сцепка транспортных средств с минимальной колёсной базой 51-foot может претендовать на перемещение до 90,000 pounds; свыше 90,000 pounds разрешение выдаётся для конкретного маршрута. Источник: NCDOT Oversize/Overweight Permit Handbook (Annual Permit / Overweight)."},"13":{"q":"В Северной Каролине груз, превышающий какой полный вес, классифицируется как «суперлоуд» (superload), требующий письменной заявки на superload и инженерной проверки мостов?","options":["Полный вес превышает 90,000 pounds","Полный вес превышает 112,000 pounds","Полный вес превышает 122,000 pounds","Полный вес превышает 132,000 pounds"],"explanation":"Разрешение на superload требуется, когда полный вес превышает 132,000 pounds (либо вес на рулевую ось превышает 20,000 pounds, либо ширина превышает 16 feet). Оно влечёт невозвратный сбор за заявку в $100 плюс дополнительные платежи. Источник: NCDOT Oversize/Overweight Permit Handbook (Superload Permit)."},"14":{"q":"Когда у груза, перевозимого по разрешению Северной Каролины, задний свес превышает 4 feet, что должно отображаться при движении в дневное время?","options":["Жёлтый проблесковый маячок сзади","Красный флаг размером 18-inch-square","Баннер «WIDE LOAD»","Красный треугольный светоотражатель"],"explanation":"Задний свес, превышающий 4 feet, должен обозначаться красным флагом размером 18-inch-square при движении в дневное время и габаритными огнями ночью; груз не может выступать более чем на 14 feet за заднюю часть транспортного средства, а максимальный свес составляет 14 feet. Источник: NCDOT Oversize/Overweight Permit Handbook (Overhang)."},"15":{"q":"По разрешению Северной Каролины, предупреждающие флаги, обозначающие самую широкую точку негабаритного по ширине груза, должны быть какого размера и цвета?","options":["12 inches square, жёлтые","16 inches square, только оранжевые","18 inches square, красные или оранжевые","24 inches square, только красные"],"explanation":"Флаги должны быть размером 18 inches square, красные или оранжевые, размещаться в самой широкой точке негабаритного по ширине груза или как указано в разрешении. Источник: NCDOT Oversize/Overweight Permit Handbook (Flags)."},"16":{"q":"На двухполосной двусторонней автодороге Северной Каролины передний автомобиль сопровождения, как правило, требуется, когда перевозимый по разрешению груз превышает какую ширину?","options":["10 feet wide","12 feet wide","14 feet wide","16 feet wide"],"explanation":"Переднее сопровождение требуется для грузов по разрешению шире 12 feet на двухполосных двусторонних автодорогах, с задним сопровождением на многополосных автодорогах или как указано в разрешении. Источник: NCDOT Oversize/Overweight Permit Handbook (Escorts)."},"17":{"q":"По правилам разрешений Северной Каролины переднее сопровождение требуется для любого перевозимого по разрешению груза, вес которого превышает какой порог?","options":["Более 80,000 pounds","Более 112,000 pounds","Более 132,000 pounds","Более 149,999 pounds"],"explanation":"Переднее сопровождение требуется при весе более 149,999 pounds; переднее и заднее сопровождение требуются при общей длине 150 feet или более. Источник: NCDOT Oversize/Overweight Permit Handbook (Escorts)."},"18":{"q":"Закон Северной Каролины предусматривает повышенный весовой допуск вне системы Interstate для сельскохозяйственной и лесной продукции. Каков увеличенный предел для одиночной оси по этому допуску?","options":["20,000 pounds","21,500 pounds","22,000 pounds","26,000 pounds"],"explanation":"Для соответствующей требованиям сельскохозяйственной и лесной продукции, перевозимой вне системы Interstate, Северная Каролина допускает до 22,000 pounds на одиночную ось, 42,000 pounds на сдвоенную ось и 90,000 pounds полного веса. Источник: N.C. Gen. Stat. 20-118(c)(12)."},"19":{"q":"К каким ограничениям применяется 10-процентный весовой допуск Северной Каролины?","options":["К ограничениям для одиночной и сдвоенной осей","К пределу полного веса 80,000-pound и пределам по осям на Interstate","Только к весам группы осей, исключая одиночные/сдвоенные оси, предел полного веса 80,000-pound, мосты с ограничениями и Interstate","Ко всем ограничениям по весу на обозначенных мостах по всему штату"],"explanation":"10-процентный допуск применяется только к весам группы осей (по формуле моста); он не применяется к пределам для одиночной или сдвоенной оси, к максимуму полного веса 80,000-pound, к мостам с ограничениями или к автодорогам Interstate. Источник: N.C. Gen. Stat. 20-118(h)."},"20":{"q":"В Северной Каролине какой класс CDL требуется для управления сцепкой транспортных средств с полной массой (GVWR) 26,001 pounds или более, при условии, что буксируемое транспортное средство имеет GVWR более 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Северная Каролина следует федеральной классификации: CDL Class A требуется для любой сцепки транспортных средств с GVWR 26,001 lbs или более, где буксируемый(ые) блок(и) превышают 10,000 lbs GVWR. Источник: страница Commercial Driver License на сайте NCDMV и N.C. Commercial Driver License Manual."},"21":{"q":"По правилам Северной Каролины, одиночное транспортное средство с GVWR 26,001 pounds или более, буксирующее блок, не превышающий 10,000 pounds GVWR, требует какого класса CDL?","options":["Class A","Class B","Class C","Class E"],"explanation":"CDL Class B охватывает одиночное транспортное средство с расчётной массой 26,001 lbs GVWR или более, плюс любое буксируемое транспортное средство, не превышающее 10,000 lbs GVWR. Источник: страница Commercial Driver License на сайте NCDMV и N.C. CDL Manual."},"22":{"q":"Какой класс CDL в Северной Каролине применяется к транспортному средству, которое не соответствует весовым порогам Class A или B, но рассчитано на перевозку 16 или более пассажиров (включая водителя) или перевозит маркированные плакардами опасные материалы?","options":["Class A","Class B","Class C","Class M"],"explanation":"В Северной Каролине CDL Class C требуется для транспортных средств, не соответствующих Class A или B, которые рассчитаны на перевозку 16 или более человек (включая водителя) или перевозят маркированные плакардами опасные материалы. Источник: страница Commercial Driver License на сайте NCDMV и N.C. CDL Manual."},"23":{"q":"Каков в Северной Каролине минимальный возраст для получения CDL, ограниченного только внутриштатным (intrastate) коммерческим вождением?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Северная Каролина разрешает CDL с 18 лет только для внутриштатной (intrastate) деятельности. Для межштатной (interstate) перевозки или перевозки опасных материалов водители должны быть в возрасте 21 года. Источник: требования Commercial Driver License на сайте NCDMV; N.C.G.S. Chapter 20, Article 2C."},"24":{"q":"Какого минимального возраста должен достичь водитель в Северной Каролине, чтобы управлять коммерческим автотранспортным средством в межштатной (interstate) перевозке или иметь право на endorsement по опасным материалам?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Северная Каролина требует минимальный возраст 21 год для межштатного (interstate) коммерческого вождения и для endorsement по опасным материалам (H); 18 лет — минимум только для внутриштатной (intrastate) деятельности. Источник: требования Commercial Driver License на сайте NCDMV; N.C.G.S. Chapter 20, Article 2C."},"25":{"q":"Какой endorsement нужен держателю CDL в Северной Каролине для перевозки опасных материалов в количествах, требующих плакардов?","options":["endorsement N","endorsement H","endorsement T","endorsement P"],"explanation":"endorsement H (HazMat, опасные материалы) требуется для перевозки опасных материалов в количествах, требующих плакардов. Он требует сдачи теоретического теста плюс прохождения проверки угрозы безопасности TSA. Источник: endorsements CDL на сайте NCDMV; 49 CFR 383.93."},"26":{"q":"Какой endorsement в Северной Каролине требуется для управления цистерной, предназначенной для перевозки жидкого или газообразного груза в ёмкости вместимостью не менее 1,000 gallons?","options":["endorsement H","endorsement T","endorsement N","endorsement X"],"explanation":"endorsement N (Tank Vehicle, цистерна) требуется для цистерн с индивидуальной расчётной вместимостью 1,000 gallons или более, перевозящих жидкости или газы. Источник: endorsements CDL на сайте NCDMV; N.C. CDL Manual; 49 CFR 383.5/383.93."},"27":{"q":"Какой endorsement должен иметь водитель CDL в Северной Каролине, который тянет сцепки с двумя или тремя прицепами?","options":["endorsement T","endorsement N","endorsement P","endorsement S"],"explanation":"endorsement T даёт право на управление сцепками с двумя и тремя прицепами. Он получается путём сдачи теоретического теста; отдельный практический тест по навыкам не требуется. Источник: endorsements CDL на сайте NCDMV; N.C. CDL Manual."},"28":{"q":"Какой комбинированный endorsement отображается на CDL в Северной Каролине, когда водитель имеет право управлять цистерной, которая также перевозит опасные материалы?","options":["endorsement HT","endorsement X","endorsement NP","endorsement Z"],"explanation":"Северная Каролина выдаёт endorsement X для обозначения комбинации endorsement по цистерне (N) и по опасным материалам (H) на одном CDL. Источник: endorsements/restrictions CDL на сайте NCDMV."},"29":{"q":"Какие endorsements CDL в Северной Каролине требуют сдачи практического теста по навыкам вождения (SKILLS test), а не только теоретического теста?","options":["H и N","N и T","P и S","H и T"],"explanation":"endorsements Passenger (P, пассажирский) и School Bus (S, школьный автобус) требуют практического/дорожного теста на соответствующем транспортном средстве, тогда как H, N и T получаются только путём теоретических тестов. Источник: endorsements CDL на сайте NCDMV; N.C. CDL Manual."},"30":{"q":"Прежде чем заявитель в Северной Каролине сможет получить endorsement School Bus (S, школьный автобус), какой другой endorsement он должен иметь сначала?","options":["H (HazMat)","N (цистерна)","T (Doubles/Triples)","P (пассажирский)"],"explanation":"Согласно федеральным правилам и правилам Северной Каролины, endorsement School Bus (S, школьный автобус) требует, чтобы водитель сначала получил право на endorsement Passenger (P, пассажирский). Источник: endorsements CDL на сайте NCDMV; 49 CFR 383.93(b)."},"31":{"q":"Сколько действует Commercial Learner Permit (CLP) Северной Каролины, прежде чем его необходимо продлить?","options":["90 days","180 days","1 year","30 days"],"explanation":"CLP Северной Каролины действует 180 days и может быть продлён один раз ещё на 180 days без повторной сдачи общего теоретического теста. Источник: страница Commercial Driver License на сайте NCDMV; 49 CFR 383.25."},"32":{"q":"Согласно федеральным правилам, принятым в Северной Каролине, каков минимальный срок, в течение которого заявитель на CDL должен иметь Commercial Learner Permit, прежде чем сдавать практический (дорожный) тест на CDL?","options":["7 days","14 days","30 days","60 days"],"explanation":"Заявитель должен иметь CLP минимум 14 days, прежде чем ему будет разрешено сдавать практический тест на CDL. Северная Каролина применяет это федеральное требование. Источник: страница CDL на сайте NCDMV; 49 CFR 383.25(e)."},"33":{"q":"При управлении транспортным средством по Commercial Learner Permit Северной Каролины держатель CLP должен находиться в сопровождении лица, обладающего каким документом?","options":["Любым действительным водительским удостоверением Class C","Действительным CDL того же или более высокого класса с надлежащими endorsements","Северокаролинским учебным разрешением (instruction permit)","Сопровождающий водитель не требуется"],"explanation":"Держатель CLP всегда должен находиться в сопровождении лица, обладающего действительным CDL соответствующего класса и endorsements, сидящего на переднем сиденье. Источник: страница CDL на сайте NCDMV; 49 CFR 383.25."},"34":{"q":"Какое требование к начальной подготовке водителей (ELDT) применяется в Северной Каролине для лица, получающего CDL впервые?","options":["Подготовка у любого частного инструктора по выбору водителя","Подготовка у провайдера, внесённого в FMCSA Training Provider Registry","Только онлайн-видеокурс, одобренный NCDMV","Никакой формальной подготовки не требуется, только тесты"],"explanation":"С 7 февраля 2022 года заявители на CDL впервые (а также повышающие класс с B до A или желающие получить endorsements P, S или H) должны пройти ELDT у провайдера из FMCSA Training Provider Registry перед тестированием. Источник: правило FMCSA ELDT; страница CDL на сайте NCDMV."},"35":{"q":"Для endorsement HazMat (H) в Северной Каролине, какой тип ELDT должен быть пройден и когда?","options":["Только теоретическая подготовка перед теоретическим тестом","Практическая подготовка за рулём перед практическим тестом","Как теоретическая, так и практическая за рулём перед дорожным тестом","ELDT для HazMat не требуется"],"explanation":"ELDT для endorsement H — это только теоретическая (knowledge) подготовка, пройденная через провайдера Training Provider Registry перед теоретическим тестом штата; для H нет практического компонента за рулём. Источник: правило FMCSA ELDT (49 CFR Part 380, Subpart F)."},"36":{"q":"Помимо сдачи теоретического теста, что требует Северная Каролина перед выдачей endorsement HazMat (H)?","options":["Освобождение по зрению (vision waiver) от NCDMV","Проверку угрозы безопасности TSA, включая снятие отпечатков пальцев","Пять лет водительского стажа","Отдельный практический тест по навыкам вождения"],"explanation":"endorsement H требует проверки биографии по программе TSA Hazmat Endorsement Threat Assessment Program со снятием отпечатков пальцев; endorsement обычно продлевается каждые пять лет. Источник: страница CDL на сайте NCDMV; программа TSA HME; 49 CFR 1572."},"37":{"q":"При подаче заявления на CDL в Северной Каролине, какой набор документов должен предоставить заявитель?","options":["Только карточку Social Security","Подтверждение личности/возраста, номер Social Security, проживание в Северной Каролине и законность пребывания","Только паспорт и ничего больше","Только подтверждение страхования гражданской ответственности"],"explanation":"NCDMV требует документы, подтверждающие личность/дату рождения, номер Social Security, проживание в Северной Каролине и законность пребывания (гражданство США или законный статус), плюс подтверждение страхования гражданской ответственности. Источник: требования к документам Commercial Driver License на сайте NCDMV."},"38":{"q":"Из скольких категорий медицинской самосертификации должен выбрать заявитель на CDL в Северной Каролине при сертификации типа коммерческой деятельности, которую он осуществляет?","options":["Двух","Трёх","Четырёх","Пяти"],"explanation":"Держатели CDL в Северной Каролине самосертифицируются в одну из четырёх категорий: межштатная без исключений (interstate non-excepted), межштатная с исключениями (interstate excepted), внутриштатная без исключений (intrastate non-excepted) или внутриштатная с исключениями (intrastate excepted). Источник: медицинская самосертификация CDL на сайте NCDMV (Form CDL-MED-1)."},"39":{"q":"Какая категория самосертификации CDL в Северной Каролине требует, чтобы водитель имел действительную справку медицинского эксперта в досье в NCDMV?","options":["Interstate excepted","Interstate non-excepted","Intrastate excepted","Ни одна категория не требует медицинской справки"],"explanation":"Водитель, сертифицирующийся как Interstate Non-Excepted, подпадает под действие 49 CFR Part 391 и должен получить и поддерживать справку медицинского эксперта в NCDMV; категории с исключениями (excepted) этого не требуют. Источник: самосертификация CDL на сайте NCDMV; 49 CFR 391.41 / 383.71."},"40":{"q":"Какова в Северной Каролине максимальная концентрация алкоголя в крови (BAC), при которой человек может законно управлять коммерческим автотранспортным средством?","options":["0.02","0.04","0.08","0.10"],"explanation":"Северная Каролина устанавливает порог опьянения для CMV в 0.04 BAC согласно G.S. 20-138.2, что составляет половину предела 0.08 для обычных водителей. Руководство NC CDL относит управление CMV с BAC 0.04 или более к серьёзным правонарушениям (major offense)."},"41":{"q":"За первое серьёзное правонарушение (например, DWI или BAC 0.04+), совершённое в транспортном средстве, НЕ перевозящем маркированные плакардами опасные материалы, на какой срок дисквалифицируется держатель CDL в Северной Каролине?","options":["60 days","120 days","1 year","3 years"],"explanation":"Согласно G.S. 20-17.4 и руководству NC CDL (отражающим 49 CFR 383.51), первое серьёзное правонарушение дисквалифицирует водителя минимум на 1 year, когда маркированные плакардами опасные материалы не задействованы."},"42":{"q":"Если держатель CDL в Северной Каролине совершает первое серьёзное правонарушение при управлении транспортным средством, маркированным плакардами для опасных материалов, до какого срока увеличивается период дисквалификации?","options":["1 year","2 years","3 years","5 years"],"explanation":"G.S. 20-17.4 и руководство NC CDL предусматривают, что первое серьёзное правонарушение во время перевозки маркированных плакардами опасных материалов влечёт дисквалификацию на 3 years вместо стандартного 1 year."},"43":{"q":"Согласно закону Северной Каролины, какова дисквалификация для держателя CDL, осуждённого за ВТОРОЕ серьёзное правонарушение (второе DWI, отказ или подобное), возникшее в результате отдельного инцидента?","options":["3 years","5 years","10 years","Пожизненно"],"explanation":"G.S. 20-17.4 и руководство NC CDL налагают пожизненную дисквалификацию CDL за второе серьёзное правонарушение, возникшее в результате отдельного инцидента. В некоторых случаях ограниченное восстановление может быть возможным через 10 years, но сама дисквалификация является пожизненной."},"44":{"q":"Держателя CDL в Северной Каролине останавливают за вождение в состоянии опьянения в CMV, и он отказывается пройти химический анализ (дыхания или крови). Как трактуется отказ для целей дисквалификации CDL?","options":["Он не влечёт наказания по CDL, только наказание по личным правам","Это серьёзное нарушение ПДД (дисквалификация на 60 days)","Это серьёзное правонарушение (дисквалификация минимум на 1 year)","Он влечёт пожизненную дисквалификацию при первом отказе"],"explanation":"Согласно закону Северной Каролины о подразумеваемом согласии (implied consent) и G.S. 20-17.4, отказ от химического анализа является серьёзным правонарушением (major offense), дисквалифицирующим водителя минимум на 1 year (3 years при перевозке маркированных плакардами опасных грузов), так же как и осуждение."},"45":{"q":"Согласно закону Северной Каролины о подразумеваемом согласии (implied consent), управляя коммерческим транспортным средством на дорогах штата, водитель CDL считается давшим согласие на что из перечисленного при законной остановке за вождение в состоянии опьянения?","options":["Только на тест на трезвость на месте (field sobriety test)","На химический анализ дыхания, крови или мочи","На обыск транспортного средства без ордера","На сдачу CDL на месте"],"explanation":"Закон Северной Каролины о подразумеваемом согласии (G.S. 20-16.2) предусматривает, что любой водитель подразумеваемо соглашается на химический анализ дыхания, крови или другой биологической жидкости при обвинении в правонарушении, подпадающем под подразумеваемое согласие; отказ влечёт отзыв прав и дисквалификацию CDL."},"46":{"q":"Сколько серьёзных нарушений ПДД в течение 3-летнего периода (в CMV) должен совершить держатель CDL в Северной Каролине, прежде чем ему грозит дисквалификация на 60 days?","options":["1","2","3","4"],"explanation":"G.S. 20-17.4 и руководство NC CDL дисквалифицируют водителя на 60 days при ВТОРОМ серьёзном нарушении ПДД, возникшем в результате отдельных инцидентов в течение 3 лет."},"47":{"q":"В Северной Каролине ТРЕТЬЕ серьёзное нарушение ПДД в течение 3-летнего периода влечёт дисквалификацию CDL на какой срок?","options":["60 days","120 days","180 days","1 year"],"explanation":"Согласно G.S. 20-17.4 и руководству NC CDL, третье серьёзное нарушение ПДД (отдельные инциденты) в течение 3 лет влечёт дисквалификацию на 120 days, отбываемую по окончании любой предыдущей дисквалификации."},"48":{"q":"Что из перечисленного классифицируется как «серьёзное нарушение ПДД» для держателя CDL в Северной Каролине?","options":["Превышение скорости на 15 mph или более сверх установленного лимита","Нарушение правил парковки в CMV","Движение со скоростью на 5 mph выше лимита","Просроченная регистрация транспортного средства"],"explanation":"Руководство NC CDL и 49 CFR 383.51 определяют чрезмерное превышение скорости (на 15 mph или более сверх лимита) как серьёзное нарушение ПДД. Нарушения правил парковки и регистрации прямо исключены из этой категории."},"49":{"q":"Согласно правилам Северной Каролины, что из этого НЕ засчитывается как серьёзное нарушение ПДД для целей дисквалификации CDL?","options":["Безрассудное вождение (reckless driving)","Слишком близкая дистанция (following too closely)","Неправильная или беспорядочная смена полос","Управление CMV с перегоревшей фарой"],"explanation":"Руководство NC CDL перечисляет безрассудное вождение, слишком близкую дистанцию и неправильную/беспорядочную смену полос среди серьёзных нарушений ПДД согласно G.S. 20-17.4 / 49 CFR 383.51. Дефект оборудования, такой как перегоревшая фара, в этот список не входит."},"50":{"q":"Управление CMV в Северной Каролине без надлежащего класса CDL или требуемого endorsement трактуется как какой тип правонарушения?","options":["Серьёзное правонарушение (major offense, дисквалификация на 1 year)","Серьёзное нарушение ПДД (serious traffic violation)","Нарушение предписания о выводе из эксплуатации (out-of-service)","Несообщаемое нарушение по оборудованию"],"explanation":"Руководство NC CDL и 49 CFR 383.51 относят управление CMV без надлежащего класса CDL или endorsement (либо без наличия CDL при себе) к серьёзным нарушениям ПДД, что может повлечь дисквалификации на 60/120 days при сочетании с другими серьёзными нарушениями."},"51":{"q":"Для держателя CDL в Северной Каролине отправка текстовых сообщений во время управления коммерческим автотранспортным средством классифицируется как что для целей дисквалификации?","options":["Серьёзное правонарушение (major offense)","Серьёзное нарушение ПДД (serious traffic violation)","Нарушение предписания о выводе из эксплуатации (out-of-service)","Нарушение на железнодорожном переезде"],"explanation":"Согласно G.S. 20-137.4A и руководству NC CDL (в соответствии с 49 CFR 383.51 и 392.80), отправка текстовых сообщений во время управления CMV является серьёзным нарушением ПДД, способствующим дисквалификациям на 60/120 days."},"52":{"q":"Закон Северной Каролины ограничивает использование водителем CMV мобильного телефона во время вождения чем из перечисленного?","options":["Только использование hands-free (без рук)","Использование только при остановке на красный свет","Звонки продолжительностью менее одной минуты","Использование любого ручного телефона для голосовых вызовов"],"explanation":"G.S. 20-137.4A запрещает операторам CMV, подпадающим под FMCSA Parts 390/392, использовать ручной мобильный телефон; разрешена только работа в режиме hands-free. Нарушение с использованием ручного телефона в CMV является серьёзным нарушением ПДД."},"53":{"q":"Каков период дисквалификации для держателя CDL в Северной Каролине за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) при управлении CMV (без опасных грузов)?","options":["Не менее 30 days","Не менее 60 days","Не менее 90 days","Не менее 180 days"],"explanation":"G.S. 20-17.4 и руководство NC CDL устанавливают за первое нарушение предписания о выводе из эксплуатации срок не менее 180 days (до 1 year) для стандартного CMV, что значительно выше наказания за большинство серьёзных нарушений."},"54":{"q":"Если держатель CDL в Северной Каролине нарушает предписание о выводе из эксплуатации (out-of-service order) во время перевозки маркированных плакардами опасных материалов или 16+ пассажиров, ПЕРВОЕ нарушение влечёт дисквалификацию не менее чем на какой срок?","options":["90 days","180 days","1 year","3 years"],"explanation":"Согласно G.S. 20-17.4, первое нарушение предписания о выводе из эксплуатации во время перевозки маркированных плакардами опасных грузов или 16 и более пассажиров составляет не менее 180 days (и до 2 years), что является более длительным максимумом, чем для стандартного нарушения out-of-service."},"55":{"q":"Согласно закону Северной Каролины, ВТОРОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) в течение 10-летнего периода дисквалифицирует держателя CDL на какой минимальный срок?","options":["180 days","1 year","2 years","5 years"],"explanation":"G.S. 20-17.4 и руководство NC CDL дисквалифицируют водителя не менее чем на 2 years (до 5 years) за второе нарушение предписания о выводе из эксплуатации в течение любого 10-летнего периода."},"56":{"q":"Какова в Северной Каролине дисквалификация за ПЕРВОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing), совершённое держателем CDL в CMV?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"G.S. 20-17.4 и руководство NC CDL налагают дисквалификацию не менее чем на 60 days за первое нарушение на железнодорожном переезде в CMV."},"57":{"q":"Держатель CDL в Северной Каролине совершает ТРЕТЬЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в течение 3-летнего периода. Какова дисквалификация?","options":["60 days","120 days","Не менее 1 year","Пожизненно"],"explanation":"Согласно G.S. 20-17.4 и руководству NC CDL, нарушения на железнодорожных переездах влекут 60 days (первое), 120 days (второе в течение 3 лет) и не менее 1 year (третье в течение 3 лет)."},"58":{"q":"Когда держатель CDL в Северной Каролине совершает движущееся нарушение ПДД в коммерческом транспортном средстве, за которое начисляются штрафные баллы, как суд трактует штраф по сравнению с некоммерческим водителем?","options":["Штраф отменяется для держателей CDL","Штраф может быть удвоен","Штраф уменьшается вдвое","Штраф такой же, как для любого водителя"],"explanation":"Согласно закону Северной Каролины, суд может удвоить штраф для оператора CMV, совершившего нарушение ПДД, за которое начисляются баллы, что отражает более высокие требования, предъявляемые к коммерческим водителям."},"59":{"q":"Когда водитель CDL в Северной Каролине отказывается от химического анализа или показывает 0.04 или более в CMV во время остановки по подразумеваемому согласию, какое немедленное досудебное действие обычно применяется к водительскому удостоверению до какого-либо осуждения?","options":["Административное удержание на 10 days","Гражданский отзов на 30 days","Приостановка на 90 days","Никаких действий до осуждения"],"explanation":"Закон Северной Каролины о подразумеваемом согласии (G.S. 20-16.5) налагает гражданский (досудебный) отзыв водительского удостоверения на 30 days при квалифицирующем результате анализа или отказе, отдельно от дисквалификации CDL, которая следует за осуждением."},"60":{"q":"На автомагистрали Северной Каролины с ограниченным доступом, имеющей шесть или более полос, какое ограничение применяется к грузовику с полной разрешённой массой (GVWR) 26 001 фунт или более?","options":["Он не может двигаться в крайней левой полосе, кроме случаев въезда или выезда, обгона или объезда опасности","Он всегда должен двигаться только в крайней правой полосе","Он может использовать любую полосу, пока не отстаёт от потока","Он может использовать крайнюю левую полосу только с 9 вечера до 6 утра"],"explanation":"Закон Северной Каролины G.S. 20-146 запрещает транспортному средству с полной разрешённой массой (GVWR) 26 001 фунт или более двигаться в крайней левой полосе автомагистрали с ограниченным доступом, имеющей шесть или более полос, за исключением случаев въезда или выезда с автомагистрали, обгона или объезда опасности. Источник: N.C. Gen. Stat. 20-146."},"61":{"q":"Согласно закону Северной Каролины «Move Over», что должен сделать водитель при приближении к остановившемуся аварийному или специальному служебному транспортному средству с включёнными мигающими предупреждающими огнями на многополосной дороге?","options":["Перестроиться в полосу, не являющуюся ближайшей к остановившемуся транспортному средству, если это можно сделать безопасно","Полностью остановиться в текущей полосе, пока транспортное средство не уедет","Непрерывно подавать звуковой сигнал во время проезда","Проезжать со скоростью не более чем на 5 mph ниже установленного ограничения скорости"],"explanation":"Согласно N.C. Gen. Stat. 20-157, на дороге с двумя или более полосами в направлении движения водитель должен перестроиться в полосу, не являющуюся ближайшей к остановившемуся аварийному/специальному служебному транспортному средству, когда это можно сделать безопасно. На однополосной дороге водитель должен вместо этого снизить скорость и быть готовым остановиться. Источник: N.C. Gen. Stat. 20-157."},"62":{"q":"Водитель в Северной Каролине, управляющий транспортным средством с опасными грузами и установленными табличками (placards), приближается к железнодорожному переезду. Где должен остановиться водитель?","options":["В пределах 50 футов, но не ближе 15 футов к ближайшему рельсу","В пределах 25 футов, но не ближе 5 футов к ближайшему рельсу","В пределах 100 футов, но не ближе 50 футов к ближайшему рельсу","Ровно в 10 футах от ближайшего рельса"],"explanation":"Автобусы и транспортные средства с табличками/опасными грузами должны останавливаться в пределах 50 футов, но не ближе 15 футов к ближайшему рельсу перед переездом, затем смотреть и слушать. Этот федеральный стандарт (49 CFR 392.10) изложен в руководстве CDL Северной Каролины и применяется в Северной Каролине. Источник: N.C. CDL Driver Handbook; 49 CFR 392.10."},"63":{"q":"На двухполосной дороге в Северной Каролине (по одной полосе в каждом направлении) школьный автобус останавливается с мигающими красными огнями и выдвинутым знаком «стоп», чтобы посадить детей. Какие транспортные средства должны остановиться?","options":["Транспорт, приближающийся с обоих направлений, должен остановиться","Только транспорт позади автобуса должен остановиться","Только встречный транспорт должен остановиться","Никто не обязан останавливаться, если водители снижают скорость до 20 mph"],"explanation":"Согласно N.C. Gen. Stat. 20-217, на двухполосной дороге каждое транспортное средство, приближающееся к остановившемуся школьному автобусу с любого направления по той же улице, должно полностью остановиться и оставаться на месте, пока стоп-сигнал не будет убран и автобус не тронется. Источник: N.C. Gen. Stat. 20-217(a)."},"64":{"q":"Согласно закону Северной Каролины об остановке у школьного автобуса, когда водитель транспортного средства, движущегося в ПРОТИВОПОЛОЖНОМ направлении от остановившегося школьного автобуса, НЕ обязан останавливаться?","options":["Когда дорога разделена на две проезжие части разделительным пространством или физическим барьером (центральная полоса для поворота засчитывается только если дорога имеет не менее четырёх полос)","Всякий раз, когда на дороге есть нанесённая центральная разметка любого вида","Всякий раз, когда есть по одной полосе в каждом направлении","Всякий раз, когда встречный водитель снижает скорость до 15 mph или менее"],"explanation":"N.C. Gen. Stat. 20-217(c) освобождает встречный транспорт от остановки только там, где дорога разделена на две проезжие части разделительным пространством (включая центральную полосу для левых поворотов, ЕСЛИ проезжая часть состоит как минимум из четырёх полос) или физическим барьером. Простая нанесённая центральная разметка на неразделённой дороге не подходит под это условие. Источник: N.C. Gen. Stat. 20-217(c)."},"65":{"q":"Какое максимальное ограничение скорости может установить North Carolina DOT на межштатной автомагистрали или автомагистрали с ограниченным доступом?","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"Согласно N.C. Gen. Stat. 20-141(b), ограничение скорости, установленное на системе межштатных автомагистралей или автомагистралей с ограниченным доступом, не может превышать 70 миль в час. Источник: N.C. Gen. Stat. 20-141."},"66":{"q":"На автомагистрали Северной Каролины, где установленное ограничение скорости сделано единым для всех типов транспортных средств, как соотносится ограничение скорости для грузовиков с ограничением для легковых автомобилей?","options":["Для грузовиков и легковых автомобилей действует одинаковое установленное ограничение скорости","Для грузовиков ограничение на 10 mph ниже, чем для легковых автомобилей","Грузовики ограничены 55 mph независимо от установленного ограничения","Грузовики могут двигаться на 5 mph быстрее легковых автомобилей на подъёмах"],"explanation":"Северная Каролина не устанавливает отдельное, более низкое общегосударственное ограничение скорости для грузовиков; G.S. 20-141(l) делает установленное ограничение единообразно применимым ко всем типам автотранспортных средств. (Более низкое ограничение может применяться к конкретному транспортному средству, движущемуся по разрешению на негабаритный/сверхтяжёлый груз.) Источник: N.C. Gen. Stat. 20-141(l)."},"67":{"q":"Почему коммерческим грузовикам запрещено движение по бульвару Blue Ridge Parkway в Северной Каролине?","options":["Это узкая, извилистая двухполосная живописная дорога без полос для грузовиков и аварийных съездов","Это частная платная дорога, открытая только для легковых автомобилей","Она пересекает границу другого штата без весовых станций","На ней есть мосты с ограничением по весу через каждую милю"],"explanation":"Коммерческим транспортным средствам запрещён въезд на Blue Ridge Parkway, потому что это узкая двухполосная живописная дорога Национальной службы парков с переменными уклонами, поворотами, ограниченной видимостью и без полос для грузовиков или аварийных съездов для грузовиков. Источник: правила National Park Service / Blue Ridge Parkway."},"68":{"q":"Грузовик ломается на разделённой автомагистрали в Северной Каролине. Где следует разместить три аварийных предупреждающих устройства (светоотражающие треугольники)?","options":["В 10 футах, 100 футах и 200 футах позади, все в сторону приближающегося транспорта","В 10 футах, 50 футах и 150 футах, два позади и один спереди","В 5 футах, 75 футах и 250 футах позади","В 25 футах, 100 футах и 300 футах позади"],"explanation":"На дороге с односторонним движением или разделённой автомагистрали все три предупреждающих устройства размещаются в сторону приближающегося транспорта на расстоянии 10, 100 и 200 футов от остановившегося транспортного средства. (На двусторонней дороге одно ставится в 10 футах позади, одно в 100 футах позади и одно в 100 футах впереди.) Источник: N.C. CDL Driver Handbook; 49 CFR 392.22."},"69":{"q":"Закон Северной Каролины «Move Over» распространяется не только на полицию, пожарных и машины скорой помощи, но и на какую дополнительную категорию транспортных средств?","options":["Коммунальные, дорожно-ремонтные и аварийные/эвакуаторные транспортные средства с включёнными жёлтыми мигающими огнями","Любой легковой автомобиль с включённой аварийной сигнализацией","Только транспортные средства доставки почты","Только аварийные транспортные средства из других штатов"],"explanation":"N.C. Gen. Stat. 20-157 также охватывает «специальные служебные транспортные средства» с включёнными жёлтыми мигающими огнями, включая коммунальные (электро-, газо-, водо-, связь), дорожно-ремонтные, мусоровозные и аварийные/эвакуаторные транспортные средства. Водители должны перестроиться или снизить скорость для них. Источник: N.C. Gen. Stat. 20-157."},"70":{"q":"После остановки на железнодорожном переезде водитель автобуса или транспортного средства с табличками в Северной Каролине должен сделать что из перечисленного во время переезда?","options":["Переезжать на передаче, которая не потребует переключения на путях","Переключиться на пониженную передачу посередине переезда для контроля","Снова остановиться в центре путей для повторной проверки","Переезжать накатом на нейтрали для экономии топлива"],"explanation":"Руководство CDL Северной Каролины предписывает водителям выбирать передачу, позволяющую полностью пересечь переезд без переключения, и никогда не переключать передачи на путях, чтобы избежать остановки двигателя. Источник: N.C. CDL Driver Handbook; 49 CFR 392.10/392.11."},"71":{"q":"Каков минимальный штраф в Северной Каролине за незаконный обгон остановившегося школьного автобуса, который высаживает или забирает детей?","options":["$500 и проступок класса 1 (Class 1 misdemeanor)","$100 и правонарушение (infraction)","$250 и проступок класса 3 (Class 3 misdemeanor)","$1,000 и проступок класса 2 (Class 2 misdemeanor)"],"explanation":"Согласно N.C. Gen. Stat. 20-217(e), обгон остановившегося школьного автобуса является проступком класса 1 (Class 1 misdemeanor) с минимальным штрафом $500, и отложение приговора (prayer for judgment continued) не допускается. Наезд на человека повышает это до уголовного преступления (felony) с более высокими минимальными штрафами. Источник: N.C. Gen. Stat. 20-217(e),(g)."},"72":{"q":"На скоростной автомагистрали Triangle Expressway и других платных объектах North Carolina Turnpike (таких как I-540) как взимается плата за проезд?","options":["Полностью электронный сбор платы без пунктов оплаты, с использованием транспондеров NC Quick Pass или счёта по почте","Пункты оплаты только за наличные на каждой развязке","Фиксированная ежегодная плата за наклейку для всех грузовиков","Плата взимается только на границе штата"],"explanation":"Платные дороги Северной Каролины используют 100% полностью электронный сбор платы без пунктов оплаты; водители платят через транспондер/счёт NC Quick Pass или получают счёт по почте. С грузовиков взимается больше в зависимости от количества осей. Источник: NCDOT Turnpike Authority / NC Quick Pass."},"73":{"q":"Каков стандартный штраф за базовое нарушение закона Северной Каролины «Move Over» (без травм или повреждения имущества)?","options":["Правонарушение (infraction) с штрафом $250","Правонарушение (infraction) с штрафом $50","Проступок класса 1 (Class 1 misdemeanor) с штрафом $500","Уголовное преступление (felony) с штрафом $1,000"],"explanation":"Базовое нарушение N.C. Gen. Stat. 20-157 является правонарушением (infraction), наказуемым штрафом $250. Оно повышается до проступка (misdemeanor) при повреждении имущества свыше $500 или травме, и до уголовного преступления класса F (Class F felony), если оно вызывает серьёзную травму или смерть. Источник: N.C. Gen. Stat. 20-157."},"74":{"q":"Согласно правилу Северной Каролины о движении по правой стороне, где обычно должно двигаться транспортное средство, движущееся медленнее установленной законом максимальной скорости?","options":["В правой полосе, доступной для сквозного движения, или как можно ближе к правому краю","В той полосе, которая наименее загружена","В центральной полосе трёхполосной дороги","В левой полосе, чтобы оставить правую полосу свободной для въезда"],"explanation":"N.C. Gen. Stat. 20-146 требует, чтобы любое транспортное средство, движущееся со скоростью ниже установленной законом максимальной, двигалось в правой полосе сквозного движения или как можно ближе к правому краю, за исключением обгона или подготовки к левому повороту. Источник: N.C. Gen. Stat. 20-146."},"75":{"q":"Для целей закона Северной Каролины об остановке у школьного автобуса, что из перечисленного считается «школьным автобусом», требующим остановки остального транспорта?","options":["Государственный школьный автобус, перевозящий пожилых граждан в соответствии с G.S. 115C-243 и имеющий маркировку «school bus» спереди и сзади","Любой жёлтый фургон, используемый детским садом, с маркировкой или без","Чартерный туристический автобус с тонированными окнами","Любое транспортное средство с красными стоп-сигналами"],"explanation":"N.C. Gen. Stat. 20-217(b) определяет охватываемый школьный автобус как включающий государственный школьный автобус, перевозящий детей или персонал, государственный школьный автобус, перевозящий пожилых граждан в соответствии с G.S. 115C-243, или частный автобус, перевозящий детей, но только когда он имеет ясно видимые знаки «school bus» спереди и сзади. Источник: N.C. Gen. Stat. 20-217(b)."},"76":{"q":"На каком железнодорожном переезде в Северной Каролине водитель CDL НЕ обязан останавливаться, даже при перевозке опасных грузов с табличками?","options":["На переезде, где полицейский или регулировщик направляет движение","На любом переезде с крестообразными знаками (crossbucks), но без шлагбаумов","На переезде на сельской двухполосной автомагистрали","На переезде с установленным ограничением скорости свыше 45 mph"],"explanation":"Обязательная остановка не требуется на переездах, регулируемых полицейским или регулировщиком, на трамвайных/промышленных маневровых путях в деловом районе, на переездах с маркировкой «Exempt» или «Abandoned», а также там, где работающий дорожный светофор показывает зелёный. Источник: N.C. CDL Driver Handbook; 49 CFR 392.10(b)."},"77":{"q":"Школьный автобус останавливается на дороге в Северной Каролине, имеющей две полосы движения в каждом направлении, разделённые только непрерывной центральной двусторонней полосой для левого поворота (пятиполосная дорога). Должен ли встречный транспорт останавливаться?","options":["Нет, потому что центральная полоса для левого поворота считается разделительным пространством, когда дорога имеет не менее четырёх полос","Да, потому что полоса для поворота не является физическим барьером","Да, на всех дорогах встречный транспорт обязан останавливаться","Нет, встречный транспорт никогда не обязан останавливаться на любой многополосной дороге"],"explanation":"G.S. 20-217(c) позволяет встречному транспорту продолжать движение, когда дорога разделена разделительным пространством, и это конкретно включает центральную полосу для левых поворотов, ЕСЛИ проезжая часть состоит как минимум из четырёх полос. Пятиполосная дорога с центральной полосой для поворота соответствует этому условию, поэтому встречному транспорту не нужно останавливаться. Источник: N.C. Gen. Stat. 20-217(c)."},"78":{"q":"Водитель осуждён во второй раз в течение трёх лет за обгон остановившегося школьного автобуса в Северной Каролине. Каковы последствия для водительского удостоверения в дополнение к штрафу?","options":["Аннулирование водительского удостоверения на один год","Только 30-дневное приостановление","Никаких действий с удостоверением, только штрафные баллы","Постоянное аннулирование при втором нарушении"],"explanation":"Согласно N.C. Gen. Stat. 20-217(g1), второе осуждение за проступок (misdemeanor) по этому разделу в течение трёхлетнего периода приводит к аннулированию водительского удостоверения на один год; владелец CDL также дисквалифицируется от управления коммерческим транспортным средством на этот период. Источник: N.C. Gen. Stat. 20-217(g1)."},"79":{"q":"Северная Каролина может установить более низкое ограничение скорости для конкретного коммерческого транспортного средства в каком случае?","options":["Когда транспортное средство движется по специальному разрешению на негабаритный/сверхтяжёлый груз из-за его веса или габаритов","Всякий раз, когда у транспортного средства более двух осей","Всякий раз, когда транспортное средство зарегистрировано в другом штате","Всякий раз, когда длина прицепа более 40 футов"],"explanation":"N.C. Gen. Stat. 20-141(l) позволяет устанавливать более низкое ограничение скорости для транспортного средства, движущегося по специальному разрешению из-за любого веса или габарита транспортного средства или его груза. В противном случае установленное ограничение единое для всех типов транспортных средств. Источник: N.C. Gen. Stat. 20-141(l); правила NCDOT о разрешениях на негабаритный/сверхтяжёлый груз."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Северной Каролине?","options":["Федеральное управление безопасности грузоперевозок (FMCSA)","Департамент общественной безопасности Северной Каролины","Дорожный патруль Департамента транспорта Северной Каролины","Отдел автотранспортных средств Северной Каролины (NCDMV)"],"explanation":"В Северной Каролине CDL выдаются и администрируются Отделом автотранспортных средств Северной Каролины (NCDMV), подразделением NCDOT. FMCSA устанавливает федеральные стандарты, но не выдаёт удостоверения. Источник: страница Commercial Driver License NCDMV и N.C. CDL Manual, Раздел 1."},"81":{"q":"Чтобы получить CDL или коммерческое учебное удостоверение в Северной Каролине, какие два типа тестов должен пройти заявитель?","options":["Письменный тест и тест на вес транспортного средства","Теоретические тесты (knowledge tests) и тесты навыков (skills tests)","Тест на физическую подготовку и тест на дополнительную категорию","Дорожный тест от работодателя и федеральный экзамен"],"explanation":"N.C. CDL Manual (Раздел 1.1) гласит, что для получения CDL или CLP вы должны пройти теоретические тесты (knowledge tests) и тесты навыков (skills tests). Тест навыков проводится в том классе транспортного средства, на который вы хотите получить удостоверение. Источник: N.C. CDL Manual, Раздел 1.1."},"82":{"q":"Тест навыков CDL в Северной Каролине состоит из каких трёх частей?","options":["Письменный теоретический тест, проверка зрения и дорожный тест","Проверка пневматических тормозов, тест на сцепку и тест на автомагистрали","Осмотр транспортного средства (предрейсовый), базовое управление транспортным средством и вождение по дороге","Задний ход, параллельная парковка и тест на ночное вождение"],"explanation":"Согласно N.C. CDL Manual (Раздел 1.1.2), тест навыков состоит из трёх частей: тест на осмотр транспортного средства (предрейсовый), тест на базовое управление транспортным средством и тест на вождение по дороге. Все три должны быть пройдены в соответствующем классе транспортного средства. Источник: N.C. CDL Manual, Раздел 1.1.2."},"83":{"q":"Какой теоретический тест должен сдать КАЖДЫЙ заявитель на CDL в Северной Каролине, независимо от класса или дополнительных категорий?","options":["Тест на общие знания (general knowledge test)","Тест на составные транспортные средства (combination vehicles)","Тест на пневматические тормоза (air brakes)","Тест на опасные материалы (hazardous materials)"],"explanation":"N.C. CDL Manual (Раздел 1.1.1) гласит, что тест на общие знания (general knowledge test) сдают все заявители. Другие тесты (составные транспортные средства, пневматические тормоза, опасные материалы и т. д.) применяются только к определённым классам или дополнительным категориям. Источник: N.C. CDL Manual, Раздел 1.1.1."},"84":{"q":"Каков минимальный проходной балл на каждом теоретическом тесте CDL в Северной Каролине?","options":["70% правильных ответов","80% правильных ответов","75% правильных ответов","85% правильных ответов"],"explanation":"Северная Каролина требует не менее 80% правильных ответов на каждом теоретическом тесте CDL (например, 40 из 50 на тесте на общие знания, 16 из 20 на составных транспортных средствах или пневматических тормозах), оцениваемых отдельно. Источник: стандарты теоретического тестирования CDL NCDMV (минимум FMCSA, принятый Северной Каролиной)."},"85":{"q":"Как долго действует коммерческое учебное удостоверение (CLP) в Северной Каролине?","options":["30 дней, без возможности продления","180 дней, с возможностью однократного продления ещё на 180 дней","1 год, с неограниченным числом продлений","60 дней, с возможностью однократного продления на 60 дней"],"explanation":"CLP в Северной Каролине действует 180 дней и может быть продлено один раз ещё на 180 дней без повторной сдачи теста на общие знания. Источник: страница Commercial Driver License NCDMV; N.C. CDL Manual (CLP), в соответствии с 49 CFR 383.25."},"86":{"q":"После выдачи CLP в Северной Каролине, как долго заявитель должен ждать перед сдачей теста навыков CDL?","options":["Не менее 30 дней","Не менее 7 дней","Не менее 60 дней","Не менее 14 дней"],"explanation":"Владелец CLP должен ждать не менее 14 дней после выдачи CLP перед сдачей теста навыков CDL. Это федеральное правило (49 CFR 383.25) применяется NCDMV. Источник: страница Commercial Driver License NCDMV; 49 CFR 383.25."},"87":{"q":"Прежде чем впервые подающий заявление на класс A или класс B в Северной Каролине сможет сдать тест навыков CDL, какое федеральное обучение должно быть завершено?","options":["Государственный курс безопасного вождения в офисе NCDMV","120 часов вождения, зарегистрированных с любым лицензированным владельцем CDL","Обучение начинающих водителей (ELDT) от поставщика из реестра поставщиков обучения FMCSA (FMCSA Training Provider Registry)","Сертификация по охране труда OSHA"],"explanation":"Федеральное обучение начинающих водителей (ELDT) должно быть завершено через поставщика, указанного в реестре поставщиков обучения FMCSA (FMCSA Training Provider Registry), перед тестированием для получения CDL класса A/B впервые (а также для дополнительных категорий P, S и H или повышения с B до A). Источник: страница CDL NCDMV; правило FMCSA ELDT (49 CFR Part 380)."},"88":{"q":"Помимо впервые подающих заявление на класс A и класс B, ELDT также требуется перед тестированием на какие дополнительные категории?","options":["Цистерна (N), сдвоенные/строенные прицепы (T) и пневматические тормоза","Составные транспортные средства, пневматические тормоза и цистерна (N)","Пассажирская (P), школьный автобус (S) и опасные материалы (H)","Только опасные материалы (H)"],"explanation":"ELDT применяется перед первичной выдачей класса A/B, повышением с B до A, а также для дополнительных категорий «Пассажирская» (P), «Школьный автобус» (S) и «Опасные материалы» (H). Дополнительная категория H требует ELDT только по теории. Источник: страница CDL NCDMV; правило FMCSA ELDT (49 CFR Part 380)."},"89":{"q":"Заявители на CDL в Северной Каролине должны самостоятельно сертифицировать свой тип коммерческого вождения. Сколько существует категорий самосертификации?","options":["Четыре","Две","Три","Пять"],"explanation":"Существует четыре категории самосертификации: межштатная неисключённая (interstate non-excepted), межштатная исключённая (interstate excepted), внутриштатная неисключённая (intrastate non-excepted) и внутриштатная исключённая (intrastate excepted). Заявитель отмечает поле, соответствующее его деятельности. Источник: N.C. CDL Manual, Раздел 1.2.3."},"90":{"q":"Какая категория самосертификации в Северной Каролине требует, чтобы водитель предоставил и поддерживал федеральный медицинский сертификат DOT (DOT medical examiner's certificate)?","options":["Межштатная исключённая (interstate excepted)","Межштатная неисключённая (interstate non-excepted)","Внутриштатная исключённая (intrastate excepted)","Исключённый частный пассажирский транспорт"],"explanation":"Водитель категории «межштатная неисключённая» (interstate non-excepted) удостоверяет, что он подпадает под действие федеральных медицинских требований DOT по 49 CFR Part 391 и соответствует им, и должен получить медицинский сертификат (medical examiner's certificate). Большинство владельцев CDL для межштатных перевозок относятся к неисключённым. Источник: N.C. CDL Manual, Раздел 1.2.3."},"91":{"q":"Водитель в Северной Каролине, который работает только в межштатной торговле, но исключительно в операциях, исключённых из 49 CFR Part 391, должен самосертифицироваться как:","options":["Межштатная неисключённая (interstate non-excepted)","Внутриштатная неисключённая (intrastate non-excepted)","Межштатная исключённая (interstate excepted)","Внутриштатная исключённая (intrastate excepted)"],"explanation":"Водитель категории «межштатная исключённая» (interstate excepted) удостоверяет, что он работает в межштатной торговле, но занимается исключительно операциями, исключёнными по 49 CFR 390.3(f), 391.2, 391.68 или 398.3, и НЕ обязан получать медицинский сертификат (medical examiner's certificate). Источник: N.C. CDL Manual, Раздел 1.2.3."},"92":{"q":"Согласно правилам Северной Каролины, если водитель работает И в межштатной, И во внутриштатной торговле, какую категорию он должен выбрать?","options":["Внутриштатная торговля (intrastate commerce)","Межштатная торговля (interstate commerce) (более строгая категория)","Ту, в которой он водит чаще","Он может свободно выбрать любую из них"],"explanation":"N.C. CDL Manual (Раздел 1.2.1) гласит, что водитель, работающий и в межштатной, и во внутриштатной торговле, должен выбрать межштатную торговлю (interstate commerce), поскольку она несёт более строгие квалификационные требования. Источник: N.C. CDL Manual, Раздел 1.2.1."},"93":{"q":"Согласно процессу Национального реестра FMCSA (FMCSA National Registry), который теперь используется в Северной Каролине, как медицинский сертификат DOT неисключённого водителя обычно попадает в NCDMV?","options":["Водитель должен отправлять бумажную копию напрямую в NCDMV каждые два года","Работодатель отправляет медицинскую карту по факсу в штаб-квартиру NCDMV","Врач водителя звонит в медицинское подразделение NCDMV, чтобы сообщить результаты","Сертифицированный медицинский эксперт подаёт результаты осмотра электронно в Национальный реестр FMCSA (FMCSA National Registry), который передаёт их в NCDMV"],"explanation":"Согласно процессу Национального реестра FMCSA / NRII (соответствие в 2025 году), сертифицированные медицинские эксперты электронно подают результаты осмотра CDL/CLP в Национальный реестр, и FMCSA передаёт статус медицинской сертификации штату (NCDMV). Водителям больше не нужно доставлять бумажную карту в NCDMV. Источник: правило FMCSA National Registry; руководство NCDMV по медицинской сертификации."},"94":{"q":"Самосертификация категории торговли водителя в Северной Каролине требуется в какие из этих моментов?","options":["Только один раз, при первоначальной выдаче CDL","Только когда водитель меняет работодателей","При подаче заявления на CLP, а также при продлении, повышении, добавлении дополнительных категорий или передаче CDL","Только когда водителю исполняется 65 лет"],"explanation":"Водители должны предоставлять информацию о самосертификации штату при подаче заявления на CLP, а также при продлении, повышении, добавлении дополнительных категорий или передаче CDL. Источник: N.C. CDL Manual, Раздел 1.2 (федеральные требования к медицинской сертификации)."},"95":{"q":"Каков стандартный срок действия CDL в Северной Каролине (для продлённого удостоверения, для водителя младше 65 лет)?","options":["5 лет","4 года","8 лет","10 лет"],"explanation":"Согласно N.C.G.S. 20-7, продлённое коммерческое водительское удостоверение истекает через пять лет после даты истечения продлеваемого удостоверения. CDL нельзя продлить онлайн, и они должны быть продлены лично в офисе NCDMV. Источник: N.C.G.S. 20-7; страница продления удостоверений NCDMV."},"96":{"q":"Чем продление CDL в Северной Каролине отличается от продления стандартного удостоверения (класс C)?","options":["CDL можно продлить онлайн в течение до двух лет после истечения срока","CDL автоматически продлевается автоперевозчиком работодателя","CDL никогда не истекает, как только водитель сдаст дорожный тест","CDL должно быть продлено лично в офисе выдачи водительских удостоверений NCDMV; его нельзя продлить онлайн или по почте"],"explanation":"CDL в Северной Каролине должны быть продлены лично в офисе выдачи водительских удостоверений NCDMV и не могут быть продлены онлайн или по почте, в отличие от многих стандартных удостоверений. Источник: страница продления/замены удостоверений NCDMV; N.C.G.S. 20-7."},"97":{"q":"При подаче заявления на CLP в Северной Каролине, какой из следующих документов требуется в составе заявления?","options":["Подтверждение личности/возраста, номер социального страхования, место жительства и подтверждение страхования гражданской ответственности","Аттестат о среднем образовании и нотариально заверенное письмо работодателя","Только паспорт, без других документов","Подтверждение права собственности на транспортное средство и техпаспорт на транспортное средство"],"explanation":"NCDMV требует, чтобы заявитель на CLP предъявил подтверждение личности и возраста, подтверждение номера социального страхования, два документа о месте жительства (подтверждение законного присутствия для неграждан) и подтверждение страхования гражданской ответственности от поставщика, лицензированного в Северной Каролине. Источник: страница Commercial Driver License NCDMV."},"98":{"q":"В Северной Каролине сколько попыток сдачи одного теоретического теста CDL разрешено за один день?","options":["Одна попытка на тест в день","Три попытки на тест в день","Неограниченное число попыток за один день","Две попытки на тест в день"],"explanation":"N.C. CDL Manual гласит, что разрешена только одна попытка каждого теоретического теста в день. После трёх неудачных попыток теста на общие знания требуется ещё один сбор за подачу заявления для следующих трёх попыток. Источник: N.C. CDL Manual, Раздел 1.1."},"99":{"q":"После успешной сдачи, как долго результаты тестов CDL в Северной Каролине действительны в компьютерных файлах NCDMV?","options":["30 дней с даты теста","180 дней с даты теста","1 год с даты теста","90 дней с даты теста"],"explanation":"N.C. CDL Manual отмечает, что все результаты тестов действительны в течение 90 дней с даты теста в компьютерных файлах NCDMV. Заявитель должен выполнить оставшиеся требования в течение этого срока. Источник: N.C. CDL Manual, Раздел 1.1."}},"tr":{"0":{"q":"Kuzey Carolina karayollarında, bir ticari aracın veya yükünün gabari aşımı izni olmadan izin verilen maksimum yasal genişliği nedir?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Kuzey Carolina, tüm yollarda bir aracın veya yükünün toplam dış genişliğini 102 inches (8 feet 6 inches) ile sınırlandırır; bundan daha geniş olan herhangi bir şey izin gerektirir. Kaynak: N.C. Gen. Stat. 20-116(a) ve NCDOT Oversize/Overweight Permit Handbook."},"1":{"q":"Kuzey Carolina karayollarında izin olmadan izin verilen maksimum yasal araç yüksekliği nedir?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Kuzey Carolina yasası, yüklü veya yüksüz, maksimum araç yüksekliğini 14 feet olarak belirler. Kaynak: N.C. Gen. Stat. 20-116(c) ve NCDOT Oversize/Overweight Permit Handbook."},"2":{"q":"Kuzey Carolina'da tek bir aks üzerinde izin verilen maksimum brüt ağırlık nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"Kuzey Carolina, tek aks ağırlığını federal standartla uyumlu olarak 20,000 pounds ile sınırlandırır. Kaynak: N.C. Gen. Stat. 20-118(b)(1) ve NCDOT Oversize/Overweight Permit Handbook."},"3":{"q":"Kuzey Carolina'da çift aks (tandem) üzerinde izin verilen maksimum brüt ağırlık nedir?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"Kuzey Carolina, çift aks (tandem) maksimumunu 38,000 pounds olarak belirler (federal üst sınır 34,000'dir; Kuzey Carolina'nın yasal rakamı 38,000'dir). Kaynak: N.C. Gen. Stat. 20-118(b)(2) ve NCDOT Oversize/Overweight Permit Handbook."},"4":{"q":"Kuzey Carolina'da izin olmadan tek bir aracın (iki veya daha fazla akslı) maksimum genel uzunluğu nedir?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"İki veya daha fazla aksa sahip tek bir araç, ön ve arka tamponlar dahil olmak üzere genel olarak 40 feet'i aşamaz. Kaynak: N.C. Gen. Stat. 20-116(d)(1) ve NCDOT Oversize/Overweight Permit Handbook."},"5":{"q":"Kuzey Carolina'da birbirine bağlanmış iki aracın oluşturduğu kombinasyon için genel maksimum uzunluk nedir?","options":["55 feet","60 feet","65 feet","75 feet"],"explanation":"Aksi belirtilmedikçe, iki aracın hiçbir kombinasyonu ön ve arka tamponlar dahil olmak üzere toplam 60 feet uzunluğu aşamaz. Kaynak: N.C. Gen. Stat. 20-116(e) ve NCDOT Oversize/Overweight Permit Handbook."},"6":{"q":"Kuzey Carolina'da, tek bir yarı römork çeken bir çekici (truck-tractor), yarı römork hangi uzunluğu aşmadığı sürece 60 feet'lik kombinasyon uzunluğu sınırından muaftır?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"En fazla 53 feet uzunluğunda bir yarı römork çeken bir çekici (güç ünitesi), Kuzey Carolina'daki tüm yollarda 60 feet'lik genel maksimumu aşabilir. Kaynak: N.C. Gen. Stat. 20-116(e) ve NCDOT Oversize/Overweight Permit Handbook."},"7":{"q":"Kuzey Carolina karayollarında, fazla ağırlık izni olmadan tipik bir beş akslı çekici-yarı römork için maksimum brüt araç ağırlığı nedir?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"Kuzey Carolina'nın maksimum brüt araç ağırlığı, aks ve köprü formülü sınırlarına tabi olmak üzere 80,000 pounds'dur. Kaynak: N.C. Gen. Stat. 20-118 ve NCDOT Oversize/Overweight Permit Handbook."},"8":{"q":"Kuzey Carolina, karayollarındaki aks aralığına göre izin verilen brüt ağırlığı nasıl belirler?","options":["İlçe tarafından belirlenen sabit bir aks başına çarpan ile","En uç aks ölçümüne dayanan federal köprü formülü ile","Yalnızca aracın üreticisinin GVWR'si ile","Yola değen lastik sayısı ile"],"explanation":"Brüt ağırlık, federal köprü formülü (köprü yasası) kapsamında en uç aks ölçümüne göre belirlenir. 23 U.S.C. 127 ödeneği, levha ile işaretlenmediği sürece tüm eyalet yollarında geçerlidir. Kaynak: N.C. Gen. Stat. 20-118(c)(19) ve NCDOT Oversize/Overweight Permit Handbook."},"9":{"q":"Kuzey Carolina'da yasal boyut veya ağırlık sınırlarını aşan araçlar için gabari aşımı/fazla ağırlık izinlerini hangi kurum verir?","options":["N.C. Division of Motor Vehicles (DMV)","N.C. Department of Transportation (NCDOT) Oversize/Overweight Permit Unit","N.C. State Highway Patrol","Seyahatin başladığı ilçenin şerif ofisi"],"explanation":"Gabari aşımı/fazla ağırlık izinleri NCDOT Oversize/Overweight Permit Unit (Garner, NC'deki Merkezi İzin Ofisi) tarafından verilir. Kaynak: NCDOT Oversize/Overweight Permit Handbook."},"10":{"q":"Kuzey Carolina tek seferlik gabari aşımı/fazla ağırlık izni ne kadar süre geçerlidir?","options":["Bir sefer için 5 takvim günü","Tek bir sefer için 10 takvim günü","Bir sefer için 30 takvim günü","Yürürlük tarihinden itibaren bir yıl"],"explanation":"Tek seferlik bir izin, tek bir sefer için 10 takvim günü geçerlidir; eyalet ücreti $12 ile $48 arasında değişir. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit)."},"11":{"q":"Kuzey Carolina tek seferlik bir izin kapsamında, çift aks (tandem) grubunda izin verilen maksimum ağırlık (aks ağırlıkları, brüt değil) nedir?","options":["44,000 pounds","46,000 pounds","50,000 pounds","60,000 pounds"],"explanation":"Tek seferlik bir izinde, izin verilen aks ağırlıkları şunlardır: direksiyon (steer) 20,000; tek (single) 25,000; çift (tandem) 50,000; üçlü (tridem) 60,000; ve dört veya daha fazla akslı grup 68,000 pounds. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit axle weights)."},"12":{"q":"Tek bir kalem için 90,000 pounds'a kadar taşımaya izin veren bir Kuzey Carolina fazla ağırlık iznine hak kazanmak için, aracın genellikle en az hangi minimum dingil mesafesine (wheelbase) sahip olması gerekir?","options":["41-foot wheelbase","48-foot wheelbase","51-foot wheelbase","57-foot wheelbase"],"explanation":"En az 51-foot dingil mesafesine sahip bir araç kombinasyonu, 90,000 pounds'a kadar taşıma için hak kazanabilir; 90,000 pounds üzerinde izin güzergaha özeldir. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Annual Permit / Overweight)."},"13":{"q":"Kuzey Carolina'da, hangi brüt ağırlığı aşan bir yük, yazılı bir 'superload' başvurusu ve köprü mühendisliği incelemesi gerektiren bir 'superload' olarak sınıflandırılır?","options":["Brüt ağırlık 90,000 pounds'u aşar","Brüt ağırlık 112,000 pounds'u aşar","Brüt ağırlık 122,000 pounds'u aşar","Brüt ağırlık 132,000 pounds'u aşar"],"explanation":"Brüt ağırlık 132,000 pounds'u aştığında (veya direksiyon aksı ağırlığı 20,000 pounds'u aştığında ya da genişlik 16 feet'i aştığında) bir superload izni gereklidir. $100 iade edilmeyen başvuru ücretine ek olarak ek masraflar taşır. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Superload Permit)."},"14":{"q":"Kuzey Carolina'da izinli bir yükün arka çıkıntısı (overhang) 4 feet'ten fazla olduğunda, gündüz seyahati için ne sergilenmelidir?","options":["Arkada yanıp sönen sarı bir ışık","18 inch kare kırmızı bir bayrak","Bir 'WIDE LOAD' afişi","Kırmızı bir üçgen reflektör"],"explanation":"4 feet'ten fazla bir arka çıkıntı, gündüz seyahati için 18 inch kare kırmızı bir bayrak ve geceleri gabari ışıkları sergilemelidir; yük, aracın arkasından 14 feet'ten fazla uzanamaz ve maksimum çıkıntı 14 feet'tir. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Overhang)."},"15":{"q":"Kuzey Carolina izninde, aşırı genişlikteki bir yükün en geniş noktasını işaretleyen uyarı bayrakları hangi boyutta ve renkte olmalıdır?","options":["12 inch kare, sarı","16 inch kare, yalnızca turuncu","18 inch kare, kırmızı veya turuncu","24 inch kare, yalnızca kırmızı"],"explanation":"Bayraklar 18 inch kare, kırmızı veya turuncu olmalı ve aşırı genişliğin en geniş noktasına veya izinde belirtildiği şekilde yerleştirilmelidir. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Flags)."},"16":{"q":"Kuzey Carolina'da iki şeritli, çift yönlü bir karayolunda, izinli bir yük hangi genişliği aştığında genellikle bir önden eskort aracı gereklidir?","options":["10 feet genişlik","12 feet genişlik","14 feet genişlik","16 feet genişlik"],"explanation":"İki şeritli, çift yönlü karayollarında 12 feet'ten daha geniş izinli yükler için önden eskort gereklidir; çok şeritli karayollarında veya izinde belirtildiği şekilde arkadan eskort gereklidir. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Escorts)."},"17":{"q":"Kuzey Carolina izin kurallarına göre, ağırlığı hangi eşiği aşan herhangi bir izinli yük için önden eskort gereklidir?","options":["80,000 pounds'dan fazla","112,000 pounds'dan fazla","132,000 pounds'dan fazla","149,999 pounds'dan fazla"],"explanation":"149,999 pounds'dan fazla ağırlık için önden eskort gereklidir; 150 feet veya daha fazla genel uzunluk için önden ve arkadan eskort gereklidir. Kaynak: NCDOT Oversize/Overweight Permit Handbook (Escorts)."},"18":{"q":"Kuzey Carolina yasası, tarım ve orman ürünleri için Interstate dışında daha yüksek bir ağırlık toleransı sağlar. Bu tolerans kapsamındaki artırılmış tek aks sınırı nedir?","options":["20,000 pounds","21,500 pounds","22,000 pounds","26,000 pounds"],"explanation":"Interstate sistemi dışında taşınan uygun tarım ve orman ürünleri için Kuzey Carolina, 22,000 pounds tek aks, 42,000 pounds çift aks (tandem) ve 90,000 pounds brüt ağırlığa kadar izin verir. Kaynak: N.C. Gen. Stat. 20-118(c)(12)."},"19":{"q":"Kuzey Carolina'nın yüzde 10 ağırlık tolerans ödeneği hangi sınırlar için geçerlidir?","options":["Tek aks ve çift aks (tandem) sınırları","80,000-pound brüt sınırı ve Interstate aks sınırları","Yalnızca aks grubu ağırlıkları; tek/çift aksları, 80,000-pound brüt üst sınırını, levha ile işaretli köprüleri ve Interstate'leri hariç tutarak","Eyalet genelindeki tüm levha ile işaretli köprü ağırlık sınırları"],"explanation":"Yüzde 10 tolerans yalnızca aks grubu (köprü formülü) ağırlıkları için geçerlidir; tek aks veya çift aks (tandem) sınırları, 80,000-pound brüt maksimumu, levha ile işaretli köprüler veya Interstate karayolları için geçerli değildir. Kaynak: N.C. Gen. Stat. 20-118(h)."},"20":{"q":"Kuzey Carolina'da, çekilen aracın 10,000 pounds'dan fazla GVWR'ye sahip olması koşuluyla, 26,001 pounds veya daha fazla brüt araç ağırlık derecesine (GVWR) sahip bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Kuzey Carolina federal sınıflandırmayı izler: çekilen ünite(ler)in 10,000 lbs GVWR'yi aştığı, 26,001 lbs veya daha fazla GVWR'ye sahip herhangi bir araç kombinasyonu için Class A CDL gereklidir. Kaynak: NCDMV Commercial Driver License sayfası ve N.C. Commercial Driver License Manual."},"21":{"q":"Kuzey Carolina kurallarına göre, 26,001 pounds veya daha fazla GVWR'ye sahip ve 10,000 pounds GVWR'yi aşmayan bir ünite çeken tek bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class E"],"explanation":"Class B CDL, 26,001 lbs GVWR veya daha fazla dereceye sahip tek bir aracı, artı 10,000 lbs GVWR'yi aşmayan herhangi bir çekilen aracı kapsar. Kaynak: NCDMV Commercial Driver License sayfası ve N.C. CDL Manual."},"22":{"q":"Class A veya B ağırlık eşiklerini karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış veya levha ile işaretlenmiş tehlikeli madde taşıyan bir araca hangi Kuzey Carolina CDL sınıfı uygulanır?","options":["Class A","Class B","Class C","Class M"],"explanation":"Kuzey Carolina'da, Class A veya B'yi karşılamayan, 16 veya daha fazla kişi (sürücü dahil) taşımak için tasarlanmış veya levha ile işaretlenmiş tehlikeli madde taşıyan araçlar için Class C CDL gereklidir. Kaynak: NCDMV Commercial Driver License sayfası ve N.C. CDL Manual."},"23":{"q":"Kuzey Carolina'da, yalnızca eyalet içi (intrastate) ticari sürüş ile sınırlı bir CDL almak için minimum yaş kaçtır?","options":["16 yaşında","17 yaşında","18 yaşında","21 yaşında"],"explanation":"Kuzey Carolina, yalnızca eyalet içi (intrastate) operasyon için 18 yaşında CDL'ye izin verir. Sürücüler, eyaletler arası (interstate) ticaret için veya tehlikeli madde taşımak için 21 yaşında olmalıdır. Kaynak: NCDMV Commercial Driver License gereksinimleri; N.C.G.S. Chapter 20, Article 2C."},"24":{"q":"Bir Kuzey Carolina sürücüsünün, eyaletler arası (interstate) ticarette ticari bir motorlu aracı kullanmak veya tehlikeli madde onayına (endorsement) sahip olmak için en az kaç yaşında olması gerekir?","options":["18 yaşında","19 yaşında","20 yaşında","21 yaşında"],"explanation":"Kuzey Carolina, eyaletler arası (interstate) ticari sürüş ve tehlikeli madde (H) onayı için minimum 21 yaş gerektirir; yalnızca eyalet içi (intrastate) operasyon için minimum yaş 18'dir. Kaynak: NCDMV Commercial Driver License gereksinimleri; N.C.G.S. Chapter 20, Article 2C."},"25":{"q":"Bir Kuzey Carolina CDL sahibinin, levha gerektiren miktarlarda tehlikeli madde taşımak için hangi onaya (endorsement) ihtiyacı vardır?","options":["N onayı","H onayı","T onayı","P onayı"],"explanation":"Levha gerektiren miktarlarda tehlikeli madde taşımak için H (Hazardous Materials) onayı gereklidir. Bir bilgi testinin yanı sıra bir TSA güvenlik tehdit değerlendirmesi gerektirir. Kaynak: NCDMV CDL onayları; 49 CFR 383.93."},"26":{"q":"Kuzey Carolina'da, en az 1,000 gallon kapasiteli bir tankta sıvı veya gaz halinde yük taşımak için tasarlanmış bir tanker aracı kullanmak için hangi onay (endorsement) gereklidir?","options":["H onayı","T onayı","N onayı","X onayı"],"explanation":"Sıvı veya gaz taşıyan, 1,000 gallon veya daha fazla bireysel dereceli kapasiteye sahip tanker araçları için N (Tank Vehicle) onayı gereklidir. Kaynak: NCDMV CDL onayları; N.C. CDL Manual; 49 CFR 383.5/383.93."},"27":{"q":"İkili veya üçlü römork kombinasyonları çeken bir Kuzey Carolina CDL sürücüsü hangi onaya (endorsement) sahip olmalıdır?","options":["T onayı","N onayı","P onayı","S onayı"],"explanation":"T onayı, ikili ve üçlü römork kombinasyonlarının kullanımına yetki verir. Bir bilgi testini geçerek alınır; ayrı bir beceri testi gerekmez. Kaynak: NCDMV CDL onayları; N.C. CDL Manual."},"28":{"q":"Bir sürücünün aynı zamanda tehlikeli madde taşıyan bir tanker aracı kullanmaya yetkili olduğunda, bir Kuzey Carolina CDL'sinde hangi birleşik onay (endorsement) görünür?","options":["HT onayı","X onayı","NP onayı","Z onayı"],"explanation":"Kuzey Carolina, tek bir CDL üzerinde tanker (N) ve tehlikeli madde (H) onaylarının kombinasyonunu temsil etmek için X onayını verir. Kaynak: NCDMV CDL onayları/kısıtlamaları."},"29":{"q":"Kuzey Carolina'da, hangi CDL onayları (endorsement) (yalnızca bir bilgi testi değil) direksiyon başında bir BECERİ testini geçmeyi gerektirir?","options":["H ve N","N ve T","P ve S","H ve T"],"explanation":"Passenger (P) ve School Bus (S) onayları uygun araçta bir beceri/yol testi gerektirirken, H, N ve T yalnızca bilgi testleriyle alınır. Kaynak: NCDMV CDL onayları; N.C. CDL Manual."},"30":{"q":"Bir Kuzey Carolina başvuru sahibi School Bus (S) onayını (endorsement) alabilmesi için önce hangi başka onaya sahip olması gerekir?","options":["H (HazMat)","N (Tank)","T (Doubles/Triples)","P (Passenger)"],"explanation":"Federal ve Kuzey Carolina kurallarına göre, School Bus (S) onayı, sürücünün önce Passenger (P) onayına hak kazanmasını gerektirir. Kaynak: NCDMV CDL onayları; 49 CFR 383.93(b)."},"31":{"q":"Bir Kuzey Carolina Commercial Learner Permit (CLP), yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["90 gün","180 gün","1 yıl","30 gün"],"explanation":"Bir Kuzey Carolina CLP'si 180 gün geçerlidir ve genel bilgi testini tekrar almadan ek 180 gün için bir kez yenilenebilir. Kaynak: NCDMV Commercial Driver License sayfası; 49 CFR 383.25."},"32":{"q":"Kuzey Carolina tarafından benimsenen federal kurallara göre, bir CDL başvuru sahibinin CDL beceri (yol) testini almadan önce bir Commercial Learner Permit'i tutması gereken minimum süre nedir?","options":["7 gün","14 gün","30 gün","60 gün"],"explanation":"Bir başvuru sahibinin CDL beceri testini almasına izin verilmeden önce CLP'yi minimum 14 gün tutması gerekir. Kuzey Carolina bu federal gerekliliği uygular. Kaynak: NCDMV CDL sayfası; 49 CFR 383.25(e)."},"33":{"q":"Bir Kuzey Carolina Commercial Learner Permit kapsamında çalışırken, CLP sahibine hangi yetki belgesine sahip bir kişinin eşlik etmesi gerekir?","options":["Herhangi bir geçerli Class C sürücü ehliyeti","Uygun onaylara sahip aynı veya daha yüksek sınıftan geçerli bir CDL","Bir Kuzey Carolina öğrenci belgesi (instruction permit)","Eşlik eden bir sürücü gerekmez"],"explanation":"Bir CLP sahibine her zaman ön koltukta oturan, uygun sınıf ve onaylara sahip geçerli bir CDL'ye sahip biri eşlik etmelidir. Kaynak: NCDMV CDL sayfası; 49 CFR 383.25."},"34":{"q":"İlk kez CDL alan bir kişi için Kuzey Carolina'da hangi giriş seviyesi sürücü eğitimi (ELDT) gerekliliği uygulanır?","options":["Sürücünün seçeceği herhangi bir özel eğitmenden eğitim","FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan eğitim","Yalnızca NCDMV tarafından onaylanmış çevrimiçi bir video kursu","Resmi eğitim gerekmez, yalnızca testler"],"explanation":"7 Şubat 2022'den bu yana, ilk kez CDL başvurusunda bulunanlar (ve B'den A'ya yükseltenler veya P, S ya da H onayı arayanlar) testten önce FMCSA Training Provider Registry'deki bir sağlayıcıdan ELDT'yi tamamlamalıdır. Kaynak: FMCSA ELDT kuralı; NCDMV CDL sayfası."},"35":{"q":"Kuzey Carolina HazMat (H) onayı (endorsement) için ne tür bir ELDT'nin tamamlanması gerekir ve ne zaman?","options":["Bilgi testinden önce yalnızca teori eğitimi","Beceri testinden önce direksiyon başında eğitim","Yol testinden önce hem teori hem de direksiyon başında eğitim","HazMat için ELDT gerekmez"],"explanation":"H onayı için ELDT yalnızca teori (bilgi) eğitimidir ve eyalet bilgi testinden önce bir Training Provider Registry sağlayıcısı aracılığıyla tamamlanır; H için direksiyon başında bir bileşen yoktur. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380, Subpart F)."},"36":{"q":"Bilgi testini geçmenin yanı sıra, Kuzey Carolina bir HazMat (H) onayı (endorsement) vermeden önce ne gerektirir?","options":["NCDMV'den bir görme muafiyeti","Parmak izi alımı dahil bir TSA güvenlik tehdit değerlendirmesi","Beş yıllık sürüş deneyimi","Ayrı bir direksiyon başında beceri testi"],"explanation":"H onayı, parmak izi alımı ile bir TSA Hazmat Endorsement Threat Assessment Program geçmiş kontrolü gerektirir; onay genellikle her beş yılda bir yenilenir. Kaynak: NCDMV CDL sayfası; TSA HME programı; 49 CFR 1572."},"37":{"q":"Bir Kuzey Carolina CDL'sine başvururken, bir başvuru sahibinin hangi belge setini sunması gerekir?","options":["Yalnızca bir Social Security kartı","Kimlik/yaş kanıtı, Social Security numarası, Kuzey Carolina ikameti ve yasal varlık (lawful presence)","Bir pasaport ve başka hiçbir şey","Yalnızca sorumluluk sigortası kanıtı"],"explanation":"NCDMV, kimlik/doğum tarihi, Social Security numarası, Kuzey Carolina ikameti ve yasal varlık (ABD vatandaşlığı veya yasal statü) belgelerinin yanı sıra sorumluluk sigortası kanıtı gerektirir. Kaynak: NCDMV Commercial Driver License belge gereksinimleri."},"38":{"q":"Bir Kuzey Carolina CDL başvuru sahibi, gerçekleştirdiği ticari operasyon türünü belgelendirirken kaç tıbbi öz-sertifikasyon kategorisi arasından seçim yapmalıdır?","options":["İki","Üç","Dört","Beş"],"explanation":"Kuzey Carolina CDL sahipleri dört kategoriden birine öz-sertifikasyon yapar: interstate non-excepted, interstate excepted, intrastate non-excepted veya intrastate excepted. Kaynak: NCDMV CDL tıbbi öz-sertifikasyon (Form CDL-MED-1)."},"39":{"q":"Hangi Kuzey Carolina CDL öz-sertifikasyon kategorisi, sürücünün NCDMV'de dosyada geçerli bir tıbbi muayene sertifikası bulundurmasını gerektirir?","options":["Interstate excepted","Interstate non-excepted","Intrastate excepted","Hiçbir kategori tıbbi sertifika gerektirmez"],"explanation":"Interstate Non-Excepted olarak sertifikasyon yapan bir sürücü 49 CFR Part 391'e tabidir ve NCDMV'de bir tıbbi muayene sertifikası alıp bulundurmalıdır; excepted kategoriler bunu yapmak zorunda değildir. Kaynak: NCDMV CDL öz-sertifikasyon; 49 CFR 391.41 / 383.71."},"40":{"q":"Kuzey Carolina'da, bir kişinin ticari bir motorlu aracı yasal olarak kullanabileceği maksimum kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.02","0.04","0.08","0.10"],"explanation":"Kuzey Carolina, G.S. 20-138.2 kapsamında CMV bozukluk eşiğini, sıradan sürücüler için olan 0.08 sınırının yarısı olan 0.04 BAC olarak belirler. NC CDL kılavuzu, 0.04 veya daha fazla BAC ile bir CMV kullanmayı önemli (major) bir suç olarak listeler."},"41":{"q":"Levha ile işaretli tehlikeli madde TAŞIMAYAN bir araçta işlenen ilk önemli (major) suç (DWI veya 0.04+ BAC gibi) için, bir Kuzey Carolina CDL sahibi ne kadar süre diskalifiye edilir?","options":["60 gün","120 gün","1 yıl","3 yıl"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzuna göre (49 CFR 383.51'i yansıtarak), levha ile işaretli tehlikeli madde söz konusu olmadığında ilk önemli (major) suç, sürücüyü en az 1 yıl süreyle diskalifiye eder."},"42":{"q":"Bir Kuzey Carolina CDL sahibi, tehlikeli maddeler için levha ile işaretli bir aracı kullanırken ilk önemli (major) suçu işlerse, diskalifiye süresi ne kadara çıkar?","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzu, levha ile işaretli tehlikeli madde taşırken işlenen ilk önemli (major) suçun, standart 1 yıl yerine 3 yıllık bir diskalifiye ile sonuçlandığını öngörür."},"43":{"q":"Kuzey Carolina yasasına göre, ayrı bir olaydan kaynaklanan İKİNCİ önemli (major) suçtan (ikinci bir DWI, ret veya benzeri) hüküm giyen bir CDL sahibi için diskalifiye nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzu, ayrı bir olaydan kaynaklanan ikinci önemli (major) suç için ömür boyu CDL diskalifiyesi uygular. Bazı durumlarda 10 yıl sonra sınırlı bir yeniden yürürlüğe koyma mümkün olabilir, ancak diskalifiyenin kendisi ömür boyudur."},"44":{"q":"Bir Kuzey Carolina CDL sahibi, bir CMV'de bozulmuş sürüş nedeniyle durdurulur ve kimyasal (nefes veya kan) teste girmeyi reddeder. Ret, CDL diskalifiyesi açısından nasıl değerlendirilir?","options":["CDL cezası taşımaz, yalnızca kişisel ehliyet cezası taşır","Ciddi bir trafik ihlalidir (60 günlük diskalifiye)","Önemli (major) bir suçtur (en az 1 yıllık diskalifiye)","İlk reddinde ömür boyu diskalifiye ile sonuçlanır"],"explanation":"Kuzey Carolina'nın zımni rıza (implied-consent) yasası ve G.S. 20-17.4 kapsamında, bir kimyasal testi reddetmek önemli (major) bir suçtur ve bir mahkumiyetle aynı şekilde sürücüyü en az 1 yıl (levha ile işaretli hazmat taşınıyorsa 3 yıl) diskalifiye eder."},"45":{"q":"Kuzey Carolina'nın zımni rıza (implied-consent) statüsüne göre, bir CDL sürücüsü eyaletin yollarında ticari bir araç kullanarak, bozulmuş sürüş nedeniyle yasal olarak durdurulduğunda aşağıdakilerden hangisine rıza göstermiş sayılır?","options":["Yalnızca bir saha ayıklık testi","Nefes, kan veya idrarın kimyasal testi","Arama emri olmadan araç araması","CDL'nin yerinde teslimi"],"explanation":"Kuzey Carolina'nın zımni rıza (implied-consent) yasası (G.S. 20-16.2), herhangi bir sürücünün, bir zımni rıza suçuyla suçlandığında nefes, kan veya diğer vücut sıvısının kimyasal analizine zımnen rıza gösterdiğini öngörür; ret, ehliyet iptalini ve CDL diskalifiyesini tetikler."},"46":{"q":"Bir Kuzey Carolina CDL sahibinin 60 günlük diskalifiye ile karşılaşmadan önce, 3 yıllık bir süre içinde (bir CMV'de) kaç ciddi trafik ihlali işlemesi gerekir?","options":["1","2","3","4"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzu, 3 yıl içinde ayrı olaylardan kaynaklanan İKİNCİ ciddi trafik ihlali üzerine bir sürücüyü 60 gün süreyle diskalifiye eder."},"47":{"q":"Kuzey Carolina'da, 3 yıllık bir süre içinde ÜÇÜNCÜ bir ciddi trafik ihlali ne kadar süreyle CDL diskalifiyesi ile sonuçlanır?","options":["60 gün","120 gün","180 gün","1 yıl"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzuna göre, 3 yıl içinde üçüncü bir ciddi trafik ihlali (ayrı olaylar), önceki herhangi bir diskalifiyenin sonunda uygulanan 120 günlük bir diskalifiye ile sonuçlanır."},"48":{"q":"Bir Kuzey Carolina CDL sahibi için aşağıdakilerden hangisi 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak","Bir CMV'de park ihlali","Sınırın 5 mph üzerinde sürmek","Süresi dolmuş araç tescili"],"explanation":"NC CDL kılavuzu ve 49 CFR 383.51, aşırı hızı (sınırın 15 mph veya daha fazla üzerinde) ciddi bir trafik ihlali olarak tanımlar. Park ve tescil suçları açıkça bu kategoriden hariç tutulmuştur."},"49":{"q":"Kuzey Carolina kurallarına göre, aşağıdakilerden hangisi CDL diskalifiyesi açısından ciddi bir trafik ihlali olarak SAYILMAZ?","options":["Dikkatsiz sürüş (reckless driving)","Çok yakından takip etmek","Uygunsuz veya düzensiz şerit değişiklikleri","Yanmış bir farla bir CMV kullanmak"],"explanation":"NC CDL kılavuzu, dikkatsiz sürüşü, çok yakından takip etmeyi ve uygunsuz/düzensiz şerit değişikliklerini G.S. 20-17.4 / 49 CFR 383.51 kapsamındaki ciddi trafik ihlalleri arasında listeler. Yanmış bir far gibi bir ekipman kusuru bu listede değildir."},"50":{"q":"Kuzey Carolina'da uygun CDL sınıfı veya gerekli onay (endorsement) olmadan bir CMV kullanmak ne tür bir suç olarak değerlendirilir?","options":["Önemli (major) bir suç (1 yıllık diskalifiye)","Ciddi bir trafik ihlali","Bir hizmet dışı (out-of-service) ihlali","Bildirilmesi gerekmeyen bir ekipman ihlali"],"explanation":"NC CDL kılavuzu ve 49 CFR 383.51, uygun CDL sınıfı veya onayı olmadan (ya da CDL yanında bulunmadan) bir CMV kullanmayı, diğer ciddi ihlallerle birleştiğinde 60/120 günlük diskalifiyeleri tetikleyebilecek ciddi bir trafik ihlali olarak listeler."},"51":{"q":"Bir Kuzey Carolina CDL sahibi için, ticari bir motorlu aracı kullanırken mesaj yazmak (texting), diskalifiye açısından ne olarak kategorize edilir?","options":["Önemli (major) bir suç","Ciddi bir trafik ihlali","Bir hizmet dışı (out-of-service) emri ihlali","Bir demiryolu geçiş ihlali"],"explanation":"G.S. 20-137.4A ve NC CDL kılavuzuna göre (49 CFR 383.51 ve 392.80 ile uyumlu olarak), bir CMV kullanırken mesaj yazmak, 60/120 günlük diskalifiyelere katkıda bulunan ciddi bir trafik ihlalidir."},"52":{"q":"Kuzey Carolina yasası, bir CMV sürücüsünün sürüş sırasında cep telefonu kullanımını aşağıdakilerden hangisiyle sınırlandırır?","options":["Yalnızca eller serbest (hands-free) kullanım","Yalnızca kırmızı ışıkta durulduğunda kullanım","Bir dakikadan kısa aramalar","Sesli aramalar için herhangi bir elde tutulan telefonun kullanımı"],"explanation":"G.S. 20-137.4A, FMCSA Parts 390/392'ye tabi CMV operatörlerinin elde tutulan bir cep telefonu kullanmasını yasaklar; yalnızca eller serbest (hands-free) çalıştırmaya izin verilir. Bir CMV'de elde tutulan telefon ihlali ciddi bir trafik ihlalidir."},"53":{"q":"Bir Kuzey Carolina CDL sahibinin, bir CMV'yi (hazmat olmayan) kullanırken bir hizmet dışı (out-of-service) emrini ihlal ettiği İLK mahkumiyeti için diskalifiye süresi nedir?","options":["En az 30 gün","En az 60 gün","En az 90 gün","En az 180 gün"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzu, standart bir CMV için ilk hizmet dışı (out-of-service) emri ihlalini, çoğu ciddi ihlalin cezasının çok üzerinde olan 180 günden (1 yıla kadar) az olmayacak şekilde belirler."},"54":{"q":"Bir Kuzey Carolina CDL sahibi, levha ile işaretli tehlikeli madde veya 16+ yolcu taşırken bir hizmet dışı (out-of-service) emrini ihlal ederse, İLK ihlal en az ne kadar süre diskalifiye taşır?","options":["90 gün","180 gün","1 yıl","3 yıl"],"explanation":"G.S. 20-17.4'e göre, levha ile işaretli hazmat taşırken veya 16 ya da daha fazla yolcu taşırken işlenen ilk hizmet dışı (out-of-service) ihlali, standart hizmet dışı suçundan daha uzun bir maksimum olan 180 günden az olmayacak şekildedir (ve 2 yıla kadar)."},"55":{"q":"Kuzey Carolina yasasına göre, 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı (out-of-service) emri ihlali, bir CDL sahibini hangi minimum süre için diskalifiye eder?","options":["180 gün","1 yıl","2 yıl","5 yıl"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzu, herhangi bir 10 yıllık süre içinde ikinci bir hizmet dışı (out-of-service) emri ihlali için bir sürücüyü 2 yıldan (5 yıla kadar) az olmayacak şekilde diskalifiye eder."},"56":{"q":"Kuzey Carolina'da, bir CDL sahibinin bir CMV'de işlediği İLK demiryolu-karayolu hemzemin geçit ihlali için diskalifiye nedir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzu, bir CMV'de ilk demiryolu-karayolu hemzemin geçit ihlali için 60 günden az olmayacak şekilde bir diskalifiye uygular."},"57":{"q":"Bir Kuzey Carolina CDL sahibi, 3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işler. Diskalifiye nedir?","options":["60 gün","120 gün","En az 1 yıl","Ömür boyu"],"explanation":"G.S. 20-17.4 ve NC CDL kılavuzuna göre, demiryolu geçit ihlalleri 60 gün (birinci), 120 gün (3 yıl içinde ikinci) ve 1 yıldan az olmayacak şekilde (3 yıl içinde üçüncü) diskalifiye taşır."},"58":{"q":"Bir Kuzey Carolina CDL sahibi, ticari bir araçta puan uygulanan hareketli bir trafik ihlali işlediğinde, mahkeme cezayı ticari olmayan bir sürücüye kıyasla nasıl değerlendirir?","options":["Ceza CDL sahipleri için kaldırılır","Ceza iki katına çıkarılabilir","Ceza yarıya indirilir","Ceza herhangi bir sürücü için olduğu gibidir"],"explanation":"Kuzey Carolina yasasına göre, mahkeme, puan uygulanabilir bir motorlu araç ihlali işleyen bir CMV operatörü için cezayı iki katına çıkarabilir; bu da ticari sürücülere yüklenen daha yüksek standardı yansıtır."},"59":{"q":"Bir Kuzey Carolina CDL sürücüsü, bir zımni rıza (implied-consent) durdurması sırasında bir CMV'de kimyasal testi reddettiğinde veya 0.04 ya da daha fazla kaydettiğinde, herhangi bir mahkumiyetten önce sürücünün ehliyetine genellikle hangi anlık duruşma öncesi işlem uygulanır?","options":["10 günlük idari tutma (administrative hold)","30 günlük hukuki (civil) iptal","90 günlük askıya alma","Mahkumiyete kadar işlem yok"],"explanation":"Kuzey Carolina'nın zımni rıza (implied-consent) yasası (G.S. 20-16.5), uygun bir test sonucu veya ret üzerine sürücünün ehliyetinin 30 günlük hukuki (duruşma öncesi) iptalini uygular; bu, bir mahkumiyeti takip eden CDL diskalifiyesinden ayrıdır."},"60":{"q":"Altı veya daha fazla şeritli, kontrollü erişimli bir Kuzey Carolina otoyolunda, brüt araç ağırlık derecesi (GVWR) 26.001 pound veya daha fazla olan bir kamyona hangi kısıtlama uygulanır?","options":["Otoyola giriş veya çıkış yaparken, sollarken ya da bir tehlikeden kaçınırken hariç, en sol şeritte seyredemez","Her zaman yalnızca en sağ şeritte seyretmelidir","Trafiğe ayak uydurduğu sürece herhangi bir şeridi kullanabilir","En sol şeridi yalnızca akşam 9 ile sabah 6 arasında kullanabilir"],"explanation":"Kuzey Carolina G.S. 20-146, GVWR'si 26.001 pound veya daha fazla olan bir aracın, otoyola giriş ya da çıkış yaparken, sollarken veya bir tehlikeden kaçınırken hariç, altı veya daha fazla şeritli kontrollü erişimli bir otoyolun en sol şeridinde seyretmesini yasaklar. Kaynak: N.C. Gen. Stat. 20-146."},"61":{"q":"Kuzey Carolina'nın \"Şerit Değiştir\" (Move Over) yasası uyarınca, çok şeritli bir yolda yanıp sönen uyarı ışıkları yanan, durmuş bir acil durum veya kamu hizmeti aracına yaklaşan bir sürücü ne yapmalıdır?","options":["Güvenli bir şekilde yapılabiliyorsa, durmuş araca en yakın olmayan bir şeride geçmelidir","Araç ayrılana kadar bulunduğu şeritte tamamen durmalıdır","Yanından geçerken sürekli korna çalmalıdır","Belirlenen hız sınırının en fazla 5 mph altında geçmelidir"],"explanation":"N.C. Gen. Stat. 20-157 uyarınca, gidiş yönünde iki veya daha fazla şeride sahip bir yolda sürücü, güvenli bir şekilde yapılabildiğinde durmuş acil durum/kamu hizmeti aracına en yakın olmayan bir şeride geçmelidir. Tek şeritli bir yolda ise sürücü bunun yerine yavaşlamalı ve durmaya hazır olmalıdır. Kaynak: N.C. Gen. Stat. 20-157."},"62":{"q":"Plakartlı tehlikeli madde taşıyan bir aracın Kuzey Carolina sürücüsü bir demiryolu hemzemin geçidine yaklaşıyor. Sürücü nerede durmalıdır?","options":["En yakın raya 50 feet mesafe içinde, ancak 15 feet'ten daha yakın olmamak üzere","En yakın raya 25 feet mesafe içinde, ancak 5 feet'ten daha yakın olmamak üzere","En yakın raya 100 feet mesafe içinde, ancak 50 feet'ten daha yakın olmamak üzere","En yakın raydan tam 10 feet mesafede"],"explanation":"Otobüsler ve plakartlı/tehlikeli madde (hazmat) araçları, geçmeden önce en yakın raya 50 feet mesafe içinde ve 15 feet'ten daha yakın olmamak üzere durmalı, ardından bakıp dinlemelidir. Bu federal standart (49 CFR 392.10), Kuzey Carolina CDL kılavuzunda öğretilir ve Kuzey Carolina'da geçerlidir. Kaynak: N.C. CDL Driver Handbook; 49 CFR 392.10."},"63":{"q":"İki şeritli bir Kuzey Carolina yolunda (her yönde bir şerit), bir okul otobüsü çocukları bindirmek için kırmızı ışıkları yanıp sönerek ve dur kolu açık şekilde durur. Hangi araçlar durmalıdır?","options":["Her iki yönden yaklaşan trafik durmalıdır","Yalnızca otobüsün arkasındaki trafik durmalıdır","Yalnızca karşı yönden gelen trafik durmalıdır","Sürücüler 20 mph'ye yavaşlarsa kimse durmak zorunda değildir"],"explanation":"N.C. Gen. Stat. 20-217 uyarınca, iki şeritli bir yolda, durmuş okul otobüsüne aynı yol üzerinde herhangi bir yönden yaklaşan her araç tamamen durmalı ve dur işareti geri çekilip otobüs hareket edene kadar durmuş halde kalmalıdır. Kaynak: N.C. Gen. Stat. 20-217(a)."},"64":{"q":"Kuzey Carolina'nın okul otobüsü durma yasası uyarınca, durmuş bir okul otobüsünün KARŞI yönünde seyreden bir aracın sürücüsü hangi durumda durmak ZORUNDA DEĞİLDİR?","options":["Yol, araya giren bir boşluk veya fiziksel bir bariyerle iki ayrı yola bölündüğünde (orta dönüş şeridi yalnızca yolun en az dört şeridi olması halinde sayılır)","Yolda herhangi bir türde boyalı orta çizgi bulunduğunda","Her yönde bir şerit olduğunda","Karşıdan gelen sürücü 15 mph veya daha düşük hıza yavaşladığında"],"explanation":"N.C. Gen. Stat. 20-217(c), karşı yöndeki trafiği yalnızca yolun araya giren bir boşluk (yolun en az dört veya daha fazla şeridi varsa sola dönüş için bir orta şerit dahil) ya da fiziksel bir bariyerle iki ayrı yola bölündüğü durumda muaf tutar. Bölünmemiş bir yolda yalnızca boyalı bir orta çizgi bu koşulu sağlamaz. Kaynak: N.C. Gen. Stat. 20-217(c)."},"65":{"q":"Kuzey Carolina DOT'un bir eyaletler arası veya kontrollü erişimli otoyolda belirleyebileceği azami hız sınırı nedir?","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"N.C. Gen. Stat. 20-141(b) uyarınca, eyaletler arası veya kontrollü erişimli otoyol sisteminde belirlenen bir hız sınırı saatte 70 mil'i aşamaz. Kaynak: N.C. Gen. Stat. 20-141."},"66":{"q":"Belirlenen hız sınırının tüm araç türleri için aynı yapıldığı bir Kuzey Carolina otoyolunda, kamyon hız sınırı otomobil hız sınırıyla nasıl kıyaslanır?","options":["Kamyonlar ve otomobiller aynı belirlenmiş hız sınırına sahiptir","Kamyonlar otomobil sınırının 10 mph altıyla sınırlıdır","Kamyonlar, belirlenen sınırdan bağımsız olarak 55 mph ile sınırlıdır","Kamyonlar yokuşlarda otomobillerden 5 mph daha hızlı gidebilir"],"explanation":"Kuzey Carolina, eyalet çapında ayrı ve daha düşük bir kamyon hız sınırı belirlemez; G.S. 20-141(l), belirlenen sınırı tüm motorlu araç türlerine aynı şekilde uygulanır kılar. (Aşırı boyut/aşırı ağırlık izniyle hareket eden belirli bir araca daha düşük bir sınır uygulanabilir.) Kaynak: N.C. Gen. Stat. 20-141(l)."},"67":{"q":"Ticari kamyonlar Kuzey Carolina'nın Blue Ridge Parkway'inde neden yasaktır?","options":["Kamyon şeritleri veya kaçış rampaları olmayan, dar, virajlı, iki şeritli manzaralı bir yoldur","Yalnızca binek otomobillere açık özel bir paralı yoldur","Tartı istasyonları olmadan başka bir eyalete geçer","Her mil'de ağırlık kısıtlamalı köprüleri vardır"],"explanation":"Ticari araçlar Blue Ridge Parkway'de yasaktır çünkü burası değişken eğimleri, virajları, sınırlı görüş mesafesi ve kamyon şeritleri ya da kaçış kamyon rampaları olmayan, dar, iki şeritli bir Ulusal Park Hizmeti (National Park Service) manzaralı yoludur. Kaynak: National Park Service / Blue Ridge Parkway düzenlemeleri."},"68":{"q":"Bir kamyon Kuzey Carolina'da bölünmüş bir otoyolda arıza yapar. Üç acil durum uyarı cihazı (yansıtıcı üçgenler) nereye yerleştirilmelidir?","options":["Arkaya doğru 10 feet, 100 feet ve 200 feet mesafede, hepsi yaklaşan trafiğe doğru","10 feet, 50 feet ve 150 feet mesafede, ikisi arkaya ve biri öne","Arkaya doğru 5 feet, 75 feet ve 250 feet mesafede","Arkaya doğru 25 feet, 100 feet ve 300 feet mesafede"],"explanation":"Tek yönlü veya bölünmüş bir otoyolda, üç uyarı cihazının üçü de yaklaşan trafiğe doğru, durmuş araçtan 10, 100 ve 200 feet mesafeye yerleştirilir. (İki yönlü bir yolda biri arkaya 10 feet, biri arkaya 100 feet ve biri öne 100 feet konur.) Kaynak: N.C. CDL Driver Handbook; 49 CFR 392.22."},"69":{"q":"Kuzey Carolina \"Şerit Değiştir\" (Move Over) yasası, polis, itfaiye ve ambulansların ötesinde hangi ek araç kategorisini kapsayacak şekilde genişler?","options":["Sarı (amber) yanıp sönen ışıklar yakan altyapı/elektrik hizmeti, yol bakımı ve arızalı araç/çekici (wrecker) araçları","Dörtlü flaşörlerini kullanan herhangi bir binek otomobil","Yalnızca posta dağıtım araçları","Yalnızca eyalet dışı acil durum araçları"],"explanation":"N.C. Gen. Stat. 20-157 ayrıca sarı (amber) yanıp sönen ışıklar yakan \"kamu hizmeti araçlarını\" da kapsar; buna altyapı/elektrik hizmeti (elektrik, gaz, su, iletişim), yol bakımı, çöp toplama ve arızalı araç/çekici (wrecker) hizmeti araçları dahildir. Sürücüler bunlar için şerit değiştirmeli veya yavaşlamalıdır. Kaynak: N.C. Gen. Stat. 20-157."},"70":{"q":"Bir demiryolu geçidinde durduktan sonra, bir Kuzey Carolina otobüs veya plakartlı araç sürücüsü geçiş yaparken aşağıdakilerden hangisini yapmalıdır?","options":["Raylar üzerinde vites değiştirmeyi gerektirmeyecek bir vitesle geçmelidir","Kontrol kazanmak için geçişin ortasında daha düşük bir vitese geçmelidir","Yeniden kontrol etmek için rayların ortasında tekrar durmalıdır","Yakıt tasarrufu için boşta (rölantide) süzülerek geçmelidir"],"explanation":"Kuzey Carolina CDL kılavuzu, sürücülere stop yapmadan tamamen geçmelerini sağlayacak bir vites seçmelerini ve motorun stop etmesini önlemek için raylar üzerindeyken asla vites değiştirmemelerini öğütler. Kaynak: N.C. CDL Driver Handbook; 49 CFR 392.10/392.11."},"71":{"q":"Kuzey Carolina'da, çocukları bindiren veya indiren, durmuş bir okul otobüsünü yasa dışı şekilde geçmenin asgari para cezası nedir?","options":["500 dolar ve Class 1 kabahat (misdemeanor)","100 dolar ve bir ihlal (infraction)","250 dolar ve Class 3 kabahat (misdemeanor)","1.000 dolar ve Class 2 kabahat (misdemeanor)"],"explanation":"N.C. Gen. Stat. 20-217(e) uyarınca, durmuş bir okul otobüsünü geçmek, asgari 500 dolar para cezası taşıyan bir Class 1 kabahattir (misdemeanor) ve hükmün ertelenmesine (prayer for judgment continued) izin verilmez. Bir kişiye çarpmak bunu daha yüksek asgari para cezalı bir suça (felony) yükseltir. Kaynak: N.C. Gen. Stat. 20-217(e),(g)."},"72":{"q":"Triangle Expressway ve diğer Kuzey Carolina Turnpike paralı tesislerinde (örneğin I-540), geçiş ücretleri nasıl tahsil edilir?","options":["Gişe olmadan, NC Quick Pass transponderları veya posta yoluyla fatura kullanılarak tamamen elektronik geçiş ücreti tahsilatı","Her kavşakta yalnızca nakit kabul eden gişeler","Tüm kamyonlar için sabit bir yıllık çıkartma ücreti","Geçiş ücretleri yalnızca eyalet sınırında tahsil edilir"],"explanation":"Kuzey Carolina'nın paralı yolları gişesiz, %100 tamamen elektronik geçiş ücreti tahsilatı kullanır; sürücüler bir NC Quick Pass transponderı/hesabı aracılığıyla öder veya posta yoluyla fatura alır. Kamyonlardan aks sayısına göre daha fazla ücret alınır. Kaynak: NCDOT Turnpike Authority / NC Quick Pass."},"73":{"q":"Kuzey Carolina'nın \"Şerit Değiştir\" (Move Over) yasasının temel bir ihlali için (yaralanma veya maddi hasar olmaksızın) standart para cezası nedir?","options":["250 dolar ihlal (infraction)","50 dolar ihlal (infraction)","500 dolar Class 1 kabahat (misdemeanor)","1.000 dolar suç (felony)"],"explanation":"N.C. Gen. Stat. 20-157'nin temel bir ihlali, 250 dolar para cezasıyla cezalandırılabilen bir ihlaldir (infraction). 500 dolardan fazla maddi hasar veya yaralanma olması halinde kabahate (misdemeanor), ağır yaralanma ya da ölüme yol açması halinde ise Class F suça (felony) yükselir. Kaynak: N.C. Gen. Stat. 20-157."},"74":{"q":"Kuzey Carolina'nın sağdan gitme kuralı uyarınca, yasal azami hızdan daha yavaş seyreden bir araç normalde nerede sürülmelidir?","options":["Geçiş trafiği için ayrılmış sağ şeritte ya da mümkün olduğunca sağ kenara yakın","Hangi şerit daha az kalabalıksa onda","Üç şeritli bir yolun orta şeridinde","Sağ şeridi katılan trafiğe açık bırakmak için sol şeritte"],"explanation":"N.C. Gen. Stat. 20-146, yasal azami hızdan daha yavaş ilerleyen herhangi bir aracın, sollama yaparken veya sola dönüşe hazırlanırken hariç, sağdaki geçiş şeridinde ya da mümkün olduğunca sağ kenara yakın sürülmesini gerektirir. Kaynak: N.C. Gen. Stat. 20-146."},"75":{"q":"Kuzey Carolina'nın okul otobüsü durma yasası açısından, diğer trafiğin durmasını gerektiren bir \"okul otobüsü\" olarak aşağıdakilerden hangisi kabul edilir?","options":["G.S. 115C-243 kapsamında yaşlı vatandaşları taşıyan ve önünde ve arkasında \"okul otobüsü\" (school bus) işareti bulunan bir kamu okulu otobüsü","İşaretli olsun olmasın, bir kreş tarafından kullanılan herhangi bir sarı minibüs","Camları renkli bir tur otobüsü (charter motorcoach)","Kırmızı fren ışıkları olan herhangi bir araç"],"explanation":"N.C. Gen. Stat. 20-217(b), kapsanan bir okul otobüsünü, çocuk veya personel taşıyan bir kamu okulu otobüsünü, G.S. 115C-243 kapsamında yaşlı vatandaşları taşıyan bir kamu okulu otobüsünü ya da çocuk taşıyan özel mülkiyete ait bir otobüsü içerecek şekilde tanımlar; ancak yalnızca önünde ve arkasında açıkça görülebilen \"okul otobüsü\" (school bus) işaretleri bulunması halinde. Kaynak: N.C. Gen. Stat. 20-217(b)."},"76":{"q":"Bir CDL sürücüsünün, plakartlı tehlikeli madde taşırken bile durmasının GEREKMEDİĞİ Kuzey Carolina demiryolu geçidi hangisidir?","options":["Bir polis memuru veya işaretçinin (flagger) trafiği geçirmek için yönlendirdiği bir geçit","Çarpı işaretleri (crossbucks) olan ancak bariyeri olmayan herhangi bir geçit","Kırsal, iki şeritli bir otoyoldaki bir geçit","Belirlenmiş hız sınırı 45 mph'nin üzerinde olan bir geçit"],"explanation":"Bir polis memuru veya işaretçi (flagger) tarafından kontrol edilen geçitlerde, bir iş bölgesindeki tramvay/sanayi manevra raylarında, \"Muaf\" (Exempt) ya da \"Terk Edilmiş\" (Abandoned) olarak işaretlenmiş geçitlerde ve çalışan bir trafik sinyalinin yeşil gösterdiği yerlerde zorunlu durma muaftır. Kaynak: N.C. CDL Driver Handbook; 49 CFR 392.10(b)."},"77":{"q":"Bir okul otobüsü, her yönde iki seyir şeridi olan ve yalnızca sürekli bir orta çift yönlü sola dönüş şeridiyle ayrılan (beş şeritli) bir Kuzey Carolina yolunda durur. Karşı yöndeki trafik durmalı mıdır?","options":["Hayır, çünkü yolun en az dört şeridi olduğunda orta sola dönüş şeridi bir ayırıcı boşluk olarak nitelendirilir","Evet, çünkü bir dönüş şeridi fiziksel bir bariyer değildir","Evet, tüm yollar karşı yöndeki trafiğin durmasını gerektirir","Hayır, karşı yöndeki trafik hiçbir çok şeritli yolda durmak zorunda değildir"],"explanation":"G.S. 20-217(c), yol araya giren bir boşlukla bölündüğünde karşı yöndeki trafiğin devam etmesine izin verir ve yolun en az dört şeridi varsa sola dönüş için bir orta şeridi özellikle buna dahil eder. Orta dönüş şeridi olan beş şeritli bir yol bu koşulu sağlar, dolayısıyla karşı yöndeki trafiğin durması gerekmez. Kaynak: N.C. Gen. Stat. 20-217(c)."},"78":{"q":"Bir sürücü, Kuzey Carolina'da üç yıl içinde ikinci kez durmuş bir okul otobüsünü geçmekten mahkûm olur. Para cezasına ek olarak ehliyet üzerindeki sonuç nedir?","options":["Sürücü ehliyetinin bir yıllığına iptali","Yalnızca 30 günlük askıya alma","Ehliyet işlemi yok, yalnızca ceza puanı","İkinci suçta kalıcı iptal"],"explanation":"N.C. Gen. Stat. 20-217(g1) uyarınca, bu madde kapsamında üç yıllık bir dönem içinde ikinci bir kabahat (misdemeanor) mahkûmiyeti bir yıllık ehliyet iptaliyle sonuçlanır; bir CDL sahibi ayrıca bu süre boyunca ticari araç kullanmaktan men edilir. Kaynak: N.C. Gen. Stat. 20-217(g1)."},"79":{"q":"Kuzey Carolina, belirli bir ticari araç için hangi durumda daha düşük bir belirlenmiş hız sınırı koyabilir?","options":["Araç, ağırlığı veya boyutları nedeniyle özel bir aşırı boyut/aşırı ağırlık izniyle çalışırken","Aracın ikiden fazla aksı olduğunda","Araç eyalet dışında tescilli olduğunda","Römork 40 feet'ten uzun olduğunda"],"explanation":"N.C. Gen. Stat. 20-141(l), aracın veya yükünün herhangi bir ağırlığı ya da boyutu nedeniyle özel bir izinle çalışan bir araç için daha düşük bir hız sınırı belirlenmesine izin verir. Aksi takdirde belirlenmiş sınır tüm araç türleri için aynıdır. Kaynak: N.C. Gen. Stat. 20-141(l); NCDOT aşırı boyut/aşırı ağırlık izin kuralları."},"80":{"q":"Kuzey Carolina'da Ticari Sürücü Ehliyetlerini (CDL) hangi kurum verir?","options":["Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)","Kuzey Carolina Kamu Güvenliği Departmanı","Kuzey Carolina Ulaştırma Departmanı Karayolu Devriyesi","Kuzey Carolina Motorlu Taşıtlar Dairesi (NCDMV)"],"explanation":"Kuzey Carolina'da CDL'ler, NCDOT'un bir bölümü olan Kuzey Carolina Motorlu Taşıtlar Dairesi (NCDMV) tarafından verilir ve yönetilir. FMCSA federal standartları belirler ancak ehliyet vermez. Kaynak: NCDMV Commercial Driver License sayfası ve N.C. CDL Manual, Bölüm 1."},"81":{"q":"Bir Kuzey Carolina CDL'i veya ticari öğrenme izni (commercial learner permit) almak için, bir başvuru sahibinin hangi iki tür sınavı geçmesi gerekir?","options":["Bir yazılı sınav ve bir araç ağırlığı sınavı","Bilgi sınavları ve beceri sınavları","Bir fiziksel çeviklik sınavı ve bir onay (endorsement) sınavı","Bir işveren yol sınavı ve bir federal sınav"],"explanation":"N.C. CDL Manual (Bölüm 1.1), bir CDL veya CLP almak için bilgi sınavlarını ve beceri sınavlarını geçmeniz gerektiğini belirtir. Beceri sınavı, ehliyet almak istediğiniz araç sınıfında verilir. Kaynak: N.C. CDL Manual, Bölüm 1.1."},"82":{"q":"Kuzey Carolina CDL beceri sınavı hangi üç bölümden oluşur?","options":["Yazılı bilgi, görme taraması ve bir yol sınavı","Hava freni kontrolü, bağlantı (coupling) sınavı ve bir otoyol sınavı","Araç (yola çıkış öncesi) muayenesi, temel araç kontrolü ve yolda sürüş","Geri gitme, paralel park ve bir gece sürüşü sınavı"],"explanation":"N.C. CDL Manual'a (Bölüm 1.1.2) göre, beceri sınavının üç bölümü vardır: araç (yola çıkış öncesi) muayene sınavı, temel araç kontrolü sınavı ve yolda sürüş sınavı. Üçü de uygun araç sınıfında geçilmelidir. Kaynak: N.C. CDL Manual, Bölüm 1.1.2."},"83":{"q":"Sınıf veya onaylardan (endorsement) bağımsız olarak HER Kuzey Carolina CDL başvuru sahibinin girmesi gereken bilgi sınavı hangisidir?","options":["Genel bilgi sınavı","Kombinasyon araçları sınavı","Hava frenleri sınavı","Tehlikeli maddeler sınavı"],"explanation":"N.C. CDL Manual (Bölüm 1.1.1), genel bilgi sınavının tüm başvuru sahipleri tarafından alındığını belirtir. Diğer sınavlar (kombinasyon, hava frenleri, hazmat vb.) yalnızca belirli sınıflara veya onaylara (endorsement) uygulanır. Kaynak: N.C. CDL Manual, Bölüm 1.1.1."},"84":{"q":"Her bir Kuzey Carolina CDL bilgi sınavında geçer asgari not nedir?","options":["%70 doğru","%80 doğru","%75 doğru","%85 doğru"],"explanation":"Kuzey Carolina, her bir CDL bilgi sınavında en az %80 doğru gerektirir (örneğin, genel bilgi sınavında 50 sorudan 40'ı, kombinasyon veya hava frenlerinde 20 sorudan 16'sı), her biri ayrı ayrı puanlanır. Kaynak: NCDMV CDL bilgi sınavı standartları (N.C. tarafından benimsenen FMCSA asgari değeri)."},"85":{"q":"Bir Kuzey Carolina Ticari Öğrenme İzni (CLP) ne kadar süreyle geçerlidir?","options":["30 gün, yenileme yapılamaz","180 gün, ek 180 gün için bir kez yenilenebilir","1 yıl, sınırsız yenilemeyle","60 gün, 60 gün için bir kez yenilenebilir"],"explanation":"Bir Kuzey Carolina CLP'si 180 gün geçerlidir ve genel bilgi sınavını tekrar almadan ek 180 gün için bir kez yenilenebilir. Kaynak: NCDMV Commercial Driver License sayfası; N.C. CDL Manual (CLP), 49 CFR 383.25 ile tutarlı."},"86":{"q":"Bir Kuzey Carolina CLP verildikten sonra, bir başvuru sahibi CDL beceri sınavına girmeden önce ne kadar beklemelidir?","options":["En az 30 gün","En az 7 gün","En az 60 gün","En az 14 gün"],"explanation":"Bir CLP sahibi, CDL beceri sınavına girmeden önce CLP verildikten sonra en az 14 gün beklemelidir. Bu federal kural (49 CFR 383.25) NCDMV tarafından uygulanır. Kaynak: NCDMV Commercial Driver License sayfası; 49 CFR 383.25."},"87":{"q":"İlk kez başvuran bir Kuzey Carolina Sınıf A veya Sınıf B başvuru sahibi CDL beceri sınavına girmeden önce hangi federal eğitimin tamamlanması gerekir?","options":["Bir NCDMV ofisinde eyalet tarafından yürütülen bir savunmacı sürüş kursu","Herhangi bir lisanslı CDL sahibiyle kaydedilmiş 120 saatlik direksiyon başında geçen süre","FMCSA Eğitim Sağlayıcı Kütüğü'nde (Training Provider Registry) yer alan bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT)","Bir OSHA işyeri güvenliği sertifikası"],"explanation":"İlk kez bir Sınıf A/B CDL için sınava girmeden önce (ve P, S ve H onayları ya da B'den A'ya yükseltme için) FMCSA Eğitim Sağlayıcı Kütüğü'nde listelenen bir sağlayıcı aracılığıyla federal Giriş Seviyesi Sürücü Eğitimi (ELDT) tamamlanmalıdır. Kaynak: NCDMV CDL sayfası; FMCSA ELDT kuralı (49 CFR Part 380)."},"88":{"q":"İlk kez başvuran Sınıf A ve Sınıf B başvuru sahiplerinin yanı sıra, ELDT hangi onaylar (endorsement) için sınava girmeden önce de gereklidir?","options":["Tank (N), İkili/Üçlü (T) ve Hava Frenleri","Kombinasyon, Hava Frenleri ve Tank (N)","Yolcu (P), Okul Otobüsü (S) ve Tehlikeli Maddeler (H)","Yalnızca Tehlikeli Maddeler (H)"],"explanation":"ELDT, ilk kez Sınıf A/B verilmeden önce, B'den A'ya yükseltmeden önce ve Yolcu (P), Okul Otobüsü (S) ve Tehlikeli Maddeler (H) onaylarından önce uygulanır. H onayı yalnızca teorik ELDT gerektirir. Kaynak: NCDMV CDL sayfası; FMCSA ELDT kuralı (49 CFR Part 380)."},"89":{"q":"Kuzey Carolina CDL başvuru sahipleri ticari sürüş türlerini kendileri beyan etmelidir (self-certify). Kaç tane öz-beyan kategorisi vardır?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört öz-beyan kategorisi vardır: eyaletler arası muaf olmayan (interstate non-excepted), eyaletler arası muaf (interstate excepted), eyalet içi muaf olmayan (intrastate non-excepted) ve eyalet içi muaf (intrastate excepted). Başvuru sahibi, faaliyetine uyan kutuyu işaretler. Kaynak: N.C. CDL Manual, Bölüm 1.2.3."},"90":{"q":"Hangi Kuzey Carolina öz-beyan kategorisi, sürücünün bir federal DOT tıbbi muayene uzmanı belgesi (medical examiner's certificate) sunmasını ve bunu güncel tutmasını gerektirir?","options":["Eyaletler arası muaf (interstate excepted)","Eyaletler arası muaf olmayan (interstate non-excepted)","Eyalet içi muaf (intrastate excepted)","Muaf özel yolcu (excepted private passenger)"],"explanation":"Eyaletler arası muaf olmayan (interstate non-excepted) bir sürücü, 49 CFR Part 391 kapsamındaki federal DOT tıbbi gereksinimlerine tabi olduğunu ve bunları karşıladığını beyan eder ve bir tıbbi muayene uzmanı belgesi (medical examiner's certificate) almalıdır. Çoğu eyaletler arası CDL sahibi muaf olmayan kategoridedir. Kaynak: N.C. CDL Manual, Bölüm 1.2.3."},"91":{"q":"Yalnızca eyaletler arası ticarette ancak münhasıran 49 CFR Part 391'den muaf tutulan faaliyetlerde çalışan bir Kuzey Carolina sürücüsü hangi kategoride öz-beyanda bulunmalıdır?","options":["Eyaletler arası muaf olmayan (interstate non-excepted)","Eyalet içi muaf olmayan (intrastate non-excepted)","Eyaletler arası muaf (interstate excepted)","Eyalet içi muaf (intrastate excepted)"],"explanation":"Eyaletler arası muaf (interstate excepted) bir sürücü, eyaletler arası ticarette çalıştığını ancak münhasıran 49 CFR 390.3(f), 391.2, 391.68 veya 398.3 kapsamında muaf tutulan faaliyetlerde bulunduğunu beyan eder ve bir tıbbi muayene uzmanı belgesi (medical examiner's certificate) almak zorunda DEĞİLDİR. Kaynak: N.C. CDL Manual, Bölüm 1.2.3."},"92":{"q":"Kuzey Carolina kuralları uyarınca, bir sürücü HEM eyaletler arası HEM de eyalet içi ticarette çalışıyorsa, hangi kategoriyi seçmelidir?","options":["Eyalet içi ticaret (intrastate commerce)","Eyaletler arası ticaret (interstate commerce) (daha katı olan kategori)","En sık sürdüğü hangisiyse","İkisinden istediğini serbestçe seçebilir"],"explanation":"N.C. CDL Manual (Bölüm 1.2.1), hem eyaletler arası hem de eyalet içi ticarette çalışan bir sürücünün eyaletler arası ticareti seçmesi gerektiğini belirtir, çünkü bu daha katı yeterlilik gereksinimleri taşır. Kaynak: N.C. CDL Manual, Bölüm 1.2.1."},"93":{"q":"Kuzey Carolina'nın şimdi kullandığı FMCSA Ulusal Kütük (National Registry) sürecinde, muaf olmayan bir sürücünün DOT tıbbi muayene uzmanı belgesi NCDMV'ye normalde nasıl ulaşır?","options":["Sürücü her iki yılda bir doğrudan NCDMV'ye kağıt bir kopya postalamalıdır","İşveren tıbbi kartı NCDMV merkezine faksla gönderir","Sürücünün doktoru sonuçları bildirmek için NCDMV tıbbi birimini arar","Sertifikalı tıbbi muayene uzmanı, muayene sonuçlarını elektronik olarak FMCSA Ulusal Kütük'e (National Registry) iletir; orası da bunları NCDMV'ye aktarır"],"explanation":"FMCSA Ulusal Kütük / NRII süreci kapsamında (2025'te uyumluluk), sertifikalı tıbbi muayene uzmanları CDL/CLP muayene sonuçlarını elektronik olarak Ulusal Kütük'e (National Registry) sunar ve FMCSA tıbbi sertifikasyon durumunu eyalete (NCDMV) aktarır. Sürücülerin artık kağıt kartı NCDMV'ye teslim etmeleri gerekmez. Kaynak: FMCSA National Registry kuralı; NCDMV tıbbi sertifikasyon yönergesi."},"94":{"q":"Kuzey Carolina'da bir sürücünün ticaret kategorisinin öz-beyanı aşağıdaki zamanlardan hangisinde gereklidir?","options":["Yalnızca bir kez, orijinal CDL ilk verildiğinde","Yalnızca sürücü işveren değiştirdiğinde","Bir CLP için başvururken ve bir CDL'i yenilerken, yükseltirken, onay (endorsement) eklerken veya devrederken","Yalnızca sürücü 65 yaşına girdiğinde"],"explanation":"Sürücüler, bir CLP için başvururken ve bir CDL'i yenilerken, yükseltirken, ona onay (endorsement) eklerken veya devrederken eyalete öz-beyan bilgilerini vermelidir. Kaynak: N.C. CDL Manual, Bölüm 1.2 (federal tıbbi sertifikasyon gereksinimleri)."},"95":{"q":"Bir Kuzey Carolina CDL'inin standart geçerlilik süresi (yenilenmiş bir ehliyet için, 65 yaşın altındaki bir sürücü için) nedir?","options":["5 yıl","4 yıl","8 yıl","10 yıl"],"explanation":"N.C.G.S. 20-7 uyarınca, yenilenmiş bir ticari sürücü ehliyeti, yenilenen ehliyetin son kullanma tarihinden beş yıl sonra sona erer. CDL'ler çevrimiçi yenilenemez ve bir NCDMV ofisinde şahsen yenilenmelidir. Kaynak: N.C.G.S. 20-7; NCDMV ehliyet yenileme sayfası."},"96":{"q":"Kuzey Carolina CDL yenilemesi standart bir (Sınıf C) ehliyet yenilemesinden nasıl farklıdır?","options":["Bir CDL, son kullanma tarihinden sonra iki yıla kadar çevrimiçi yenilenebilir","Bir CDL, işverenin motorlu taşıyıcısı tarafından otomatik olarak yenilenir","Bir CDL, sürücü yol sınavını geçtikten sonra hiçbir zaman sona ermez","Bir CDL, bir NCDMV sürücü ehliyet ofisinde şahsen yenilenmelidir; çevrimiçi veya posta yoluyla yenilenemez"],"explanation":"Kuzey Carolina CDL'leri, birçok standart ehliyetin aksine, bir NCDMV sürücü ehliyet ofisinde şahsen yenilenmelidir ve çevrimiçi veya posta yoluyla yenilenemez. Kaynak: NCDMV ehliyet yenileme/değiştirme sayfası; N.C.G.S. 20-7."},"97":{"q":"Bir Kuzey Carolina CLP'si için başvururken, aşağıdaki belgelerden hangisi başvurunun bir parçası olarak gereklidir?","options":["Kimlik/yaş kanıtı, Sosyal Güvenlik numarası, ikamet ve sorumluluk sigortası (liability insurance) kanıtı","Bir lise diploması ve noter onaylı bir işveren mektubu","Başka hiçbir belge olmadan yalnızca bir pasaport","Araç sahipliği kanıtı ve bir araç ruhsatı"],"explanation":"NCDMV, bir CLP başvuru sahibinden kimlik ve yaş kanıtı, Sosyal Güvenlik numarası kanıtı, iki ikamet belgesi (vatandaş olmayanlar için yasal mevcudiyet kanıtı) ve Kuzey Carolina'da lisanslı bir sağlayıcıdan sorumluluk sigortası (liability insurance) kanıtı sunmasını ister. Kaynak: NCDMV Commercial Driver License sayfası."},"98":{"q":"Kuzey Carolina'da, tek bir CDL bilgi sınavı için bir günde kaç deneme hakkı verilir?","options":["Test başına günde bir deneme","Test başına günde üç deneme","Bir günde sınırsız deneme","Test başına günde iki deneme"],"explanation":"N.C. CDL Manual, her bilgi sınavı için günde yalnızca bir denemeye izin verildiğini belirtir. Genel bilgi sınavında üç başarısız denemeden sonra, sonraki üç deneme için başka bir başvuru ücreti gerekir. Kaynak: N.C. CDL Manual, Bölüm 1.1."},"99":{"q":"Geçildikten sonra, Kuzey Carolina CDL sınav sonuçları NCDMV bilgisayar dosyalarında ne kadar süreyle geçerlidir?","options":["Sınav tarihinden itibaren 30 gün","Sınav tarihinden itibaren 180 gün","Sınav tarihinden itibaren 1 yıl","Sınav tarihinden itibaren 90 gün"],"explanation":"N.C. CDL Manual, tüm sınav sonuçlarının NCDMV bilgisayar dosyalarında sınav tarihinden itibaren 90 gün geçerli olduğunu belirtir. Bir başvuru sahibi, kalan gereksinimleri bu süre içinde tamamlamalıdır. Kaynak: N.C. CDL Manual, Bölüm 1.1."}},"es":{"0":{"q":"En las carreteras de Carolina del Norte, ¿cuál es el ancho máximo legal de un vehículo comercial o su carga sin un permiso de sobredimensión?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"Carolina del Norte limita el ancho exterior total de un vehículo o su carga a 102 pulgadas (8 pies 6 pulgadas) en todas las vías; cualquier cosa más ancha requiere un permiso. Fuente: N.C. Gen. Stat. 20-116(a) y el NCDOT Oversize/Overweight Permit Handbook."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo en las carreteras de Carolina del Norte sin un permiso?","options":["13 pies","13 pies 6 pulgadas","14 pies","14 pies 6 pulgadas"],"explanation":"La ley de Carolina del Norte fija la altura máxima del vehículo, vacío o con carga, en 14 pies. Fuente: N.C. Gen. Stat. 20-116(c) y el NCDOT Oversize/Overweight Permit Handbook."},"2":{"q":"En Carolina del Norte, ¿cuál es el peso bruto máximo permitido sobre un solo eje?","options":["18,000 libras","20,000 libras","22,400 libras","25,000 libras"],"explanation":"Carolina del Norte limita el peso de un solo eje a 20,000 libras, lo que coincide con el estándar federal. Fuente: N.C. Gen. Stat. 20-118(b)(1) y el NCDOT Oversize/Overweight Permit Handbook."},"3":{"q":"En Carolina del Norte, ¿cuál es el peso bruto máximo permitido sobre un eje tándem?","options":["34,000 libras","36,000 libras","38,000 libras","40,000 libras"],"explanation":"Carolina del Norte fija el máximo del eje tándem en 38,000 libras (el límite federal es de 34,000; la cifra establecida por ley en Carolina del Norte es de 38,000). Fuente: N.C. Gen. Stat. 20-118(b)(2) y el NCDOT Oversize/Overweight Permit Handbook."},"4":{"q":"¿Cuál es la longitud total máxima de un vehículo individual (de dos o más ejes) en Carolina del Norte sin un permiso?","options":["35 pies","40 pies","45 pies","53 pies"],"explanation":"Un vehículo individual que tenga dos o más ejes no puede exceder los 40 pies de longitud total, incluidas las defensas delantera y trasera. Fuente: N.C. Gen. Stat. 20-116(d)(1) y el NCDOT Oversize/Overweight Permit Handbook."},"5":{"q":"¿Cuál es la longitud máxima general para una combinación de dos vehículos acoplados entre sí en Carolina del Norte?","options":["55 pies","60 pies","65 pies","75 pies"],"explanation":"Ninguna combinación de dos vehículos puede exceder una longitud total de 60 pies, incluidas las defensas delantera y trasera, salvo que se disponga lo contrario. Fuente: N.C. Gen. Stat. 20-116(e) y el NCDOT Oversize/Overweight Permit Handbook."},"6":{"q":"En Carolina del Norte, un camión tractor que arrastra un solo semirremolque está exento del límite de longitud de combinación de 60 pies siempre que el semirremolque no exceda qué longitud?","options":["48 pies","50 pies","53 pies","57 pies"],"explanation":"Un camión tractor (unidad de potencia) que arrastra un semirremolque de no más de 53 pies puede exceder el máximo total de 60 pies en todas las vías de Carolina del Norte. Fuente: N.C. Gen. Stat. 20-116(e) y el NCDOT Oversize/Overweight Permit Handbook."},"7":{"q":"¿Cuál es el peso bruto vehicular máximo para un tractor-semirremolque típico de cinco ejes en las carreteras de Carolina del Norte sin un permiso de sobrepeso?","options":["73,280 libras","76,000 libras","80,000 libras","84,000 libras"],"explanation":"El peso bruto vehicular máximo de Carolina del Norte es de 80,000 libras, sujeto a los límites por eje y de la fórmula de puente. Fuente: N.C. Gen. Stat. 20-118 y el NCDOT Oversize/Overweight Permit Handbook."},"8":{"q":"¿Cómo determina Carolina del Norte el peso bruto permitido en función del espaciamiento de los ejes en sus carreteras?","options":["Mediante un multiplicador fijo por eje establecido por el condado","Mediante la fórmula federal de puente basada en la medición de los ejes extremos","Únicamente mediante el GVWR del fabricante del vehículo","Mediante la cantidad de neumáticos que tocan la vía"],"explanation":"El peso bruto se determina mediante la medición de los ejes extremos según la fórmula federal de puente (ley de puentes). La asignación de 23 U.S.C. 127 aplica a todas las vías estatales a menos que estén señalizadas. Fuente: N.C. Gen. Stat. 20-118(c)(19) y el NCDOT Oversize/Overweight Permit Handbook."},"9":{"q":"¿Qué agencia de Carolina del Norte emite los permisos de sobredimensión/sobrepeso para vehículos que exceden los límites legales de tamaño o peso?","options":["La N.C. Division of Motor Vehicles (DMV)","La unidad de permisos de sobredimensión/sobrepeso del N.C. Department of Transportation (NCDOT)","La N.C. State Highway Patrol","La oficina del sheriff del condado donde comienza el viaje"],"explanation":"Los permisos de sobredimensión/sobrepeso son emitidos por la unidad de permisos de sobredimensión/sobrepeso del NCDOT (Central Permit Office en Garner, NC). Fuente: NCDOT Oversize/Overweight Permit Handbook."},"10":{"q":"¿Por cuánto tiempo es válido un permiso de sobredimensión/sobrepeso de un solo viaje de Carolina del Norte?","options":["5 días calendario para un viaje","10 días calendario para un solo viaje","30 días calendario para un viaje","Un año a partir de la fecha de vigencia"],"explanation":"Un permiso de un solo viaje es válido por 10 días calendario para un solo viaje; la tarifa estatal varía entre $12 y $48. Fuente: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit)."},"11":{"q":"Bajo un permiso de un solo viaje de Carolina del Norte, ¿cuál es el peso máximo permitido sobre un grupo de ejes tándem (pesos por eje, no el bruto)?","options":["44,000 libras","46,000 libras","50,000 libras","60,000 libras"],"explanation":"Con un permiso de un solo viaje, los pesos por eje permitidos son: eje direccional 20,000; sencillo 25,000; tándem 50,000; tridem 60,000; y grupo de cuatro o más ejes 68,000 libras. Fuente: NCDOT Oversize/Overweight Permit Handbook (pesos por eje del Single Trip Permit)."},"12":{"q":"Para calificar para un permiso de sobrepeso de Carolina del Norte que permita el traslado de hasta 90,000 libras de un solo elemento, el vehículo generalmente debe tener al menos qué distancia entre ejes mínima?","options":["Distancia entre ejes de 41 pies","Distancia entre ejes de 48 pies","Distancia entre ejes de 51 pies","Distancia entre ejes de 57 pies"],"explanation":"Una combinación de vehículos con una distancia entre ejes mínima de 51 pies puede calificar para el traslado de hasta 90,000 libras; por encima de 90,000 libras el permiso es específico para la ruta. Fuente: NCDOT Oversize/Overweight Permit Handbook (Annual Permit / Overweight)."},"13":{"q":"En Carolina del Norte, una carga que excede qué peso bruto se clasifica como 'superload' (supercarga) que requiere una solicitud escrita de superload y una revisión de ingeniería de puentes?","options":["El peso bruto excede las 90,000 libras","El peso bruto excede las 112,000 libras","El peso bruto excede las 122,000 libras","El peso bruto excede las 132,000 libras"],"explanation":"Se requiere un permiso de superload cuando el peso bruto excede las 132,000 libras (o el peso del eje direccional excede las 20,000 libras, o el ancho excede los 16 pies). Conlleva una tarifa de solicitud no reembolsable de $100 más cargos adicionales. Fuente: NCDOT Oversize/Overweight Permit Handbook (Superload Permit)."},"14":{"q":"Cuando una carga con permiso de Carolina del Norte tiene un voladizo trasero mayor a 4 pies, ¿qué debe exhibirse para circular durante el día?","options":["Una luz ámbar intermitente en la parte trasera","Una bandera roja cuadrada de 18 pulgadas","Un letrero de 'WIDE LOAD'","Un reflector triangular rojo"],"explanation":"Un voladizo trasero que exceda los 4 pies debe exhibir una bandera roja cuadrada de 18 pulgadas para circular durante el día y luces de gálibo por la noche; la carga no puede extenderse más de 14 pies más allá de la parte trasera del vehículo, y el voladizo máximo es de 14 pies. Fuente: NCDOT Oversize/Overweight Permit Handbook (Overhang)."},"15":{"q":"En un permiso de Carolina del Norte, las banderas de advertencia que marcan el punto más ancho de una carga sobreancha deben ser de qué tamaño y color?","options":["12 pulgadas cuadradas, amarillas","16 pulgadas cuadradas, solo naranja","18 pulgadas cuadradas, rojas o naranjas","24 pulgadas cuadradas, solo rojas"],"explanation":"Las banderas deben ser cuadradas de 18 pulgadas, rojas o naranjas, colocadas en el punto más ancho de la sobreanchura o según se especifique en el permiso. Fuente: NCDOT Oversize/Overweight Permit Handbook (Flags)."},"16":{"q":"En una carretera de dos carriles y dos sentidos de Carolina del Norte, generalmente se requiere un vehículo escolta delantero cuando una carga con permiso excede qué ancho?","options":["10 pies de ancho","12 pies de ancho","14 pies de ancho","16 pies de ancho"],"explanation":"Se requiere una escolta delantera para cargas con permiso de más de 12 pies de ancho en carreteras de dos carriles y dos sentidos, con una escolta trasera en carreteras de varios carriles o según lo indicado en el permiso. Fuente: NCDOT Oversize/Overweight Permit Handbook (Escorts)."},"17":{"q":"Según las normas de permisos de Carolina del Norte, se requiere una escolta delantera para cualquier carga con permiso cuyo peso sea mayor a qué umbral?","options":["Mayor a 80,000 libras","Mayor a 112,000 libras","Mayor a 132,000 libras","Mayor a 149,999 libras"],"explanation":"Se requiere una escolta delantera para un peso mayor a 149,999 libras; se requieren escoltas delantera y trasera para una longitud total de 150 pies o más. Fuente: NCDOT Oversize/Overweight Permit Handbook (Escorts)."},"18":{"q":"La ley de Carolina del Norte ofrece una mayor variación de peso fuera de la Interestatal para productos agrícolas y forestales. ¿Cuál es el límite incrementado del eje sencillo bajo esta variación?","options":["20,000 libras","21,500 libras","22,000 libras","26,000 libras"],"explanation":"Para productos agrícolas y forestales que califican y se transportan fuera del sistema Interestatal, Carolina del Norte permite hasta 22,000 libras en eje sencillo, 42,000 libras en eje tándem y 90,000 libras de peso bruto. Fuente: N.C. Gen. Stat. 20-118(c)(12)."},"19":{"q":"La tolerancia de peso del 10 por ciento de Carolina del Norte ¿a cuáles límites aplica?","options":["A los límites del eje sencillo y del eje tándem","Al límite bruto de 80,000 libras y a los límites por eje de la Interestatal","Solo a los pesos por grupo de ejes, excluyendo los ejes sencillos/tándem, el tope bruto de 80,000 libras, los puentes señalizados y las Interestatales","A todos los límites de peso de puentes señalizados en todo el estado"],"explanation":"La tolerancia del 10 por ciento aplica solo a los pesos por grupo de ejes (fórmula de puente); no aplica a los límites de eje sencillo ni de eje tándem, al máximo bruto de 80,000 libras, a los puentes señalizados ni a las carreteras Interestatales. Fuente: N.C. Gen. Stat. 20-118(h)."},"20":{"q":"En Carolina del Norte, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una clasificación de peso bruto vehicular (GVWR) de 26,001 libras o más, siempre que el vehículo que se remolca tenga un GVWR de más de 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Carolina del Norte sigue la clasificación federal: se requiere un CDL Clase A para cualquier combinación de vehículos con un GVWR de 26,001 libras o más donde la(s) unidad(es) remolcada(s) excedan las 10,000 libras de GVWR. Fuente: la página de Commercial Driver License de NCDMV y el N.C. Commercial Driver License Manual."},"21":{"q":"Según las normas de Carolina del Norte, un vehículo individual con un GVWR de 26,001 libras o más, que remolca una unidad que no excede las 10,000 libras de GVWR, ¿qué clase de CDL requiere?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"Un CDL Clase B cubre un vehículo individual con clasificación de 26,001 libras de GVWR o más, además de cualquier vehículo remolcado que no exceda las 10,000 libras de GVWR. Fuente: la página de Commercial Driver License de NCDMV y el N.C. CDL Manual."},"22":{"q":"¿Qué clase de CDL de Carolina del Norte aplica a un vehículo que no cumple con los umbrales de peso de la Clase A o B pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que transporta materiales peligrosos con placard?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"En Carolina del Norte se requiere un CDL Clase C para vehículos que no cumplen con la Clase A o B que están diseñados para transportar 16 o más personas (incluido el conductor) o que transportan materiales peligrosos con placard. Fuente: la página de Commercial Driver License de NCDMV y el N.C. CDL Manual."},"23":{"q":"En Carolina del Norte, ¿cuál es la edad mínima para obtener un CDL restringido únicamente a la conducción comercial intraestatal (dentro del estado)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Carolina del Norte permite un CDL a los 18 años solo para operación intraestatal. Los conductores deben tener 21 años para el comercio interestatal o para transportar materiales peligrosos. Fuente: requisitos de Commercial Driver License de NCDMV; N.C.G.S. Chapter 20, Article 2C."},"24":{"q":"¿Qué edad mínima debe tener un conductor de Carolina del Norte para operar un vehículo motorizado comercial en el comercio interestatal o para tener un endoso de materiales peligrosos?","options":["18 años","19 años","20 años","21 años"],"explanation":"Carolina del Norte requiere una edad mínima de 21 años para la conducción comercial interestatal y para un endoso de materiales peligrosos (H); 18 es la edad mínima para la operación solo intraestatal. Fuente: requisitos de Commercial Driver License de NCDMV; N.C.G.S. Chapter 20, Article 2C."},"25":{"q":"¿Qué endoso necesita un titular de CDL de Carolina del Norte para transportar materiales peligrosos en cantidades que requieran placards?","options":["Endoso N","Endoso H","Endoso T","Endoso P"],"explanation":"El endoso H (HazMat, materiales peligrosos) se requiere para transportar cantidades de materiales peligrosos que requieren placard. Requiere un examen de conocimientos más una evaluación de amenazas de seguridad de la TSA. Fuente: endosos de CDL de NCDMV; 49 CFR 383.93."},"26":{"q":"En Carolina del Norte, ¿qué endoso se requiere para conducir un vehículo cisterna diseñado para transportar una carga líquida o gaseosa en un tanque de al menos 1,000 galones de capacidad?","options":["Endoso H","Endoso T","Endoso N","Endoso X"],"explanation":"El endoso N (vehículo cisterna) se requiere para vehículos cisterna con una capacidad nominal individual de 1,000 galones o más que transportan líquidos o gases. Fuente: endosos de CDL de NCDMV; N.C. CDL Manual; 49 CFR 383.5/383.93."},"27":{"q":"Un conductor con CDL de Carolina del Norte que arrastra combinaciones de remolques dobles o triples debe tener ¿qué endoso?","options":["Endoso T","Endoso N","Endoso P","Endoso S"],"explanation":"El endoso T autoriza la operación de combinaciones de remolques dobles y triples. Se obtiene aprobando un examen de conocimientos; no se requiere un examen de habilidades por separado. Fuente: endosos de CDL de NCDMV; N.C. CDL Manual."},"28":{"q":"¿Qué endoso combinado aparece en un CDL de Carolina del Norte cuando un conductor está autorizado para operar un vehículo cisterna que también transporta materiales peligrosos?","options":["Endoso HT","Endoso X","Endoso NP","Endoso Z"],"explanation":"Carolina del Norte emite el endoso X para representar la combinación de los endosos de cisterna (N) y de materiales peligrosos (H) en un solo CDL. Fuente: endosos/restricciones de CDL de NCDMV."},"29":{"q":"En Carolina del Norte, ¿qué endosos de CDL requieren aprobar un examen de HABILIDADES al volante (no solo un examen de conocimientos)?","options":["H y N","N y T","P y S","H y T"],"explanation":"Los endosos de pasajeros (P) y de autobús escolar (S) requieren un examen de habilidades/manejo en el vehículo apropiado, mientras que los H, N y T se obtienen solo mediante exámenes de conocimientos. Fuente: endosos de CDL de NCDMV; N.C. CDL Manual."},"30":{"q":"Antes de que un solicitante de Carolina del Norte pueda obtener un endoso de autobús escolar (S), ¿qué otro endoso debe tener primero?","options":["H (HazMat)","N (cisterna)","T (dobles/triples)","P (pasajeros)"],"explanation":"Según las normas federales y de Carolina del Norte, el endoso de autobús escolar (S) requiere que el conductor primero califique para el endoso de pasajeros (P). Fuente: endosos de CDL de NCDMV; 49 CFR 383.93(b)."},"31":{"q":"¿Por cuánto tiempo es válido un Commercial Learner Permit (CLP) de Carolina del Norte antes de que deba renovarse?","options":["90 días","180 días","1 año","30 días"],"explanation":"Un CLP de Carolina del Norte es válido por 180 días y puede renovarse una vez por 180 días adicionales sin volver a presentar el examen de conocimientos generales. Fuente: la página de Commercial Driver License de NCDMV; 49 CFR 383.25."},"32":{"q":"Según las normas federales adoptadas por Carolina del Norte, ¿cuál es el tiempo mínimo que un solicitante de CDL debe tener un Commercial Learner Permit antes de presentar el examen de habilidades (manejo) del CDL?","options":["7 días","14 días","30 días","60 días"],"explanation":"Un solicitante debe tener el CLP por un mínimo de 14 días antes de que se le permita presentar el examen de habilidades del CDL. Carolina del Norte aplica este requisito federal. Fuente: la página de CDL de NCDMV; 49 CFR 383.25(e)."},"33":{"q":"Al operar bajo un Commercial Learner Permit de Carolina del Norte, el titular del CLP debe ir acompañado por una persona que tenga ¿qué credencial?","options":["Cualquier licencia de conducir Clase C válida","Un CDL válido de la misma clase o superior con los endosos adecuados","Un permiso de instrucción de Carolina del Norte","No se requiere conductor acompañante"],"explanation":"Un titular de CLP siempre debe ir acompañado por alguien que tenga un CDL válido de la clase y endosos apropiados, sentado en el asiento delantero. Fuente: la página de CDL de NCDMV; 49 CFR 383.25."},"34":{"q":"¿Qué requisito de capacitación para conductores de nivel inicial (ELDT) aplica en Carolina del Norte para una persona que obtiene un CDL por primera vez?","options":["Capacitación de cualquier instructor privado que elija el conductor","Capacitación de un proveedor incluido en el FMCSA Training Provider Registry","Solo un curso en video en línea aprobado por NCDMV","No se requiere capacitación formal, solo los exámenes"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de CDL por primera vez (y quienes actualizan de B a A o buscan los endosos P, S o H) deben completar el ELDT de un proveedor del FMCSA Training Provider Registry antes de presentar el examen. Fuente: la regla ELDT de FMCSA; la página de CDL de NCDMV."},"35":{"q":"Para el endoso de HazMat (H) de Carolina del Norte, ¿qué tipo de ELDT debe completarse y cuándo?","options":["Capacitación teórica únicamente antes del examen de conocimientos","Capacitación al volante antes del examen de habilidades","Tanto teórica como al volante antes del examen de manejo","No se requiere ELDT para HazMat"],"explanation":"El ELDT para el endoso H es únicamente capacitación teórica (de conocimientos), completada a través de un proveedor del Training Provider Registry antes del examen estatal de conocimientos; no hay un componente al volante para el H. Fuente: la regla ELDT de FMCSA (49 CFR Part 380, Subpart F)."},"36":{"q":"Además de aprobar el examen de conocimientos, ¿qué requiere Carolina del Norte antes de emitir un endoso de HazMat (H)?","options":["Una exención de visión de NCDMV","Una evaluación de amenazas de seguridad de la TSA que incluye la toma de huellas dactilares","Cinco años de experiencia de conducción","Un examen de habilidades al volante por separado"],"explanation":"El endoso H requiere una verificación de antecedentes del TSA Hazmat Endorsement Threat Assessment Program con toma de huellas dactilares; el endoso generalmente se renueva cada cinco años. Fuente: la página de CDL de NCDMV; el programa HME de la TSA; 49 CFR 1572."},"37":{"q":"Al solicitar un CDL de Carolina del Norte, ¿qué conjunto de documentos debe presentar un solicitante?","options":["Solo una tarjeta de Seguro Social","Comprobante de identidad/edad, número de Seguro Social, residencia en Carolina del Norte y presencia legal","Solo un pasaporte y nada más","Solo comprobante de seguro de responsabilidad civil"],"explanation":"NCDMV requiere documentación de identidad/fecha de nacimiento, número de Seguro Social, residencia en Carolina del Norte y presencia legal (ciudadanía estadounidense o estatus legal), además de comprobante de seguro de responsabilidad civil. Fuente: requisitos de documentos de Commercial Driver License de NCDMV."},"38":{"q":"¿Entre cuántas categorías de autocertificación médica debe elegir un solicitante de CDL de Carolina del Norte al certificar el tipo de operación comercial que realiza?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"Los titulares de CDL de Carolina del Norte se autocertifican en una de cuatro categorías: interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada o intraestatal exceptuada. Fuente: autocertificación médica de CDL de NCDMV (Form CDL-MED-1)."},"39":{"q":"¿Qué categoría de autocertificación de CDL de Carolina del Norte requiere que el conductor mantenga un certificado válido de examinador médico en archivo con NCDMV?","options":["Interestatal exceptuada","Interestatal no exceptuada","Intraestatal exceptuada","Ninguna categoría requiere un certificado médico"],"explanation":"Un conductor que se certifica como Interestatal No Exceptuado está sujeto a 49 CFR Part 391 y debe obtener y mantener un certificado de examinador médico con NCDMV; las categorías exceptuadas no están obligadas a hacerlo. Fuente: autocertificación de CDL de NCDMV; 49 CFR 391.41 / 383.71."},"40":{"q":"En Carolina del Norte, ¿cuál es la concentración máxima de alcohol en sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial?","options":["0.02","0.04","0.08","0.10"],"explanation":"Carolina del Norte fija el umbral de deterioro para CMV en 0.04 de BAC bajo G.S. 20-138.2, la mitad del límite de 0.08 para conductores comunes. El NC CDL manual incluye conducir un CMV con un BAC de 0.04 o más como una infracción mayor."},"41":{"q":"Por una primera infracción mayor (como DWI o un BAC de 0.04 o más) cometida en un vehículo que NO transporta materiales peligrosos con placard, ¿por cuánto tiempo se descalifica a un titular de CDL de Carolina del Norte?","options":["60 días","120 días","1 año","3 años"],"explanation":"Bajo G.S. 20-17.4 y el NC CDL manual (que reflejan 49 CFR 383.51), una primera infracción mayor descalifica al conductor por al menos 1 año cuando no hay materiales peligrosos con placard involucrados."},"42":{"q":"Si un titular de CDL de Carolina del Norte comete una primera infracción mayor mientras opera un vehículo con placard de materiales peligrosos, ¿a cuánto aumenta el período de descalificación?","options":["1 año","2 años","3 años","5 años"],"explanation":"G.S. 20-17.4 y el NC CDL manual disponen que una primera infracción mayor mientras se transportan materiales peligrosos con placard resulta en una descalificación de 3 años en lugar del estándar de 1 año."},"43":{"q":"Según la ley de Carolina del Norte, ¿cuál es la descalificación para un titular de CDL condenado por una SEGUNDA infracción mayor (un segundo DWI, negativa o similar) que surja de un incidente separado?","options":["3 años","5 años","10 años","De por vida"],"explanation":"G.S. 20-17.4 y el NC CDL manual imponen una descalificación de CDL de por vida por una segunda infracción mayor que surja de un incidente separado. En algunos casos puede ser posible una reinstalación limitada después de 10 años, pero la descalificación en sí es de por vida."},"44":{"q":"Un titular de CDL de Carolina del Norte es detenido por conducir bajo los efectos en un CMV y se niega a someterse a una prueba química (de aliento o sangre). ¿Cómo se trata la negativa a efectos de la descalificación del CDL?","options":["No conlleva ninguna sanción de CDL, solo una sanción a la licencia personal","Es una infracción grave de tránsito (descalificación de 60 días)","Es una infracción mayor (descalificación de al menos 1 año)","Resulta en una descalificación de por vida en la primera negativa"],"explanation":"Bajo la ley de consentimiento implícito de Carolina del Norte y G.S. 20-17.4, negarse a una prueba química es una infracción mayor, que descalifica al conductor por al menos 1 año (3 años si transporta materiales peligrosos con placard), igual que una condena."},"45":{"q":"Según el estatuto de consentimiento implícito de Carolina del Norte, al operar un vehículo comercial en las vías del estado, se considera que un conductor con CDL ha consentido a cuál de las siguientes opciones cuando es detenido legalmente por conducir bajo los efectos?","options":["Solo una prueba de sobriedad en campo","Pruebas químicas de aliento, sangre u orina","Una inspección del vehículo sin orden judicial","La entrega del CDL en el lugar"],"explanation":"La ley de consentimiento implícito de Carolina del Norte (G.S. 20-16.2) dispone que todo conductor consiente implícitamente a un análisis químico de aliento, sangre u otro fluido corporal cuando se le imputa una infracción de consentimiento implícito; la negativa desencadena la revocación de la licencia y la descalificación del CDL."},"46":{"q":"¿Cuántas infracciones graves de tránsito dentro de un período de 3 años (en un CMV) debe cometer un titular de CDL de Carolina del Norte antes de enfrentar una descalificación de 60 días?","options":["1","2","3","4"],"explanation":"G.S. 20-17.4 y el NC CDL manual descalifican a un conductor por 60 días tras una SEGUNDA infracción grave de tránsito que surja de incidentes separados dentro de 3 años."},"47":{"q":"En Carolina del Norte, una TERCERA infracción grave de tránsito dentro de un período de 3 años resulta en una descalificación de CDL de ¿cuánto tiempo?","options":["60 días","120 días","180 días","1 año"],"explanation":"Bajo G.S. 20-17.4 y el NC CDL manual, una tercera infracción grave de tránsito (incidentes separados) dentro de 3 años resulta en una descalificación de 120 días, cumplida al final de cualquier descalificación previa."},"48":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción grave de tránsito' para un titular de CDL de Carolina del Norte?","options":["Exceso de velocidad de 15 mph o más por encima del límite señalizado","Una infracción de estacionamiento en un CMV","Conducir 5 mph por encima del límite","Un registro vehicular vencido"],"explanation":"El NC CDL manual y 49 CFR 383.51 definen el exceso de velocidad excesivo (15 mph o más por encima del límite) como una infracción grave de tránsito. Las infracciones de estacionamiento y de registro están expresamente excluidas de esa categoría."},"49":{"q":"Según las normas de Carolina del Norte, ¿cuál de estas NO se cuenta como una infracción grave de tránsito a efectos de la descalificación del CDL?","options":["Conducción imprudente","Seguir a demasiada distancia corta","Cambios de carril indebidos o erráticos","Conducir un CMV con un faro fundido"],"explanation":"El NC CDL manual incluye la conducción imprudente, seguir a demasiada distancia corta y los cambios de carril indebidos/erráticos entre las infracciones graves de tránsito bajo G.S. 20-17.4 / 49 CFR 383.51. Un defecto de equipo como un faro fundido no está en esa lista."},"50":{"q":"Conducir un CMV en Carolina del Norte sin la clase apropiada de CDL o sin el endoso requerido se trata como ¿qué tipo de infracción?","options":["Una infracción mayor (descalificación de 1 año)","Una infracción grave de tránsito","Una infracción de orden de fuera de servicio","Una infracción de equipo no reportable"],"explanation":"El NC CDL manual y 49 CFR 383.51 incluyen conducir un CMV sin la clase de CDL o el endoso apropiado (o sin tener el CDL en posesión) como una infracción grave de tránsito, que puede desencadenar descalificaciones de 60/120 días cuando se combina con otras infracciones graves."},"51":{"q":"Para un titular de CDL de Carolina del Norte, enviar mensajes de texto mientras conduce un vehículo motorizado comercial se clasifica como qué a efectos de la descalificación?","options":["Una infracción mayor","Una infracción grave de tránsito","Una infracción de orden de fuera de servicio","Una infracción de cruce ferroviario"],"explanation":"Bajo G.S. 20-137.4A y el NC CDL manual (en consonancia con 49 CFR 383.51 y 392.80), enviar mensajes de texto mientras se conduce un CMV es una infracción grave de tránsito, que contribuye a las descalificaciones de 60/120 días."},"52":{"q":"La ley de Carolina del Norte restringe el uso de un teléfono móvil por parte de un conductor de CMV mientras conduce a cuál de las siguientes opciones?","options":["Solo el uso de manos libres","Uso solo cuando está detenido en un semáforo en rojo","Llamadas de menos de un minuto","El uso de cualquier teléfono de mano para llamadas de voz"],"explanation":"G.S. 20-137.4A prohíbe a los operadores de CMV sujetos a las Partes 390/392 de FMCSA usar un teléfono móvil de mano; solo se permite la operación de manos libres. Una infracción por teléfono de mano en un CMV es una infracción grave de tránsito."},"53":{"q":"¿Cuál es el período de descalificación para la PRIMERA condena de un titular de CDL de Carolina del Norte por violar una orden de fuera de servicio mientras opera un CMV (sin materiales peligrosos)?","options":["Al menos 30 días","Al menos 60 días","Al menos 90 días","Al menos 180 días"],"explanation":"G.S. 20-17.4 y el NC CDL manual fijan una primera infracción de orden de fuera de servicio en no menos de 180 días (hasta 1 año) para un CMV estándar, muy por encima de la sanción para la mayoría de las infracciones graves."},"54":{"q":"Si un titular de CDL de Carolina del Norte viola una orden de fuera de servicio mientras transporta materiales peligrosos con placard o 16 o más pasajeros, la PRIMERA infracción conlleva una descalificación de al menos ¿cuánto tiempo?","options":["90 días","180 días","1 año","3 años"],"explanation":"Bajo G.S. 20-17.4, una primera infracción de fuera de servicio mientras se transportan materiales peligrosos con placard o se llevan 16 o más pasajeros es de no menos de 180 días (y hasta 2 años), un máximo más largo que la infracción de fuera de servicio estándar."},"55":{"q":"Según la ley de Carolina del Norte, una SEGUNDA infracción de orden de fuera de servicio dentro de un período de 10 años descalifica a un titular de CDL por ¿qué período mínimo?","options":["180 días","1 año","2 años","5 años"],"explanation":"G.S. 20-17.4 y el NC CDL manual descalifican a un conductor por no menos de 2 años (hasta 5 años) por una segunda infracción de orden de fuera de servicio dentro de cualquier período de 10 años."},"56":{"q":"En Carolina del Norte, ¿cuál es la descalificación para la PRIMERA infracción de cruce a nivel ferroviario-carretero de un titular de CDL cometida en un CMV?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"G.S. 20-17.4 y el NC CDL manual imponen una descalificación de no menos de 60 días por una primera infracción de cruce a nivel ferroviario-carretero en un CMV."},"57":{"q":"Un titular de CDL de Carolina del Norte comete una TERCERA infracción de cruce a nivel ferroviario-carretero dentro de un período de 3 años. ¿Cuál es la descalificación?","options":["60 días","120 días","Al menos 1 año","De por vida"],"explanation":"Bajo G.S. 20-17.4 y el NC CDL manual, las infracciones de cruce ferroviario conllevan 60 días (primera), 120 días (segunda dentro de 3 años) y no menos de 1 año (tercera dentro de 3 años)."},"58":{"q":"Cuando un titular de CDL de Carolina del Norte comete una infracción de tránsito en movimiento en un vehículo comercial por la que se asignan puntos, ¿cómo trata el tribunal la multa en comparación con un conductor no comercial?","options":["La multa se exime para los titulares de CDL","La multa puede duplicarse","La multa se reduce a la mitad","La multa es la misma que para cualquier conductor"],"explanation":"Según la ley de Carolina del Norte, el tribunal puede duplicar la multa para un operador de CMV que comete una infracción vehicular susceptible de asignación de puntos, lo que refleja el estándar más alto exigido a los conductores comerciales."},"59":{"q":"Cuando un conductor con CDL de Carolina del Norte se niega a una prueba química o registra 0.04 o más en un CMV durante una detención de consentimiento implícito, ¿qué acción previa al juicio se aplica típicamente de inmediato a la licencia del conductor antes de cualquier condena?","options":["Una retención administrativa de 10 días","Una revocación civil de 30 días","Una suspensión de 90 días","Ninguna acción hasta la condena"],"explanation":"La ley de consentimiento implícito de Carolina del Norte (G.S. 20-16.5) impone una revocación civil (previa al juicio) de 30 días de la licencia del conductor ante un resultado de prueba que califique o una negativa, separada de la descalificación del CDL que sigue a una condena."},"60":{"q":"En una autopista de acceso controlado de Carolina del Norte con seis o más carriles, ¿qué restricción aplica a un camión con una clasificación de peso bruto vehicular (GVWR) de 26,001 libras o más?","options":["No puede circular por el carril del extremo izquierdo, excepto al entrar o salir, al rebasar o al evitar un peligro","Siempre debe circular únicamente por el carril del extremo derecho","Puede usar cualquier carril mientras mantenga el ritmo del tráfico","Puede usar el carril del extremo izquierdo únicamente entre las 9 p.m. y las 6 a.m."],"explanation":"La ley G.S. 20-146 de Carolina del Norte prohíbe que un vehículo con una GVWR de 26,001 libras o más circule por el carril del extremo izquierdo de una autopista de acceso controlado con seis o más carriles, excepto al entrar o salir de la autopista, al rebasar o al evitar un peligro. Fuente: N.C. Gen. Stat. 20-146."},"61":{"q":"Según la ley de \"Move Over\" (Cambio de Carril) de Carolina del Norte, ¿qué debe hacer un conductor al acercarse a un vehículo de emergencia o de servicio público detenido que muestra luces de advertencia intermitentes en una vía de varios carriles?","options":["Cambiarse a un carril que no sea el más cercano al vehículo detenido, si se puede hacer de manera segura","Detenerse por completo en el carril actual hasta que el vehículo se retire","Tocar la bocina de forma continua mientras pasa","Pasar a no más de 5 mph por debajo del límite de velocidad indicado"],"explanation":"Según el N.C. Gen. Stat. 20-157, en una vía con dos o más carriles en el sentido de circulación, el conductor debe cambiarse a un carril que no sea el más cercano al vehículo de emergencia o de servicio público detenido cuando se pueda hacer de manera segura. En una vía de un solo carril, el conductor debe en cambio reducir la velocidad y estar preparado para detenerse. Fuente: N.C. Gen. Stat. 20-157."},"62":{"q":"Un conductor en Carolina del Norte de un vehículo con materiales peligrosos rotulado (con placard) se acerca a un cruce ferroviario a nivel. ¿Dónde debe detenerse el conductor?","options":["A menos de 50 pies, pero no más cerca de 15 pies, del riel más cercano","A menos de 25 pies, pero no más cerca de 5 pies, del riel más cercano","A menos de 100 pies, pero no más cerca de 50 pies, del riel más cercano","Exactamente a 10 pies del riel más cercano"],"explanation":"Los autobuses y los vehículos rotulados/con materiales peligrosos (hazmat) deben detenerse a menos de 50 pies, y no más cerca de 15 pies, del riel más cercano antes de cruzar, y luego mirar y escuchar. Esta norma federal (49 CFR 392.10) se enseña en el manual de CDL de Carolina del Norte y aplica en Carolina del Norte. Fuente: N.C. CDL Driver Handbook; 49 CFR 392.10."},"63":{"q":"En una vía de dos carriles de Carolina del Norte (un carril en cada sentido), un autobús escolar se detiene con las luces rojas intermitentes encendidas y el brazo de alto extendido para recoger niños. ¿Qué vehículos deben detenerse?","options":["El tráfico que se aproxima desde ambos sentidos debe detenerse","Solo el tráfico que va detrás del autobús debe detenerse","Solo el tráfico que viene en sentido contrario debe detenerse","Nadie debe detenerse si los conductores reducen a 20 mph"],"explanation":"Según el N.C. Gen. Stat. 20-217, en una vía de dos carriles todo vehículo que se aproxime al autobús escolar detenido desde cualquier sentido en la misma vía debe detenerse por completo y permanecer detenido hasta que se retire la señal de alto y el autobús se ponga en marcha. Fuente: N.C. Gen. Stat. 20-217(a)."},"64":{"q":"Según la ley de detención ante autobuses escolares de Carolina del Norte, ¿cuándo NO está obligado a detenerse el conductor de un vehículo que circula en sentido CONTRARIO al de un autobús escolar detenido?","options":["Cuando la vía está dividida en dos calzadas por un espacio intermedio o una barrera física (un carril central de giro cuenta solo si la vía tiene al menos cuatro carriles)","Siempre que la vía tenga una línea central pintada de cualquier tipo","Siempre que haya un carril en cada sentido","Siempre que el conductor en sentido contrario reduzca a 15 mph o menos"],"explanation":"El N.C. Gen. Stat. 20-217(c) exime al tráfico en sentido contrario solo cuando la vía está dividida en dos calzadas por un espacio intermedio (incluido un carril central para giros a la izquierda SI la calzada consta de al menos cuatro carriles más) o por una barrera física. Una simple línea central pintada en una vía no dividida no califica. Fuente: N.C. Gen. Stat. 20-217(c)."},"65":{"q":"¿Cuál es el límite de velocidad máximo que el North Carolina DOT puede establecer en una interestatal o autopista de acceso controlado?","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"Según el N.C. Gen. Stat. 20-141(b), un límite de velocidad establecido en el sistema de interestatales o de autopistas de acceso controlado no puede exceder las 70 millas por hora. Fuente: N.C. Gen. Stat. 20-141."},"66":{"q":"En una carretera de Carolina del Norte donde el límite de velocidad indicado se estableció de manera uniforme para todos los tipos de vehículos, ¿cómo se compara el límite de velocidad para camiones con el de los automóviles?","options":["Los camiones y los automóviles tienen el mismo límite de velocidad indicado","Los camiones están limitados a 10 mph por debajo del límite de los automóviles","Los camiones están limitados a 55 mph sin importar el límite indicado","Los camiones pueden circular 5 mph más rápido que los automóviles en las pendientes"],"explanation":"Carolina del Norte no establece un límite de velocidad para camiones independiente y más bajo a nivel estatal; el G.S. 20-141(l) hace que el límite indicado aplique de manera uniforme a todos los tipos de vehículos automotores. (Puede aplicarse un límite más bajo a un vehículo específico que circule bajo un permiso de sobredimensión/sobrepeso.) Fuente: N.C. Gen. Stat. 20-141(l)."},"67":{"q":"¿Por qué están prohibidos los camiones comerciales en la Blue Ridge Parkway de Carolina del Norte?","options":["Es una vía escénica de dos carriles, angosta y sinuosa, sin carriles para camiones ni rampas de escape","Es una vía privada de peaje abierta únicamente a automóviles de pasajeros","Cruza a otro estado sin estaciones de pesaje","Tiene puentes con restricción de peso cada milla"],"explanation":"Los vehículos comerciales están prohibidos en la Blue Ridge Parkway porque es una vía escénica del Servicio de Parques Nacionales de dos carriles, angosta, con pendientes variables, curvas, distancia de visibilidad limitada y sin carriles para camiones ni rampas de escape para camiones. Fuente: National Park Service / regulaciones de la Blue Ridge Parkway."},"68":{"q":"Un camión se avería en una carretera dividida de Carolina del Norte. ¿Dónde se deben colocar los tres dispositivos de advertencia de emergencia (triángulos reflectantes)?","options":["A 10 pies, 100 pies y 200 pies hacia atrás, todos en dirección al tráfico que se aproxima","A 10 pies, 50 pies y 150 pies, dos hacia atrás y uno hacia adelante","A 5 pies, 75 pies y 250 pies hacia atrás","A 25 pies, 100 pies y 300 pies hacia atrás"],"explanation":"En una vía de un solo sentido o dividida, los tres dispositivos de advertencia se colocan en dirección al tráfico que se aproxima a 10, 100 y 200 pies del vehículo detenido. (En una vía de doble sentido, uno se coloca a 10 pies hacia atrás, uno a 100 pies hacia atrás y uno a 100 pies hacia adelante.) Fuente: N.C. CDL Driver Handbook; 49 CFR 392.22."},"69":{"q":"La ley de \"Move Over\" (Cambio de Carril) de Carolina del Norte se extiende más allá de la policía, los bomberos y las ambulancias, ¿a qué categoría adicional de vehículos?","options":["Vehículos de servicios públicos, de mantenimiento de carreteras y de vehículos averiados/grúas que muestran luces ámbar intermitentes","Cualquier automóvil de pasajeros que use sus intermitentes de cuatro direcciones","Solo vehículos de reparto de correo","Solo vehículos de emergencia de otros estados"],"explanation":"El N.C. Gen. Stat. 20-157 también cubre los \"vehículos de servicio público\" que muestran luces ámbar intermitentes, incluidos los de servicios públicos (electricidad, gas, agua, comunicaciones), de mantenimiento de carreteras, de recolección de basura y de servicio de vehículos averiados/grúas. Los conductores deben cambiarse de carril o reducir la velocidad por ellos. Fuente: N.C. Gen. Stat. 20-157."},"70":{"q":"Después de detenerse en un cruce ferroviario, el conductor de un autobús o de un vehículo rotulado en Carolina del Norte, ¿qué debe hacer al cruzar?","options":["Cruzar en una marcha que no requiera cambiar de velocidad sobre los rieles","Cambiar a una marcha más baja a la mitad del cruce para ganar control","Detenerse de nuevo en el centro de los rieles para volver a revisar","Cruzar en punto muerto para ahorrar combustible"],"explanation":"El manual de CDL de Carolina del Norte indica a los conductores que seleccionen una marcha que les permita cruzar por completo sin cambiar de velocidad, y que nunca cambien de marcha mientras están sobre los rieles, para evitar que el motor se apague. Fuente: N.C. CDL Driver Handbook; 49 CFR 392.10/392.11."},"71":{"q":"¿Cuál es la multa mínima en Carolina del Norte por rebasar ilegalmente un autobús escolar detenido que está recogiendo o dejando niños?","options":["$500 y un delito menor de Clase 1 (Class 1 misdemeanor)","$100 y una infracción","$250 y un delito menor de Clase 3 (Class 3 misdemeanor)","$1,000 y un delito menor de Clase 2 (Class 2 misdemeanor)"],"explanation":"Según el N.C. Gen. Stat. 20-217(e), rebasar un autobús escolar detenido es un delito menor de Clase 1 que conlleva una multa mínima de $500, y no se permite ninguna suspensión del fallo (prayer for judgment continued). Atropellar a una persona lo eleva a un delito grave con multas mínimas más altas. Fuente: N.C. Gen. Stat. 20-217(e),(g)."},"72":{"q":"En la Triangle Expressway y otras instalaciones de peaje de la North Carolina Turnpike (como la I-540), ¿cómo se cobran los peajes?","options":["Peaje totalmente electrónico sin casetas de cobro, usando transpondedores NC Quick Pass o factura por correo","Casetas de cobro solo en efectivo en cada intercambiador","Una tarifa anual fija con calcomanía para todos los camiones","Los peajes se cobran únicamente en la frontera estatal"],"explanation":"Las vías de peaje de Carolina del Norte usan un sistema de peaje 100% totalmente electrónico sin casetas; los conductores pagan mediante un transpondedor/cuenta NC Quick Pass o reciben una factura por correo. A los camiones se les cobra más según el número de ejes. Fuente: NCDOT Turnpike Authority / NC Quick Pass."},"73":{"q":"¿Cuál es la multa estándar por una infracción básica de la ley de \"Move Over\" (Cambio de Carril) de Carolina del Norte (sin lesiones ni daños a la propiedad)?","options":["Infracción de $250","Infracción de $50","Delito menor de Clase 1 (Class 1 misdemeanor) de $500","Delito grave (felony) de $1,000"],"explanation":"Una infracción básica del N.C. Gen. Stat. 20-157 es una infracción sancionable con una multa de $250. Se eleva a un delito menor (misdemeanor) cuando hay daños a la propiedad superiores a $500 o lesiones, y a un delito grave de Clase F (Class F felony) si causa lesiones graves o la muerte. Fuente: N.C. Gen. Stat. 20-157."},"74":{"q":"Según la regla de mantenerse a la derecha de Carolina del Norte, ¿dónde debe circular normalmente un vehículo que viaja a una velocidad menor que la máxima legal?","options":["En el carril derecho disponible para el tráfico de paso, o lo más cerca posible del borde derecho","En el carril que esté menos congestionado","En el carril central de una vía de tres carriles","En el carril izquierdo para dejar libre el carril derecho para las incorporaciones"],"explanation":"El N.C. Gen. Stat. 20-146 exige que todo vehículo que circule a menos de la velocidad máxima legal transite por el carril derecho de paso, o lo más cerca posible del borde derecho, excepto al rebasar o prepararse para un giro a la izquierda. Fuente: N.C. Gen. Stat. 20-146."},"75":{"q":"Para efectos de la ley de detención ante autobuses escolares de Carolina del Norte, ¿cuál de estos se considera un \"autobús escolar\" que obliga al resto del tráfico a detenerse?","options":["Un autobús escolar público que transporta a personas mayores bajo el G.S. 115C-243 y rotulado como \"school bus\" al frente y atrás","Cualquier camioneta amarilla usada por una guardería, esté rotulada o no","Un autocar fletado (charter) con ventanas polarizadas","Cualquier vehículo con luces de freno rojas"],"explanation":"El N.C. Gen. Stat. 20-217(b) define un autobús escolar cubierto para incluir un autobús escolar público que transporta niños o personal, un autobús escolar público que transporta a personas mayores bajo el G.S. 115C-243, o un autobús de propiedad privada que transporta niños, pero solo cuando lleva letreros de \"school bus\" claramente visibles al frente y atrás. Fuente: N.C. Gen. Stat. 20-217(b)."},"76":{"q":"¿En qué cruce ferroviario de Carolina del Norte NO está obligado a detenerse un conductor con CDL, incluso transportando materiales peligrosos rotulados (hazmat)?","options":["Un cruce donde un oficial de policía o un señalero (flagger) dirige el tráfico para pasar","Cualquier cruce con cruces de San Andrés (crossbucks) pero sin barreras","Un cruce en una carretera rural de dos carriles","Un cruce con un límite de velocidad indicado superior a 45 mph"],"explanation":"Se exime la detención obligatoria en cruces controlados por un oficial de policía o un señalero (flagger), en vías de tranvía/de maniobras industriales en un distrito comercial, en cruces marcados como \"Exempt\" (Exento) o \"Abandoned\" (Abandonado), y donde un semáforo de tráfico vial en funcionamiento muestra verde. Fuente: N.C. CDL Driver Handbook; 49 CFR 392.10(b)."},"77":{"q":"Un autobús escolar se detiene en una vía de Carolina del Norte que tiene dos carriles de circulación en cada sentido separados únicamente por un carril central continuo de giro a la izquierda de doble sentido (una vía de cinco carriles). ¿Debe detenerse el tráfico en sentido contrario?","options":["No, porque un carril central de giro a la izquierda califica como espacio divisorio cuando la vía tiene al menos cuatro carriles","Sí, porque un carril de giro no es una barrera física","Sí, todas las vías requieren que el tráfico en sentido contrario se detenga","No, el tráfico en sentido contrario nunca tiene que detenerse en ninguna vía de varios carriles"],"explanation":"El G.S. 20-217(c) permite que el tráfico en sentido contrario continúe cuando la vía está dividida por un espacio intermedio, e incluye específicamente un carril central para giros a la izquierda SI la calzada consta de al menos cuatro carriles. Una vía de cinco carriles con un carril central de giro cumple ese criterio, por lo que el tráfico en sentido contrario no necesita detenerse. Fuente: N.C. Gen. Stat. 20-217(c)."},"78":{"q":"Un conductor es condenado por segunda vez en un plazo de tres años por rebasar un autobús escolar detenido en Carolina del Norte. ¿Cuál es la consecuencia para la licencia, además de la multa?","options":["Revocación de la licencia de conducir por un año","Solo una suspensión de 30 días","Ninguna acción sobre la licencia, solo puntos","Revocación permanente en la segunda infracción"],"explanation":"Según el N.C. Gen. Stat. 20-217(g1), una segunda condena por delito menor (misdemeanor) bajo esta sección dentro de un período de tres años resulta en una revocación de la licencia por un año; el titular de un CDL también queda descalificado para conducir un vehículo comercial durante ese período. Fuente: N.C. Gen. Stat. 20-217(g1)."},"79":{"q":"¿En qué circunstancia puede Carolina del Norte establecer un límite de velocidad indicado más bajo para un vehículo comercial en particular?","options":["Cuando el vehículo circula bajo un permiso especial de sobredimensión/sobrepeso debido a su peso o sus dimensiones","Siempre que el vehículo tenga más de dos ejes","Siempre que el vehículo esté registrado fuera del estado","Siempre que el remolque mida más de 40 pies de largo"],"explanation":"El N.C. Gen. Stat. 20-141(l) permite establecer un límite de velocidad más bajo para un vehículo que circula bajo un permiso especial debido a cualquier peso o dimensión del vehículo o su carga. De lo contrario, el límite indicado es uniforme para todos los tipos de vehículos. Fuente: N.C. Gen. Stat. 20-141(l); reglas de permisos de sobredimensión/sobrepeso de NCDOT."},"80":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Carolina del Norte?","options":["La Federal Motor Carrier Safety Administration (FMCSA)","El North Carolina Department of Public Safety","El North Carolina Department of Transportation Highway Patrol","La North Carolina Division of Motor Vehicles (NCDMV)"],"explanation":"En Carolina del Norte, las CDL son emitidas y administradas por la North Carolina Division of Motor Vehicles (NCDMV), una división de NCDOT. La FMCSA establece las normas federales pero no emite las licencias. Fuente: página de Commercial Driver License de NCDMV y N.C. CDL Manual, Sección 1."},"81":{"q":"Para obtener una CDL o un permiso de aprendizaje comercial de Carolina del Norte, ¿qué dos tipos de exámenes debe aprobar un solicitante?","options":["Un examen escrito y un examen de peso del vehículo","Exámenes de conocimientos y exámenes de habilidades","Un examen de agilidad física y un examen de endoso","Un examen de manejo del empleador y un examen federal"],"explanation":"El N.C. CDL Manual (Sección 1.1) indica que para obtener una CDL o CLP debe aprobar exámenes de conocimientos y exámenes de habilidades. El examen de habilidades se realiza en la clase de vehículo para la que desea obtener la licencia. Fuente: N.C. CDL Manual, Sección 1.1."},"82":{"q":"El examen de habilidades de CDL de Carolina del Norte consta de ¿cuáles tres partes?","options":["Conocimientos escritos, examen de la vista y un examen de manejo","Revisión de frenos de aire, examen de acoplamiento y un examen en carretera","Inspección del vehículo (pre-viaje), control básico del vehículo y manejo en carretera","Retroceso, estacionamiento en paralelo y un examen de manejo nocturno"],"explanation":"Según el N.C. CDL Manual (Sección 1.1.2), el examen de habilidades tiene tres partes: el examen de inspección del vehículo (pre-viaje), el examen de control básico del vehículo y el examen de manejo en carretera. Las tres deben aprobarse en la clase de vehículo correspondiente. Fuente: N.C. CDL Manual, Sección 1.1.2."},"83":{"q":"¿Qué examen de conocimientos debe presentar TODO solicitante de CDL en Carolina del Norte, sin importar la clase o los endosos?","options":["El examen de conocimientos generales","El examen de vehículos combinados","El examen de frenos de aire","El examen de materiales peligrosos"],"explanation":"El N.C. CDL Manual (Sección 1.1.1) indica que el examen de conocimientos generales lo presentan todos los solicitantes. Los demás exámenes (vehículos combinados, frenos de aire, hazmat, etc.) aplican solo a clases o endosos específicos. Fuente: N.C. CDL Manual, Sección 1.1.1."},"84":{"q":"¿Cuál es la puntuación mínima para aprobar cada examen de conocimientos de CDL de Carolina del Norte?","options":["70% correcto","80% correcto","75% correcto","85% correcto"],"explanation":"Carolina del Norte exige al menos 80% correcto en cada examen de conocimientos de CDL (por ejemplo, 40 de 50 en el examen de conocimientos generales, 16 de 20 en vehículos combinados o frenos de aire), calificados por separado. Fuente: normas de exámenes de conocimientos de CDL de NCDMV (mínimo de la FMCSA adoptado por N.C.)."},"85":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendizaje Comercial (CLP) de Carolina del Norte?","options":["30 días, sin renovación permitida","180 días, con una renovación por 180 días adicionales","1 año, con renovaciones ilimitadas","60 días, renovable una vez por 60 días"],"explanation":"Un CLP de Carolina del Norte es válido por 180 días y puede renovarse una vez por 180 días adicionales sin volver a presentar el examen de conocimientos generales. Fuente: página de Commercial Driver License de NCDMV; N.C. CDL Manual (CLP), en concordancia con 49 CFR 383.25."},"86":{"q":"Después de que se emite un CLP de Carolina del Norte, ¿cuánto tiempo debe esperar un solicitante antes de presentar el examen de habilidades de CDL?","options":["Al menos 30 días","Al menos 7 días","Al menos 60 días","Al menos 14 días"],"explanation":"El titular de un CLP debe esperar al menos 14 días después de que se emite el CLP antes de presentar el examen de habilidades de CDL. Esta regla federal (49 CFR 383.25) es aplicada por NCDMV. Fuente: página de Commercial Driver License de NCDMV; 49 CFR 383.25."},"87":{"q":"Antes de que un solicitante de Clase A o Clase B por primera vez en Carolina del Norte pueda presentar el examen de habilidades de CDL, ¿qué capacitación federal debe completar?","options":["Un curso de manejo defensivo administrado por el estado en una oficina de NCDMV","120 horas de tiempo al volante registradas con cualquier titular de CDL con licencia","Capacitación de Conductor de Nivel Básico (ELDT) de un proveedor del FMCSA Training Provider Registry","Una certificación de seguridad laboral de OSHA"],"explanation":"La Capacitación de Conductor de Nivel Básico (ELDT) federal debe completarse a través de un proveedor que figure en el FMCSA Training Provider Registry antes de presentar el examen para una CDL de Clase A/B por primera vez (y para los endosos P, S y H o una actualización de B a A). Fuente: página de CDL de NCDMV; regla ELDT de la FMCSA (49 CFR Part 380)."},"88":{"q":"Además de los solicitantes de Clase A y Clase B por primera vez, la ELDT también se requiere antes de presentar el examen para ¿cuáles endosos?","options":["Cisterna (N), Dobles/Triples (T) y Frenos de Aire","Vehículos combinados, Frenos de Aire y Cisterna (N)","Pasajeros (P), Autobús Escolar (S) y Materiales Peligrosos (H)","Solo Materiales Peligrosos (H)"],"explanation":"La ELDT aplica antes de la emisión de una Clase A/B por primera vez, una actualización de B a A, y los endosos de Pasajeros (P), Autobús Escolar (S) y Materiales Peligrosos (H). El endoso H requiere la ELDT solo teórica. Fuente: página de CDL de NCDMV; regla ELDT de la FMCSA (49 CFR Part 380)."},"89":{"q":"Los solicitantes de CDL en Carolina del Norte deben autocertificar su tipo de conducción comercial. ¿Cuántas categorías de autocertificación existen?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Hay cuatro categorías de autocertificación: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado e intraestatal exceptuado. El solicitante marca la casilla que corresponde a su operación. Fuente: N.C. CDL Manual, Sección 1.2.3."},"90":{"q":"¿Qué categoría de autocertificación de Carolina del Norte exige que el conductor presente y mantenga un certificado de examinador médico federal del DOT?","options":["Interestatal exceptuado","Interestatal no exceptuado","Intraestatal exceptuado","Pasajero privado exceptuado"],"explanation":"Un conductor interestatal no exceptuado certifica que está sujeto a los requisitos médicos federales del DOT bajo el 49 CFR Part 391 y que los cumple, y debe obtener un certificado de examinador médico. La mayoría de los titulares de CDL interestatales son no exceptuados. Fuente: N.C. CDL Manual, Sección 1.2.3."},"91":{"q":"Un conductor de Carolina del Norte que opera únicamente en comercio interestatal pero exclusivamente en operaciones exceptuadas del 49 CFR Part 391 debe autocertificarse como:","options":["Interestatal no exceptuado","Intraestatal no exceptuado","Interestatal exceptuado","Intraestatal exceptuado"],"explanation":"Un conductor interestatal exceptuado certifica que opera en comercio interestatal pero participa exclusivamente en operaciones exceptuadas bajo el 49 CFR 390.3(f), 391.2, 391.68 o 398.3, y NO está obligado a obtener un certificado de examinador médico. Fuente: N.C. CDL Manual, Sección 1.2.3."},"92":{"q":"Según las reglas de Carolina del Norte, si un conductor opera tanto en comercio interestatal como intraestatal, ¿qué categoría debe elegir?","options":["Comercio intraestatal","Comercio interestatal (la categoría más exigente)","La que conduzca con más frecuencia","Puede elegir cualquiera libremente"],"explanation":"El N.C. CDL Manual (Sección 1.2.1) indica que un conductor que opera tanto en comercio interestatal como intraestatal debe elegir comercio interestatal, porque conlleva los requisitos de calificación más estrictos. Fuente: N.C. CDL Manual, Sección 1.2.1."},"93":{"q":"Bajo el proceso del National Registry de la FMCSA que ahora usa Carolina del Norte, ¿cómo llega normalmente a NCDMV el certificado de examinador médico del DOT de un conductor no exceptuado?","options":["El conductor debe enviar por correo una copia impresa directamente a NCDMV cada dos años","El empleador envía por fax la tarjeta médica a la sede de NCDMV","El médico del conductor llama a la unidad médica de NCDMV para reportar los resultados","El examinador médico certificado envía los resultados del examen electrónicamente al National Registry de la FMCSA, que los transmite a NCDMV"],"explanation":"Bajo el proceso del National Registry / NRII de la FMCSA (cumplimiento en 2025), los examinadores médicos certificados envían electrónicamente los resultados del examen de CDL/CLP al National Registry, y la FMCSA transmite el estado de la certificación médica al estado (NCDMV). Los conductores ya no necesitan entregar la tarjeta impresa a NCDMV. Fuente: regla del National Registry de la FMCSA; guía de certificación médica de NCDMV."},"94":{"q":"La autocertificación de la categoría de comercio de un conductor en Carolina del Norte se requiere ¿en cuáles de estos momentos?","options":["Solo una vez, cuando se emite la CDL original por primera vez","Solo cuando el conductor cambia de empleador","Al solicitar un CLP, y al renovar, actualizar, agregar endosos o transferir una CDL","Solo cuando el conductor cumple 65 años"],"explanation":"Los conductores deben proporcionar información de autocertificación al estado al solicitar un CLP, y al renovar, actualizar, agregar endosos o transferir una CDL. Fuente: N.C. CDL Manual, Sección 1.2 (requisitos federales de certificación médica)."},"95":{"q":"¿Cuál es el período de validez estándar de una CDL de Carolina del Norte (para una licencia renovada, para un conductor menor de 65 años)?","options":["5 años","4 años","8 años","10 años"],"explanation":"Según el N.C.G.S. 20-7, una licencia de conducir comercial renovada vence cinco años después de la fecha de vencimiento de la licencia que se está renovando. Las CDL no pueden renovarse en línea y deben renovarse en persona en una oficina de NCDMV. Fuente: N.C.G.S. 20-7; página de renovación de licencias de NCDMV."},"96":{"q":"¿En qué se diferencia la renovación de una CDL de Carolina del Norte de la renovación de una licencia estándar (Clase C)?","options":["Una CDL puede renovarse en línea hasta dos años después de su vencimiento","Una CDL se renueva automáticamente por el transportista del empleador","Una CDL nunca vence una vez que el conductor aprueba el examen de manejo","Una CDL debe renovarse en persona en una oficina de licencias de conducir de NCDMV; no puede renovarse en línea ni por correo"],"explanation":"Las CDL de Carolina del Norte deben renovarse en persona en una oficina de licencias de conducir de NCDMV y no pueden renovarse en línea ni por correo, a diferencia de muchas licencias estándar. Fuente: página de renovación/reposición de licencias de NCDMV; N.C.G.S. 20-7."},"97":{"q":"Al solicitar un CLP de Carolina del Norte, ¿cuál de los siguientes documentos se requiere como parte de la solicitud?","options":["Prueba de identidad/edad, número de Seguro Social, residencia y prueba de seguro de responsabilidad civil","Un diploma de preparatoria y una carta notariada del empleador","Solo un pasaporte, sin ningún otro documento","Prueba de propiedad del vehículo y un título del vehículo"],"explanation":"NCDMV exige que un solicitante de CLP presente prueba de identidad y edad, prueba del número de Seguro Social, dos documentos de residencia (prueba de presencia legal para no ciudadanos) y prueba de seguro de responsabilidad civil de un proveedor con licencia en Carolina del Norte. Fuente: página de Commercial Driver License de NCDMV."},"98":{"q":"En Carolina del Norte, ¿cuántos intentos de un solo examen de conocimientos de CDL se permiten en un día?","options":["Un intento por examen por día","Tres intentos por examen por día","Intentos ilimitados en un día","Dos intentos por examen por día"],"explanation":"El N.C. CDL Manual indica que solo se permite un intento de cada examen de conocimientos por día. Después de tres intentos fallidos del examen de conocimientos generales, se requiere otra cuota de solicitud para los siguientes tres intentos. Fuente: N.C. CDL Manual, Sección 1.1."},"99":{"q":"Una vez aprobados, ¿por cuánto tiempo son válidas las puntuaciones de los exámenes de CDL de Carolina del Norte en los archivos computarizados de NCDMV?","options":["30 días desde la fecha del examen","180 días desde la fecha del examen","1 año desde la fecha del examen","90 días desde la fecha del examen"],"explanation":"El N.C. CDL Manual señala que todas las puntuaciones de los exámenes son válidas por 90 días desde la fecha del examen en los archivos computarizados de NCDMV. Un solicitante debe completar los requisitos restantes dentro de ese plazo. Fuente: N.C. CDL Manual, Sección 1.1."}},"hi":{"0":{"q":"नॉर्थ कैरोलाइना के राजमार्गों पर, ओवरसाइज़ परमिट के बिना किसी वाणिज्यिक वाहन या उसके भार की अधिकतम वैध चौड़ाई कितनी होती है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"नॉर्थ कैरोलाइना सभी सड़कों पर किसी वाहन या उसके भार की कुल बाहरी चौड़ाई को 102 inches (8 feet 6 inches) तक सीमित करता है; इससे अधिक चौड़ी किसी भी चीज़ के लिए परमिट आवश्यक है। स्रोत: N.C. Gen. Stat. 20-116(a) और NCDOT Oversize/Overweight Permit Handbook।"},"1":{"q":"नॉर्थ कैरोलाइना के राजमार्गों पर परमिट के बिना वाहन की अधिकतम वैध ऊँचाई कितनी होती है?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"नॉर्थ कैरोलाइना का कानून वाहन की अधिकतम ऊँचाई, चाहे वह खाली हो या भार के साथ, 14 feet निर्धारित करता है। स्रोत: N.C. Gen. Stat. 20-116(c) और NCDOT Oversize/Overweight Permit Handbook।"},"2":{"q":"नॉर्थ कैरोलाइना में, एक सिंगल एक्सल पर अनुमत अधिकतम सकल भार कितना होता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"नॉर्थ कैरोलाइना सिंगल-एक्सल भार को 20,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। स्रोत: N.C. Gen. Stat. 20-118(b)(1) और NCDOT Oversize/Overweight Permit Handbook।"},"3":{"q":"नॉर्थ कैरोलाइना में, एक टैंडम एक्सल पर अनुमत अधिकतम सकल भार कितना होता है?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"नॉर्थ कैरोलाइना टैंडम-एक्सल का अधिकतम भार 38,000 pounds निर्धारित करता है (संघीय सीमा 34,000 है; नॉर्थ कैरोलाइना का वैधानिक आँकड़ा 38,000 है)। स्रोत: N.C. Gen. Stat. 20-118(b)(2) और NCDOT Oversize/Overweight Permit Handbook।"},"4":{"q":"नॉर्थ कैरोलाइना में परमिट के बिना एक एकल वाहन (दो या अधिक एक्सल वाले) की अधिकतम कुल लंबाई कितनी होती है?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"दो या अधिक एक्सल वाला एक एकल वाहन कुल मिलाकर 40 feet से अधिक नहीं हो सकता, जिसमें आगे और पीछे के बम्पर शामिल हैं। स्रोत: N.C. Gen. Stat. 20-116(d)(1) और NCDOT Oversize/Overweight Permit Handbook।"},"5":{"q":"नॉर्थ कैरोलाइना में एक साथ जुड़े दो वाहनों के संयोजन के लिए सामान्य अधिकतम लंबाई कितनी होती है?","options":["55 feet","60 feet","65 feet","75 feet"],"explanation":"अन्यथा प्रावधानित को छोड़कर, दो वाहनों का कोई भी संयोजन आगे और पीछे के बम्पर सहित कुल 60 feet से अधिक लंबाई का नहीं हो सकता। स्रोत: N.C. Gen. Stat. 20-116(e) और NCDOT Oversize/Overweight Permit Handbook।"},"6":{"q":"नॉर्थ कैरोलाइना में, एक एकल सेमीट्रेलर खींचने वाला ट्रक-ट्रैक्टर 60-foot संयोजन लंबाई सीमा से तब तक छूट प्राप्त रहता है जब तक सेमीट्रेलर किस लंबाई से अधिक न हो?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"एक ट्रक-ट्रैक्टर (पावर यूनिट) जो 53 feet से अधिक का न होने वाला एक सेमीट्रेलर खींच रहा हो, नॉर्थ कैरोलाइना की सभी सड़कों पर 60-foot की कुल अधिकतम सीमा से अधिक हो सकता है। स्रोत: N.C. Gen. Stat. 20-116(e) और NCDOT Oversize/Overweight Permit Handbook।"},"7":{"q":"ओवरवेट परमिट के बिना नॉर्थ कैरोलाइना के राजमार्गों पर एक सामान्य पाँच-एक्सल ट्रैक्टर-सेमीट्रेलर के लिए अधिकतम सकल वाहन भार कितना होता है?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"नॉर्थ कैरोलाइना का अधिकतम सकल वाहन भार 80,000 pounds है, जो एक्सल और ब्रिज-फॉर्मूला सीमाओं के अधीन है। स्रोत: N.C. Gen. Stat. 20-118 और NCDOT Oversize/Overweight Permit Handbook।"},"8":{"q":"नॉर्थ कैरोलाइना अपने राजमार्गों पर एक्सल अंतराल के आधार पर अनुमेय सकल भार कैसे निर्धारित करता है?","options":["काउंटी द्वारा निर्धारित एक समान प्रति-एक्सल गुणक द्वारा","चरम एक्सल माप पर आधारित संघीय ब्रिज फॉर्मूला द्वारा","केवल वाहन के निर्माता GVWR द्वारा","सड़क को छूने वाले टायरों की संख्या द्वारा"],"explanation":"सकल भार संघीय ब्रिज फॉर्मूला (ब्रिज कानून) के तहत चरम एक्सल माप द्वारा निर्धारित किया जाता है। 23 U.S.C. 127 की छूट सभी राज्य सड़कों पर लागू होती है जब तक कि साइन-बोर्ड न लगा हो। स्रोत: N.C. Gen. Stat. 20-118(c)(19) और NCDOT Oversize/Overweight Permit Handbook।"},"9":{"q":"नॉर्थ कैरोलाइना की कौन-सी एजेंसी वैध आकार या भार सीमाओं से अधिक वाले वाहनों के लिए ओवरसाइज़/ओवरवेट परमिट जारी करती है?","options":["N.C. Division of Motor Vehicles (DMV)","N.C. Department of Transportation (NCDOT) Oversize/Overweight Permit Unit","N.C. State Highway Patrol","वह काउंटी शेरिफ का कार्यालय जहाँ से यात्रा शुरू होती है"],"explanation":"ओवरसाइज़/ओवरवेट परमिट NCDOT Oversize/Overweight Permit Unit (Garner, NC में Central Permit Office) द्वारा जारी किए जाते हैं। स्रोत: NCDOT Oversize/Overweight Permit Handbook।"},"10":{"q":"नॉर्थ कैरोलाइना का एकल-यात्रा ओवरसाइज़/ओवरवेट परमिट कितने समय के लिए वैध होता है?","options":["एक यात्रा के लिए 5 calendar days","एक एकल यात्रा के लिए 10 calendar days","एक यात्रा के लिए 30 calendar days","प्रभावी तिथि से एक वर्ष"],"explanation":"एकल-यात्रा परमिट एक एकल यात्रा के लिए 10 calendar days तक वैध होता है; राज्य शुल्क $12 से $48 तक होता है। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit)।"},"11":{"q":"नॉर्थ कैरोलाइना के एकल-यात्रा परमिट के तहत, एक टैंडम एक्सल समूह पर अनुमत अधिकतम भार (एक्सल भार, सकल नहीं) कितना होता है?","options":["44,000 pounds","46,000 pounds","50,000 pounds","60,000 pounds"],"explanation":"एकल-यात्रा परमिट पर, अनुमेय एक्सल भार इस प्रकार हैं: स्टीयर 20,000; सिंगल 25,000; टैंडम 50,000; ट्राइडेम 60,000; और चार-या-अधिक-एक्सल समूह 68,000 pounds। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Single Trip Permit axle weights)।"},"12":{"q":"एक वस्तु के लिए 90,000 pounds तक की आवाजाही की अनुमति देने वाले नॉर्थ कैरोलाइना ओवरवेट परमिट के लिए पात्र होने हेतु, वाहन में आमतौर पर कम से कम कितना व्हीलबेस होना चाहिए?","options":["41-foot wheelbase","48-foot wheelbase","51-foot wheelbase","57-foot wheelbase"],"explanation":"न्यूनतम 51-foot व्हीलबेस वाला एक वाहन संयोजन 90,000 pounds तक की आवाजाही के लिए पात्र हो सकता है; 90,000 pounds से अधिक होने पर परमिट मार्ग-विशिष्ट होता है। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Annual Permit / Overweight)।"},"13":{"q":"नॉर्थ कैरोलाइना में, किस सकल भार से अधिक के भार को 'सुपरलोड' के रूप में वर्गीकृत किया जाता है, जिसके लिए लिखित सुपरलोड आवेदन और ब्रिज इंजीनियरिंग समीक्षा आवश्यक होती है?","options":["सकल भार 90,000 pounds से अधिक हो","सकल भार 112,000 pounds से अधिक हो","सकल भार 122,000 pounds से अधिक हो","सकल भार 132,000 pounds से अधिक हो"],"explanation":"सुपरलोड परमिट तब आवश्यक होता है जब सकल भार 132,000 pounds से अधिक हो (या स्टीयर-एक्सल भार 20,000 pounds से अधिक हो, या चौड़ाई 16 feet से अधिक हो)। इसमें $100 गैर-वापसी योग्य आवेदन शुल्क के साथ अतिरिक्त शुल्क लगता है। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Superload Permit)।"},"14":{"q":"जब नॉर्थ कैरोलाइना के एक परमिट प्राप्त भार में 4 feet से अधिक का पिछला ओवरहैंग हो, तो दिन के समय यात्रा के लिए क्या प्रदर्शित किया जाना चाहिए?","options":["पीछे एक एम्बर फ्लैशिंग लाइट","एक 18-inch-square लाल झंडा","एक 'WIDE LOAD' बैनर","एक लाल त्रिकोण रिफ्लेक्टर"],"explanation":"4 feet से अधिक के पिछले ओवरहैंग के लिए दिन के समय यात्रा हेतु एक 18-inch-square लाल झंडा और रात में क्लीयरेंस लाइट प्रदर्शित की जानी चाहिए; भार वाहन के पीछे से 14 feet से अधिक आगे नहीं बढ़ सकता, और अधिकतम ओवरहैंग 14 feet है। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Overhang)।"},"15":{"q":"नॉर्थ कैरोलाइना के परमिट पर, अधिक-चौड़ाई वाले भार के सबसे चौड़े बिंदु को चिह्नित करने वाले चेतावनी झंडे किस आकार और रंग के होने चाहिए?","options":["12 inches square, पीला","16 inches square, केवल नारंगी","18 inches square, लाल या नारंगी","24 inches square, केवल लाल"],"explanation":"झंडे 18 inches square, लाल या नारंगी रंग के होने चाहिए, जो अधिक-चौड़ाई के सबसे चौड़े बिंदु पर या परमिट में निर्दिष्ट अनुसार लगाए जाएँ। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Flags)।"},"16":{"q":"नॉर्थ कैरोलाइना के दो-लेन, दो-दिशा वाले राजमार्ग पर, जब परमिट प्राप्त भार की चौड़ाई किस सीमा से अधिक हो जाती है तो आमतौर पर एक फ्रंट एस्कॉर्ट वाहन आवश्यक होता है?","options":["10 feet चौड़ा","12 feet चौड़ा","14 feet चौड़ा","16 feet चौड़ा"],"explanation":"दो-लेन, दो-दिशा वाले राजमार्गों पर 12 feet से अधिक चौड़े परमिट प्राप्त भार के लिए एक फ्रंट एस्कॉर्ट आवश्यक है, और बहु-लेन राजमार्गों पर या परमिट में बताए अनुसार एक रियर एस्कॉर्ट आवश्यक है। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Escorts)।"},"17":{"q":"नॉर्थ कैरोलाइना के परमिट नियमों के तहत, किसी भी परमिट प्राप्त भार के लिए, जिसका भार किस सीमा से अधिक हो, एक फ्रंट एस्कॉर्ट आवश्यक होता है?","options":["80,000 pounds से अधिक","112,000 pounds से अधिक","132,000 pounds से अधिक","149,999 pounds से अधिक"],"explanation":"149,999 pounds से अधिक भार के लिए एक फ्रंट एस्कॉर्ट आवश्यक है; 150 feet या उससे अधिक की कुल लंबाई के लिए फ्रंट और रियर दोनों एस्कॉर्ट आवश्यक हैं। स्रोत: NCDOT Oversize/Overweight Permit Handbook (Escorts)।"},"18":{"q":"नॉर्थ कैरोलाइना का कानून कृषि और वन उत्पादों के लिए इंटरस्टेट से बाहर एक उच्च भार छूट प्रदान करता है। इस छूट के तहत बढ़ी हुई सिंगल-एक्सल सीमा क्या है?","options":["20,000 pounds","21,500 pounds","22,000 pounds","26,000 pounds"],"explanation":"इंटरस्टेट प्रणाली से बाहर ढोए गए पात्र कृषि और वन उत्पादों के लिए, नॉर्थ कैरोलाइना सिंगल एक्सल पर 22,000 pounds तक, टैंडम एक्सल पर 42,000 pounds तक, और सकल 90,000 pounds तक की अनुमति देता है। स्रोत: N.C. Gen. Stat. 20-118(c)(12)।"},"19":{"q":"नॉर्थ कैरोलाइना का 10 प्रतिशत भार सहनशीलता भत्ता किन सीमाओं पर लागू होता है?","options":["सिंगल-एक्सल और टैंडम-एक्सल सीमाओं पर","80,000-pound सकल सीमा और इंटरस्टेट एक्सल सीमाओं पर","केवल एक्सल-समूह भार पर, सिंगल/टैंडम एक्सल, 80,000-pound सकल सीमा, साइन-बोर्ड वाले पुलों, और इंटरस्टेट को छोड़कर","राज्यभर में सभी साइन-बोर्ड वाली पुल भार सीमाओं पर"],"explanation":"10 प्रतिशत सहनशीलता केवल एक्सल-समूह (ब्रिज-फॉर्मूला) भार पर लागू होती है; यह सिंगल-एक्सल या टैंडम-एक्सल सीमाओं, 80,000-pound सकल अधिकतम, साइन-बोर्ड वाले पुलों, या इंटरस्टेट राजमार्गों पर लागू नहीं होती। स्रोत: N.C. Gen. Stat. 20-118(h)।"},"20":{"q":"नॉर्थ कैरोलाइना में, 26,001 pounds या उससे अधिक के सकल वाहन भार रेटिंग (GVWR) वाले वाहनों के संयोजन को चलाने के लिए कौन-सी CDL श्रेणी आवश्यक है, बशर्ते खींचे जा रहे वाहन का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"नॉर्थ कैरोलाइना संघीय वर्गीकरण का पालन करता है: 26,001 lbs या उससे अधिक GVWR वाले वाहनों के किसी भी संयोजन के लिए, जहाँ खींची गई इकाई(याँ) 10,000 lbs GVWR से अधिक हों, एक Class A CDL आवश्यक है। स्रोत: NCDMV Commercial Driver License पेज और N.C. Commercial Driver License Manual।"},"21":{"q":"नॉर्थ कैरोलाइना के नियमों के तहत, 26,001 pounds या उससे अधिक GVWR वाले एक एकल वाहन को, जो 10,000 pounds GVWR से अधिक न होने वाली एक इकाई खींच रहा हो, किस CDL श्रेणी की आवश्यकता होती है?","options":["Class A","Class B","Class C","Class E"],"explanation":"एक Class B CDL में 26,001 lbs GVWR या उससे अधिक रेटिंग वाला एक एकल वाहन, साथ ही 10,000 lbs GVWR से अधिक न होने वाला कोई भी खींचा गया वाहन शामिल होता है। स्रोत: NCDMV Commercial Driver License पेज और N.C. CDL Manual।"},"22":{"q":"नॉर्थ कैरोलाइना की कौन-सी CDL श्रेणी ऐसे वाहन पर लागू होती है जो Class A या B के भार मानदंडों को पूरा नहीं करता है लेकिन 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या प्लेकार्ड वाली खतरनाक सामग्री ले जाता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"नॉर्थ कैरोलाइना में Class A या B को पूरा न करने वाले उन वाहनों के लिए एक Class C CDL आवश्यक है जो 16 या अधिक लोगों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए हैं या जो प्लेकार्ड वाली खतरनाक सामग्री ले जाते हैं। स्रोत: NCDMV Commercial Driver License पेज और N.C. CDL Manual।"},"23":{"q":"नॉर्थ कैरोलाइना में, केवल इंट्रास्टेट (राज्य के भीतर) वाणिज्यिक ड्राइविंग तक सीमित CDL प्राप्त करने के लिए न्यूनतम आयु कितनी होती है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"नॉर्थ कैरोलाइना केवल इंट्रास्टेट संचालन के लिए 18 वर्ष की आयु में CDL की अनुमति देता है। इंटरस्टेट वाणिज्य के लिए या खतरनाक सामग्री ले जाने के लिए चालकों की आयु 21 वर्ष होनी चाहिए। स्रोत: NCDMV Commercial Driver License आवश्यकताएँ; N.C.G.S. Chapter 20, Article 2C।"},"24":{"q":"नॉर्थ कैरोलाइना के एक चालक को इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन चलाने या खतरनाक सामग्री एंडोर्समेंट रखने के लिए कम से कम कितनी आयु का होना चाहिए?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"नॉर्थ कैरोलाइना इंटरस्टेट वाणिज्यिक ड्राइविंग और खतरनाक सामग्री (H) एंडोर्समेंट के लिए न्यूनतम 21 वर्ष की आयु अनिवार्य करता है; केवल इंट्रास्टेट संचालन के लिए न्यूनतम आयु 18 वर्ष है। स्रोत: NCDMV Commercial Driver License आवश्यकताएँ; N.C.G.S. Chapter 20, Article 2C।"},"25":{"q":"प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री ले जाने के लिए नॉर्थ कैरोलाइना के एक CDL धारक को किस एंडोर्समेंट की आवश्यकता होती है?","options":["N endorsement","H endorsement","T endorsement","P endorsement"],"explanation":"प्लेकार्ड योग्य मात्रा में खतरनाक सामग्री ढोने के लिए H (Hazardous Materials) एंडोर्समेंट आवश्यक है। इसके लिए एक नॉलेज टेस्ट के साथ-साथ एक TSA सुरक्षा खतरा मूल्यांकन की आवश्यकता होती है। स्रोत: NCDMV CDL endorsements; 49 CFR 383.93।"},"26":{"q":"नॉर्थ कैरोलाइना में, कम से कम 1,000 gallons क्षमता वाले टैंक में तरल या गैसीय भार ले जाने के लिए डिज़ाइन किए गए टैंक वाहन को चलाने के लिए कौन-सा एंडोर्समेंट आवश्यक है?","options":["H endorsement","T endorsement","N endorsement","X endorsement"],"explanation":"1,000 gallons या उससे अधिक की व्यक्तिगत रेटेड क्षमता वाले तरल या गैस ले जाने वाले टैंक वाहनों के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। स्रोत: NCDMV CDL endorsements; N.C. CDL Manual; 49 CFR 383.5/383.93।"},"27":{"q":"एक नॉर्थ कैरोलाइना CDL चालक जो डबल या ट्रिपल ट्रेलर संयोजन खींचता है, उसके पास कौन-सा एंडोर्समेंट होना चाहिए?","options":["T endorsement","N endorsement","P endorsement","S endorsement"],"explanation":"T एंडोर्समेंट डबल और ट्रिपल ट्रेलर संयोजनों के संचालन को अधिकृत करता है। इसे एक नॉलेज टेस्ट पास करके प्राप्त किया जाता है; किसी अलग स्किल्स टेस्ट की आवश्यकता नहीं होती। स्रोत: NCDMV CDL endorsements; N.C. CDL Manual।"},"28":{"q":"जब एक चालक को टैंक वाहन चलाने के लिए अधिकृत किया जाता है जो खतरनाक सामग्री भी ले जा रहा हो, तो नॉर्थ कैरोलाइना CDL पर कौन-सा संयुक्त एंडोर्समेंट दिखाई देता है?","options":["HT endorsement","X endorsement","NP endorsement","Z endorsement"],"explanation":"नॉर्थ कैरोलाइना एक ही CDL पर टैंक (N) और खतरनाक सामग्री (H) एंडोर्समेंट के संयोजन को दर्शाने के लिए X एंडोर्समेंट जारी करता है। स्रोत: NCDMV CDL endorsements/restrictions।"},"29":{"q":"नॉर्थ कैरोलाइना में, किन CDL एंडोर्समेंट के लिए एक बिहाइंड-द-व्हील स्किल्स (SKILLS) टेस्ट पास करना आवश्यक है (केवल एक नॉलेज टेस्ट नहीं)?","options":["H और N","N और T","P और S","H और T"],"explanation":"Passenger (P) और School Bus (S) एंडोर्समेंट के लिए उपयुक्त वाहन में एक स्किल्स/रोड टेस्ट आवश्यक है, जबकि H, N, और T केवल नॉलेज टेस्ट से प्राप्त किए जाते हैं। स्रोत: NCDMV CDL endorsements; N.C. CDL Manual।"},"30":{"q":"इससे पहले कि एक नॉर्थ कैरोलाइना आवेदक School Bus (S) एंडोर्समेंट प्राप्त कर सके, उसके पास सबसे पहले कौन-सा अन्य एंडोर्समेंट होना चाहिए?","options":["H (HazMat)","N (Tank)","T (Doubles/Triples)","P (Passenger)"],"explanation":"संघीय और नॉर्थ कैरोलाइना नियमों के तहत, School Bus (S) एंडोर्समेंट के लिए चालक को पहले Passenger (P) एंडोर्समेंट के लिए योग्य होना आवश्यक है। स्रोत: NCDMV CDL endorsements; 49 CFR 383.93(b)।"},"31":{"q":"नवीनीकरण की आवश्यकता से पहले एक नॉर्थ कैरोलाइना Commercial Learner Permit (CLP) कितने समय तक वैध रहता है?","options":["90 days","180 days","1 year","30 days"],"explanation":"एक नॉर्थ कैरोलाइना CLP 180 days के लिए वैध होता है और सामान्य नॉलेज टेस्ट दोबारा दिए बिना अतिरिक्त 180 days के लिए एक बार नवीनीकृत किया जा सकता है। स्रोत: NCDMV Commercial Driver License पेज; 49 CFR 383.25।"},"32":{"q":"नॉर्थ कैरोलाइना द्वारा अपनाए गए संघीय नियमों के तहत, CDL स्किल्स (रोड) टेस्ट देने से पहले एक CDL आवेदक को Commercial Learner Permit कम से कम कितने समय तक रखना आवश्यक है?","options":["7 days","14 days","30 days","60 days"],"explanation":"CDL स्किल्स टेस्ट देने की अनुमति दिए जाने से पहले एक आवेदक को CLP कम से कम 14 days तक रखना आवश्यक है। नॉर्थ कैरोलाइना इस संघीय आवश्यकता को लागू करता है। स्रोत: NCDMV CDL पेज; 49 CFR 383.25(e)।"},"33":{"q":"नॉर्थ कैरोलाइना Commercial Learner Permit के तहत संचालन करते समय, CLP धारक के साथ ऐसा व्यक्ति होना चाहिए जिसके पास कौन-सा प्रमाण-पत्र हो?","options":["कोई भी वैध Class C ड्राइवर लाइसेंस","उचित एंडोर्समेंट के साथ समान या उच्च श्रेणी का एक वैध CDL","एक नॉर्थ कैरोलाइना इंस्ट्रक्शन परमिट","किसी साथी चालक की आवश्यकता नहीं है"],"explanation":"एक CLP धारक के साथ हमेशा उपयुक्त श्रेणी और एंडोर्समेंट का वैध CDL रखने वाला कोई व्यक्ति होना चाहिए, जो आगे की सीट पर बैठा हो। स्रोत: NCDMV CDL पेज; 49 CFR 383.25।"},"34":{"q":"पहली बार CDL प्राप्त करने वाले व्यक्ति के लिए नॉर्थ कैरोलाइना में कौन-सी एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) आवश्यकता लागू होती है?","options":["चालक की पसंद के किसी भी निजी प्रशिक्षक से प्रशिक्षण","FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से प्रशिक्षण","केवल NCDMV द्वारा अनुमोदित एक ऑनलाइन वीडियो पाठ्यक्रम","किसी औपचारिक प्रशिक्षण की आवश्यकता नहीं, केवल परीक्षण"],"explanation":"Feb. 7, 2022 से, पहली बार CDL आवेदकों (और B से A में अपग्रेड करने वालों या P, S, या H एंडोर्समेंट चाहने वालों) को परीक्षण से पहले FMCSA Training Provider Registry पर मौजूद एक प्रदाता से ELDT पूरा करना आवश्यक है। स्रोत: FMCSA ELDT rule; NCDMV CDL पेज।"},"35":{"q":"नॉर्थ कैरोलाइना HazMat (H) एंडोर्समेंट के लिए, किस प्रकार का ELDT पूरा किया जाना चाहिए और कब?","options":["नॉलेज टेस्ट से पहले केवल थ्योरी प्रशिक्षण","स्किल्स टेस्ट से पहले बिहाइंड-द-व्हील प्रशिक्षण","रोड टेस्ट से पहले थ्योरी और बिहाइंड-द-व्हील दोनों","HazMat के लिए कोई ELDT आवश्यक नहीं है"],"explanation":"H एंडोर्समेंट के लिए ELDT केवल थ्योरी (नॉलेज) प्रशिक्षण है, जो राज्य नॉलेज टेस्ट से पहले एक Training Provider Registry प्रदाता के माध्यम से पूरा किया जाता है; H के लिए कोई बिहाइंड-द-व्हील घटक नहीं है। स्रोत: FMCSA ELDT rule (49 CFR Part 380, Subpart F)।"},"36":{"q":"नॉलेज टेस्ट पास करने के अलावा, नॉर्थ कैरोलाइना HazMat (H) एंडोर्समेंट जारी करने से पहले क्या आवश्यक करता है?","options":["NCDMV से एक विज़न छूट","फिंगरप्रिंटिंग सहित एक TSA सुरक्षा खतरा मूल्यांकन","पाँच वर्ष का ड्राइविंग अनुभव","एक अलग बिहाइंड-द-व्हील स्किल्स टेस्ट"],"explanation":"H एंडोर्समेंट के लिए फिंगरप्रिंटिंग के साथ एक TSA Hazmat Endorsement Threat Assessment Program पृष्ठभूमि जाँच आवश्यक है; एंडोर्समेंट आमतौर पर हर पाँच वर्ष में नवीनीकृत किया जाता है। स्रोत: NCDMV CDL पेज; TSA HME program; 49 CFR 1572।"},"37":{"q":"नॉर्थ कैरोलाइना CDL के लिए आवेदन करते समय, एक आवेदक को कौन-सा दस्तावेज़ सेट प्रदान करना चाहिए?","options":["केवल एक Social Security card","पहचान/आयु, Social Security number, नॉर्थ कैरोलाइना निवास, और वैध उपस्थिति का प्रमाण","एक पासपोर्ट और कुछ नहीं","केवल देयता बीमा का प्रमाण"],"explanation":"NCDMV को पहचान/जन्म तिथि, Social Security number, नॉर्थ कैरोलाइना निवास, और वैध उपस्थिति (U.S. नागरिकता या कानूनी स्थिति) के दस्तावेज़ीकरण के साथ-साथ देयता बीमा के प्रमाण की आवश्यकता होती है। स्रोत: NCDMV Commercial Driver License document requirements।"},"38":{"q":"नॉर्थ कैरोलाइना CDL आवेदक को अपने द्वारा किए जाने वाले वाणिज्यिक संचालन के प्रकार को प्रमाणित करते समय कितनी मेडिकल स्व-प्रमाणन श्रेणियों में से चुनना होता है?","options":["दो","तीन","चार","पाँच"],"explanation":"नॉर्थ कैरोलाइना CDL धारक चार श्रेणियों में से एक में स्व-प्रमाणित करते हैं: interstate non-excepted, interstate excepted, intrastate non-excepted, या intrastate excepted। स्रोत: NCDMV CDL medical self-certification (Form CDL-MED-1)।"},"39":{"q":"किस नॉर्थ कैरोलाइना CDL स्व-प्रमाणन श्रेणी में चालक को NCDMV के पास एक वैध मेडिकल एग्ज़ामिनर का प्रमाण-पत्र फाइल में बनाए रखना आवश्यक है?","options":["Interstate excepted","Interstate non-excepted","Intrastate excepted","किसी भी श्रेणी में मेडिकल प्रमाण-पत्र की आवश्यकता नहीं है"],"explanation":"Interstate Non-Excepted के रूप में प्रमाणित करने वाला चालक 49 CFR Part 391 के अधीन है और उसे NCDMV के पास एक मेडिकल एग्ज़ामिनर का प्रमाण-पत्र प्राप्त करना और बनाए रखना आवश्यक है; excepted श्रेणियों के लिए यह आवश्यक नहीं है। स्रोत: NCDMV CDL self-certification; 49 CFR 391.41 / 383.71।"},"40":{"q":"नॉर्थ कैरोलाइना में, किसी व्यक्ति द्वारा वाणिज्यिक मोटर वाहन को कानूनी रूप से चलाने के लिए अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितनी होती है?","options":["0.02","0.04","0.08","0.10"],"explanation":"नॉर्थ कैरोलाइना G.S. 20-138.2 के तहत CMV दुर्बलता सीमा को 0.04 BAC निर्धारित करता है, जो सामान्य चालकों के लिए 0.08 सीमा का आधा है। NC CDL मैनुअल 0.04 या उससे अधिक BAC के साथ CMV चलाने को एक प्रमुख अपराध के रूप में सूचीबद्ध करता है।"},"41":{"q":"प्लेकार्ड वाली खतरनाक सामग्री न ले जाने वाले वाहन में किए गए पहले प्रमुख अपराध (जैसे DWI या 0.04+ BAC) के लिए, एक नॉर्थ कैरोलाइना CDL धारक को कितने समय के लिए अयोग्य ठहराया जाता है?","options":["60 days","120 days","1 year","3 years"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल (49 CFR 383.51 को प्रतिबिंबित करते हुए) के तहत, जब कोई प्लेकार्ड वाली खतरनाक सामग्री शामिल न हो तो पहला प्रमुख अपराध चालक को कम से कम 1 year के लिए अयोग्य ठहराता है।"},"42":{"q":"यदि एक नॉर्थ कैरोलाइना CDL धारक खतरनाक सामग्री के लिए प्लेकार्ड वाले वाहन को चलाते समय पहला प्रमुख अपराध करता है, तो अयोग्यता अवधि बढ़कर कितनी हो जाती है?","options":["1 year","2 years","3 years","5 years"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल यह प्रावधान करते हैं कि प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय किए गए पहले प्रमुख अपराध के परिणामस्वरूप मानक 1 year के बजाय 3-year की अयोग्यता होती है।"},"43":{"q":"नॉर्थ कैरोलाइना कानून के तहत, एक अलग घटना से उत्पन्न दूसरे प्रमुख अपराध (दूसरा DWI, इनकार, या समान) के लिए दोषी पाए गए CDL धारक के लिए अयोग्यता क्या है?","options":["3 years","5 years","10 years","आजीवन"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल एक अलग घटना से उत्पन्न दूसरे प्रमुख अपराध के लिए आजीवन CDL अयोग्यता लगाते हैं। कुछ मामलों में 10 years के बाद एक सीमित बहाली संभव हो सकती है, लेकिन अयोग्यता स्वयं आजीवन के लिए होती है।"},"44":{"q":"एक नॉर्थ कैरोलाइना CDL धारक को CMV में नशे में ड्राइविंग के लिए रोका जाता है और वह एक रासायनिक (श्वास या रक्त) परीक्षण देने से इनकार कर देता है। CDL अयोग्यता उद्देश्यों के लिए इस इनकार को कैसे माना जाता है?","options":["इस पर कोई CDL दंड नहीं लगता, केवल एक व्यक्तिगत-लाइसेंस दंड लगता है","यह एक गंभीर यातायात उल्लंघन है (60-day अयोग्यता)","यह एक प्रमुख अपराध है (कम से कम 1-year अयोग्यता)","पहले इनकार पर इसका परिणाम आजीवन अयोग्यता होता है"],"explanation":"नॉर्थ कैरोलाइना के अंतर्निहित-सहमति कानून और G.S. 20-17.4 के तहत, रासायनिक परीक्षण से इनकार करना एक प्रमुख अपराध है, जो चालक को कम से कम 1 year (प्लेकार्ड वाली हैज़मैट ढोने पर 3 years) के लिए अयोग्य ठहराता है, ठीक एक दोषसिद्धि के समान।"},"45":{"q":"नॉर्थ कैरोलाइना के अंतर्निहित-सहमति क़ानून के तहत, राज्य की सड़कों पर एक वाणिज्यिक वाहन चलाने से एक CDL चालक को नशे में ड्राइविंग के लिए कानूनी रूप से रोके जाने पर निम्नलिखित में से किसके लिए सहमति देने वाला माना जाता है?","options":["केवल एक फील्ड संयम परीक्षण","श्वास, रक्त, या मूत्र का रासायनिक परीक्षण","वारंट के बिना एक वाहन तलाशी","मौके पर CDL का समर्पण"],"explanation":"नॉर्थ कैरोलाइना का अंतर्निहित-सहमति कानून (G.S. 20-16.2) यह प्रावधान करता है कि कोई भी चालक एक अंतर्निहित-सहमति अपराध के आरोप में श्वास, रक्त, या अन्य शारीरिक द्रव के रासायनिक विश्लेषण के लिए अंतर्निहित रूप से सहमति देता है; इनकार लाइसेंस निरस्तीकरण और CDL अयोग्यता को ट्रिगर करता है।"},"46":{"q":"60-day अयोग्यता का सामना करने से पहले एक नॉर्थ कैरोलाइना CDL धारक को 3-year की अवधि के भीतर (एक CMV में) कितने गंभीर यातायात उल्लंघन करने चाहिए?","options":["1","2","3","4"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल 3 years के भीतर अलग-अलग घटनाओं से उत्पन्न होने वाले दूसरे गंभीर यातायात उल्लंघन पर एक चालक को 60 days के लिए अयोग्य ठहराते हैं।"},"47":{"q":"नॉर्थ कैरोलाइना में, 3-year की अवधि के भीतर तीसरे गंभीर यातायात उल्लंघन के परिणामस्वरूप कितने समय की CDL अयोग्यता होती है?","options":["60 days","120 days","180 days","1 year"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल के तहत, 3 years के भीतर तीसरा गंभीर यातायात उल्लंघन (अलग-अलग घटनाएँ) 120-day की अयोग्यता का परिणाम देता है, जो किसी पूर्व अयोग्यता के अंत में पूरी की जाती है।"},"48":{"q":"निम्नलिखित में से किसे एक नॉर्थ कैरोलाइना CDL धारक के लिए 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["निर्धारित सीमा से 15 mph या उससे अधिक तेज़ गति","एक CMV में पार्किंग उल्लंघन","सीमा से 5 mph तेज़ ड्राइविंग","एक समाप्त वाहन पंजीकरण"],"explanation":"NC CDL मैनुअल और 49 CFR 383.51 अत्यधिक गति (सीमा से 15 mph या उससे अधिक) को एक गंभीर यातायात उल्लंघन के रूप में परिभाषित करते हैं। पार्किंग और पंजीकरण अपराधों को स्पष्ट रूप से उस श्रेणी से बाहर रखा गया है।"},"49":{"q":"नॉर्थ कैरोलाइना नियमों के तहत, CDL अयोग्यता उद्देश्यों के लिए इनमें से किसे एक गंभीर यातायात उल्लंघन के रूप में नहीं गिना जाता है?","options":["लापरवाह ड्राइविंग","बहुत पास से पीछा करना","अनुचित या अनियमित लेन परिवर्तन","एक जली हुई हेडलाइट के साथ CMV चलाना"],"explanation":"NC CDL मैनुअल G.S. 20-17.4 / 49 CFR 383.51 के तहत लापरवाह ड्राइविंग, बहुत पास से पीछा करना, और अनुचित/अनियमित लेन परिवर्तन को गंभीर यातायात उल्लंघनों में सूचीबद्ध करता है। जली हुई हेडलाइट जैसा एक उपकरण दोष उस सूची में नहीं है।"},"50":{"q":"नॉर्थ कैरोलाइना में उचित श्रेणी की CDL या आवश्यक एंडोर्समेंट के बिना CMV चलाना किस प्रकार के अपराध के रूप में माना जाता है?","options":["एक प्रमुख अपराध (1-year अयोग्यता)","एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ-सर्विस उल्लंघन","एक गैर-रिपोर्ट योग्य उपकरण उल्लंघन"],"explanation":"NC CDL मैनुअल और 49 CFR 383.51 उचित CDL श्रेणी या एंडोर्समेंट के बिना (या CDL को साथ रखे बिना) CMV चलाने को एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध करते हैं, जो अन्य गंभीर उल्लंघनों के साथ मिलकर 60/120-day की अयोग्यता को ट्रिगर कर सकता है।"},"51":{"q":"एक नॉर्थ कैरोलाइना CDL धारक के लिए, वाणिज्यिक मोटर वाहन चलाते समय टेक्स्टिंग करना अयोग्यता उद्देश्यों के लिए किस रूप में वर्गीकृत किया जाता है?","options":["एक प्रमुख अपराध","एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ-सर्विस आदेश उल्लंघन","एक रेलरोड-क्रॉसिंग उल्लंघन"],"explanation":"G.S. 20-137.4A और NC CDL मैनुअल (49 CFR 383.51 और 392.80 के अनुरूप) के तहत, CMV चलाते समय टेक्स्टिंग करना एक गंभीर यातायात उल्लंघन है, जो 60/120-day की अयोग्यता में योगदान देता है।"},"52":{"q":"नॉर्थ कैरोलाइना कानून ड्राइविंग करते समय एक CMV चालक के मोबाइल टेलीफोन के उपयोग को निम्नलिखित में से किस तक सीमित करता है?","options":["केवल हैंड्स-फ्री उपयोग","केवल लाल बत्ती पर रुकने पर उपयोग","एक मिनट से कम की कॉल","वॉइस कॉल के लिए किसी भी हैंडहेल्ड फोन का उपयोग"],"explanation":"G.S. 20-137.4A FMCSA Parts 390/392 के अधीन CMV ऑपरेटरों को एक हैंडहेल्ड मोबाइल फोन का उपयोग करने से प्रतिबंधित करता है; केवल हैंड्स-फ्री संचालन की अनुमति है। CMV में एक हैंडहेल्ड-फोन उल्लंघन एक गंभीर यातायात उल्लंघन है।"},"53":{"q":"CMV (गैर-हैज़मैट) चलाते समय एक आउट-ऑफ-सर्विस आदेश का उल्लंघन करने पर एक नॉर्थ कैरोलाइना CDL धारक की पहली दोषसिद्धि के लिए अयोग्यता अवधि क्या है?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 90 days","कम से कम 180 days"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल एक मानक CMV के लिए पहले आउट-ऑफ-सर्विस आदेश उल्लंघन को 180 days से कम नहीं (1 year तक) निर्धारित करते हैं, जो अधिकांश गंभीर उल्लंघनों के दंड से कहीं अधिक है।"},"54":{"q":"यदि एक नॉर्थ कैरोलाइना CDL धारक प्लेकार्ड वाली खतरनाक सामग्री या 16+ यात्रियों को ले जाते समय एक आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है, तो पहले उल्लंघन के लिए कम से कम कितने समय की अयोग्यता होती है?","options":["90 days","180 days","1 year","3 years"],"explanation":"G.S. 20-17.4 के तहत, प्लेकार्ड वाली हैज़मैट ढोते समय या 16 या अधिक यात्रियों को ले जाते समय पहला आउट-ऑफ-सर्विस उल्लंघन 180 days से कम नहीं (और 2 years तक) होता है, जो मानक आउट-ऑफ-सर्विस अपराध की तुलना में एक लंबी अधिकतम सीमा है।"},"55":{"q":"नॉर्थ कैरोलाइना कानून के तहत, 10-year की अवधि के भीतर एक दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन एक CDL धारक को कम से कम कितनी अवधि के लिए अयोग्य ठहराता है?","options":["180 days","1 year","2 years","5 years"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल किसी भी 10-year की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए एक चालक को 2 years से कम नहीं (5 years तक) के लिए अयोग्य ठहराते हैं।"},"56":{"q":"नॉर्थ कैरोलाइना में, CMV में किए गए एक CDL धारक के पहले रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता क्या है?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल एक CMV में पहले रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए 60 days से कम नहीं की अयोग्यता लगाते हैं।"},"57":{"q":"एक नॉर्थ कैरोलाइना CDL धारक 3-year की अवधि के भीतर एक तीसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। अयोग्यता क्या है?","options":["60 days","120 days","कम से कम 1 year","आजीवन"],"explanation":"G.S. 20-17.4 और NC CDL मैनुअल के तहत, रेलरोड-क्रॉसिंग उल्लंघनों के लिए 60 days (पहला), 120 days (3 years के भीतर दूसरा), और 1 year से कम नहीं (3 years के भीतर तीसरा) की अयोग्यता होती है।"},"58":{"q":"जब एक नॉर्थ कैरोलाइना CDL धारक एक वाणिज्यिक वाहन में एक मूविंग यातायात उल्लंघन करता है जिसके लिए अंक निर्धारित किए जाते हैं, तो अदालत एक गैर-वाणिज्यिक चालक की तुलना में जुर्माने को कैसे मानती है?","options":["CDL धारकों के लिए जुर्माना माफ कर दिया जाता है","जुर्माना दोगुना किया जा सकता है","जुर्माना आधा कर दिया जाता है","जुर्माना किसी भी चालक के समान ही होता है"],"explanation":"नॉर्थ कैरोलाइना कानून के तहत, अदालत एक CMV ऑपरेटर के लिए जुर्माना दोगुना कर सकती है जो एक अंक-निर्धारण योग्य मोटर वाहन उल्लंघन करता है, जो वाणिज्यिक चालकों पर रखे गए उच्च मानक को दर्शाता है।"},"59":{"q":"जब एक नॉर्थ कैरोलाइना CDL चालक एक रासायनिक परीक्षण से इनकार करता है या एक अंतर्निहित-सहमति स्टॉप के दौरान CMV में 0.04 या उससे अधिक दर्ज करता है, तो किसी भी दोषसिद्धि से पहले चालक के लाइसेंस पर आमतौर पर कौन-सी तत्काल पूर्व-परीक्षण कार्रवाई लागू होती है?","options":["एक 10-day प्रशासनिक रोक","एक 30-day नागरिक निरस्तीकरण","एक 90-day निलंबन","दोषसिद्धि तक कोई कार्रवाई नहीं"],"explanation":"नॉर्थ कैरोलाइना का अंतर्निहित-सहमति कानून (G.S. 20-16.5) एक योग्य परीक्षण परिणाम या इनकार पर चालक के लाइसेंस का 30-day नागरिक (पूर्व-परीक्षण) निरस्तीकरण लगाता है, जो एक दोषसिद्धि के बाद होने वाली CDL अयोग्यता से अलग है।"},"60":{"q":"नॉर्थ कैरोलाइना के छह या अधिक लेन वाले नियंत्रित-पहुंच राजमार्ग (controlled-access highway) पर, 26,001 पाउंड या उससे अधिक के सकल वाहन भार रेटिंग (GVWR) वाले ट्रक पर कौन-सी पाबंदी लागू होती है?","options":["यह बाएं-सबसे लेन में संचालन नहीं कर सकता, सिवाय राजमार्ग में प्रवेश करते या बाहर निकलते समय, ओवरटेक करते समय, या किसी खतरे से बचते समय","इसे हमेशा केवल दाएं-सबसे लेन में ही चलना चाहिए","जब तक यह यातायात के साथ गति बनाए रखता है, तब तक यह किसी भी लेन का उपयोग कर सकता है","यह बाएं-सबसे लेन का उपयोग केवल रात 9 बजे और सुबह 6 बजे के बीच ही कर सकता है"],"explanation":"नॉर्थ कैरोलाइना G.S. 20-146 के अनुसार 26,001 पाउंड या उससे अधिक GVWR वाले वाहन को छह या अधिक लेन वाले नियंत्रित-पहुंच राजमार्ग की बाएं-सबसे लेन में संचालन करने से प्रतिबंधित किया गया है, सिवाय राजमार्ग में प्रवेश करते या बाहर निकलते समय, ओवरटेक करते समय, या किसी खतरे से बचते समय। स्रोत: N.C. Gen. Stat. 20-146।"},"61":{"q":"नॉर्थ कैरोलाइना के मूव ओवर कानून (Move Over law) के तहत, जब कोई चालक किसी बहु-लेन सड़क पर चमकती चेतावनी रोशनी (flashing warning lights) दिखा रहे रुके हुए आपातकालीन या सार्वजनिक सेवा वाहन के पास पहुंचता है, तो उसे क्या करना चाहिए?","options":["यदि सुरक्षित रूप से किया जा सके, तो उस लेन में चला जाना चाहिए जो रुके हुए वाहन के सबसे नज़दीक की लेन नहीं है","वर्तमान लेन में तब तक पूरी तरह रुक जाना चाहिए जब तक वाहन वहां से चला न जाए","गुज़रते समय लगातार हॉर्न बजाना चाहिए","निर्धारित गति सीमा से 5 mph से अधिक धीमी गति से न गुज़रना चाहिए"],"explanation":"N.C. Gen. Stat. 20-157 के तहत, यात्रा की दिशा में दो या अधिक लेन वाली सड़क पर, चालक को, जब सुरक्षित रूप से किया जा सके, उस लेन में चला जाना चाहिए जो रुके हुए आपातकालीन/सार्वजनिक सेवा वाहन के सबसे नज़दीक नहीं है। एकल-लेन सड़क पर चालक को इसके बजाय गति धीमी करनी चाहिए और रुकने के लिए तैयार रहना चाहिए। स्रोत: N.C. Gen. Stat. 20-157।"},"62":{"q":"नॉर्थ कैरोलाइना में प्लेकार्ड लगे खतरनाक-सामग्री वाहन का एक चालक किसी रेलमार्ग ग्रेड क्रॉसिंग के पास पहुंचता है। चालक को कहां रुकना चाहिए?","options":["सबसे नज़दीकी रेल से 50 फीट के भीतर, लेकिन 15 फीट से अधिक नज़दीक नहीं","सबसे नज़दीकी रेल से 25 फीट के भीतर, लेकिन 5 फीट से अधिक नज़दीक नहीं","सबसे नज़दीकी रेल से 100 फीट के भीतर, लेकिन 50 फीट से अधिक नज़दीक नहीं","सबसे नज़दीकी रेल से ठीक 10 फीट दूर"],"explanation":"बसों और प्लेकार्ड लगे/हैज़मैट वाहनों को क्रॉस करने से पहले सबसे नज़दीकी रेल से 50 फीट के भीतर, और 15 फीट से अधिक नज़दीक नहीं, रुकना चाहिए, फिर देखना और सुनना चाहिए। यह संघीय मानक (49 CFR 392.10) नॉर्थ कैरोलाइना CDL मैनुअल में सिखाया जाता है और नॉर्थ कैरोलाइना में लागू होता है। स्रोत: N.C. CDL Driver Handbook; 49 CFR 392.10।"},"63":{"q":"नॉर्थ कैरोलाइना की दो-लेन वाली सड़क (प्रत्येक दिशा में एक लेन) पर, एक स्कूल बस लाल बत्तियां चमकाते हुए और अपनी स्टॉप आर्म बाहर निकाले हुए बच्चों को बैठाने के लिए रुकती है। किन वाहनों को रुकना चाहिए?","options":["दोनों दिशाओं से आ रहे यातायात को रुकना चाहिए","केवल बस के पीछे का यातायात रुकना चाहिए","केवल विपरीत दिशा का यातायात रुकना चाहिए","यदि चालक 20 mph तक धीमे हो जाएं तो किसी को रुकने की ज़रूरत नहीं"],"explanation":"N.C. Gen. Stat. 20-217 के तहत, दो-लेन वाली सड़क पर उसी सड़क पर किसी भी दिशा से रुकी हुई स्कूल बस के पास आ रहे हर वाहन को पूरी तरह रुकना चाहिए और तब तक रुके रहना चाहिए जब तक स्टॉप सिग्नल वापस न ले लिया जाए और बस चल न पड़े। स्रोत: N.C. Gen. Stat. 20-217(a)।"},"64":{"q":"नॉर्थ कैरोलाइना के स्कूल-बस रुकने के कानून के तहत, रुकी हुई स्कूल बस की विपरीत दिशा में चल रहे वाहन के चालक को किस स्थिति में रुकना नहीं पड़ता?","options":["जब सड़क किसी बीच के स्थान या भौतिक अवरोध द्वारा दो सड़कमार्गों में विभाजित हो (एक केंद्रीय मोड़ लेन तभी गिनी जाती है जब सड़क में कम से कम चार लेन हों)","जब भी सड़क पर किसी भी प्रकार की पेंट की हुई केंद्रीय रेखा हो","जब भी प्रत्येक दिशा में एक लेन हो","जब भी विपरीत दिशा का चालक 15 mph या उससे कम तक धीमा हो जाए"],"explanation":"N.C. Gen. Stat. 20-217(c) विपरीत दिशा के यातायात को केवल वहीं छूट देता है जहां सड़क किसी बीच के स्थान (इसमें बाएं मोड़ के लिए केंद्रीय लेन शामिल है, यदि सड़कमार्ग में कम से कम चार अधिक लेन हों) या किसी भौतिक अवरोध द्वारा दो सड़कमार्गों में विभाजित हो। किसी अविभाजित सड़क पर केवल पेंट की हुई केंद्रीय रेखा इसके लिए योग्य नहीं है। स्रोत: N.C. Gen. Stat. 20-217(c)।"},"65":{"q":"नॉर्थ कैरोलाइना DOT किसी अंतरराज्यीय या नियंत्रित-पहुंच राजमार्ग पर अधिकतम कितनी गति सीमा निर्धारित कर सकता है?","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"N.C. Gen. Stat. 20-141(b) के तहत, अंतरराज्यीय या नियंत्रित-पहुंच राजमार्ग प्रणाली पर निर्धारित गति सीमा 70 मील प्रति घंटे से अधिक नहीं हो सकती। स्रोत: N.C. Gen. Stat. 20-141।"},"66":{"q":"नॉर्थ कैरोलाइना के किसी राजमार्ग पर जहां निर्धारित गति सीमा सभी प्रकार के वाहनों के लिए एक समान कर दी गई है, वहां ट्रक की गति सीमा कार की गति सीमा की तुलना में कैसी होती है?","options":["ट्रकों और कारों की निर्धारित गति सीमा समान होती है","ट्रक कार की सीमा से 10 mph कम तक सीमित होते हैं","निर्धारित सीमा चाहे जो भी हो, ट्रक 55 mph तक सीमित होते हैं","ढलानों पर ट्रक कारों से 5 mph तेज़ चल सकते हैं"],"explanation":"नॉर्थ कैरोलाइना ट्रकों के लिए कोई अलग, कम राज्यव्यापी गति सीमा निर्धारित नहीं करता; G.S. 20-141(l) निर्धारित सीमा को सभी प्रकार के मोटर वाहनों पर एक समान रूप से लागू करता है। (ओवरसाइज़/ओवरवेट परमिट के तहत चल रहे किसी विशिष्ट वाहन पर एक कम सीमा लागू हो सकती है।) स्रोत: N.C. Gen. Stat. 20-141(l)।"},"67":{"q":"नॉर्थ कैरोलाइना के ब्लू रिज पार्कवे (Blue Ridge Parkway) पर वाणिज्यिक ट्रकों पर प्रतिबंध क्यों है?","options":["यह एक संकरी, घुमावदार दो-लेन वाली दर्शनीय सड़क है जिसमें कोई ट्रक लेन या रनअवे रैंप नहीं हैं","यह एक निजी टोल सड़क है जो केवल यात्री कारों के लिए खुली है","यह बिना वज़न स्टेशनों के दूसरे राज्य में प्रवेश करती है","इस पर हर मील पर वज़न-प्रतिबंधित पुल हैं"],"explanation":"वाणिज्यिक वाहनों पर ब्लू रिज पार्कवे पर प्रतिबंध इसलिए है क्योंकि यह एक संकरी, दो-लेन वाली नेशनल पार्क सर्विस की दर्शनीय सड़क है जिसमें बदलती ढलानें, मोड़, सीमित दृश्यता दूरी, और कोई ट्रक लेन या रनअवे ट्रक रैंप नहीं हैं। स्रोत: National Park Service / Blue Ridge Parkway regulations।"},"68":{"q":"नॉर्थ कैरोलाइना के किसी विभाजित राजमार्ग पर एक ट्रक खराब हो जाता है। तीन आपातकालीन चेतावनी उपकरण (परावर्तक त्रिकोण) कहां रखे जाने चाहिए?","options":["पीछे की ओर 10 फीट, 100 फीट, और 200 फीट पर, सभी आ रहे यातायात की ओर","10 फीट, 50 फीट, और 150 फीट पर, दो पीछे की ओर और एक आगे की ओर","पीछे की ओर 5 फीट, 75 फीट, और 250 फीट पर","पीछे की ओर 25 फीट, 100 फीट, और 300 फीट पर"],"explanation":"किसी एकतरफ़ा या विभाजित राजमार्ग पर, तीनों चेतावनी उपकरण रुके हुए वाहन से 10, 100, और 200 फीट पर आ रहे यातायात की ओर रखे जाते हैं। (दो-तरफ़ा सड़क पर, एक पीछे की ओर 10 फीट, एक पीछे की ओर 100 फीट, और एक आगे की ओर 100 फीट पर जाता है।) स्रोत: N.C. CDL Driver Handbook; 49 CFR 392.22।"},"69":{"q":"नॉर्थ कैरोलाइना का मूव ओवर कानून पुलिस, अग्निशमन, और एम्बुलेंस के अलावा किस अतिरिक्त श्रेणी के वाहन तक विस्तृत होता है?","options":["एम्बर चमकती रोशनी दिखा रहे उपयोगिता (utility), राजमार्ग-रखरखाव, और खराब-वाहन/रेकर (wrecker) वाहन","अपनी चार-तरफ़ा फ्लैशर का उपयोग कर रही कोई भी यात्री कार","केवल डाक-वितरण वाहन","केवल राज्य के बाहर के आपातकालीन वाहन"],"explanation":"N.C. Gen. Stat. 20-157 एम्बर चमकती रोशनी दिखा रहे 'सार्वजनिक सेवा वाहनों' को भी शामिल करता है, जिसमें उपयोगिता (बिजली, गैस, पानी, संचार), राजमार्ग-रखरखाव, कचरा, और खराब-वाहन/रेकर सेवा वाहन शामिल हैं। चालकों को उनके लिए लेन बदलनी चाहिए या गति धीमी करनी चाहिए। स्रोत: N.C. Gen. Stat. 20-157।"},"70":{"q":"किसी रेलमार्ग क्रॉसिंग पर रुकने के बाद, नॉर्थ कैरोलाइना की बस या प्लेकार्ड लगे वाहन के चालक को क्रॉस करते समय निम्न में से क्या करना चाहिए?","options":["ऐसे गियर में क्रॉस करें जिसमें पटरियों पर गियर बदलने की ज़रूरत न पड़े","नियंत्रण पाने के लिए बीच में पहुंचकर निचले गियर में बदल जाएं","दोबारा जांच के लिए पटरियों के केंद्र पर फिर से रुकें","ईंधन बचाने के लिए न्यूट्रल में क्रॉस करें"],"explanation":"नॉर्थ कैरोलाइना CDL मैनुअल चालकों को ऐसा गियर चुनने का निर्देश देता है जो उन्हें बिना गियर बदले पूरी तरह क्रॉस करने दे, और रुकने (stalling) से बचने के लिए पटरियों पर रहते हुए कभी भी गियर न बदलें। स्रोत: N.C. CDL Driver Handbook; 49 CFR 392.10/392.11।"},"71":{"q":"नॉर्थ कैरोलाइना में बच्चों को बैठा या उतार रही रुकी हुई स्कूल बस को गैरकानूनी रूप से ओवरटेक करने पर न्यूनतम जुर्माना क्या है?","options":["$500 और एक Class 1 misdemeanor","$100 और एक infraction","$250 और एक Class 3 misdemeanor","$1,000 और एक Class 2 misdemeanor"],"explanation":"N.C. Gen. Stat. 20-217(e) के तहत, रुकी हुई स्कूल बस को ओवरटेक करना एक Class 1 misdemeanor है जिसमें $500 का न्यूनतम जुर्माना लगता है, और कोई prayer for judgment continued की अनुमति नहीं है। किसी व्यक्ति को टक्कर मारने पर यह उच्च न्यूनतम जुर्माने वाला felony बन जाता है। स्रोत: N.C. Gen. Stat. 20-217(e),(g)।"},"72":{"q":"ट्रायंगल एक्सप्रेसवे (Triangle Expressway) और नॉर्थ कैरोलाइना टर्नपाइक की अन्य टोल सुविधाओं (जैसे I-540) पर, टोल कैसे वसूले जाते हैं?","options":["बिना किसी टोल बूथ के सर्व-इलेक्ट्रॉनिक टोलिंग, NC Quick Pass ट्रांसपोंडर या डाक-द्वारा-बिल का उपयोग करके","हर इंटरचेंज पर केवल-नकद टोल बूथ","सभी ट्रकों के लिए एक समान वार्षिक स्टिकर शुल्क","टोल केवल राज्य की सीमा पर वसूले जाते हैं"],"explanation":"नॉर्थ कैरोलाइना की टोल सड़कें बिना बूथ के 100% सर्व-इलेक्ट्रॉनिक टोलिंग का उपयोग करती हैं; चालक NC Quick Pass ट्रांसपोंडर/खाते के माध्यम से भुगतान करते हैं या डाक द्वारा बिल प्राप्त करते हैं। ट्रकों से एक्सल की संख्या के आधार पर अधिक शुल्क लिया जाता है। स्रोत: NCDOT Turnpike Authority / NC Quick Pass।"},"73":{"q":"नॉर्थ कैरोलाइना के मूव ओवर कानून के एक बुनियादी उल्लंघन (कोई चोट या संपत्ति क्षति नहीं) के लिए मानक जुर्माना क्या है?","options":["$250 infraction","$50 infraction","$500 Class 1 misdemeanor","$1,000 felony"],"explanation":"N.C. Gen. Stat. 20-157 का एक बुनियादी उल्लंघन एक infraction है जिसमें $250 जुर्माने की सज़ा है। $500 से अधिक की संपत्ति क्षति या चोट होने पर यह एक misdemeanor में बढ़ जाता है, और यदि इससे गंभीर चोट या मृत्यु होती है तो यह एक Class F felony बन जाता है। स्रोत: N.C. Gen. Stat. 20-157।"},"74":{"q":"नॉर्थ कैरोलाइना के दाएं-रहने (keep-right) नियम के तहत, कानूनी अधिकतम गति से धीमी चल रहे वाहन को सामान्यतः कहां चलाया जाना चाहिए?","options":["थ्रू ट्रैफ़िक के लिए उपलब्ध दाएं हाथ की लेन में, या जितना व्यावहारिक हो उतना दाएं किनारे के पास","जो भी लेन सबसे कम भीड़भाड़ वाली हो उसमें","तीन-लेन वाली सड़क की केंद्रीय लेन में","बाईं लेन में ताकि दाईं लेन विलय (merging) के लिए खुली रहे"],"explanation":"N.C. Gen. Stat. 20-146 के अनुसार कानूनी अधिकतम गति से कम पर चल रहे किसी भी वाहन को दाएं हाथ की थ्रू लेन में, या जितना व्यावहारिक हो उतना दाएं किनारे के पास चलना चाहिए, सिवाय ओवरटेक करते समय या बाएं मोड़ की तैयारी करते समय। स्रोत: N.C. Gen. Stat. 20-146।"},"75":{"q":"नॉर्थ कैरोलाइना के स्कूल-बस रुकने के कानून के प्रयोजनों के लिए, इनमें से किसे एक 'स्कूल बस' माना जाता है जिसके लिए अन्य यातायात को रुकना आवश्यक है?","options":["G.S. 115C-243 के तहत वरिष्ठ नागरिकों को ले जा रही और आगे व पीछे 'school bus' अंकित एक सार्वजनिक स्कूल बस","किसी डेकेयर द्वारा उपयोग की जा रही कोई भी पीली वैन, चाहे अंकित हो या न हो","रंगे हुए (tinted) शीशों वाली एक चार्टर मोटरकोच","लाल ब्रेक लाइट वाला कोई भी वाहन"],"explanation":"N.C. Gen. Stat. 20-217(b) एक कवर की गई स्कूल बस को इस प्रकार परिभाषित करता है जिसमें बच्चों या कर्मचारियों को ले जा रही एक सार्वजनिक स्कूल बस, G.S. 115C-243 के तहत वरिष्ठ नागरिकों को ले जा रही एक सार्वजनिक स्कूल बस, या बच्चों को ले जा रही एक निजी स्वामित्व वाली बस शामिल है, लेकिन केवल तभी जब उस पर आगे और पीछे साफ़ दिखाई देने वाले 'school bus' चिन्ह हों। स्रोत: N.C. Gen. Stat. 20-217(b)।"},"76":{"q":"नॉर्थ कैरोलाइना के किस रेलमार्ग क्रॉसिंग पर एक CDL चालक को रुकना आवश्यक नहीं है, भले ही वह प्लेकार्ड लगे हैज़मैट को ढो रहा हो?","options":["एक ऐसा क्रॉसिंग जहां कोई पुलिस अधिकारी या फ्लैगर यातायात को आगे निर्देशित कर रहा हो","क्रॉसबक वाला, लेकिन बिना गेट वाला कोई भी क्रॉसिंग","ग्रामीण दो-लेन राजमार्ग पर एक क्रॉसिंग","45 mph से अधिक निर्धारित गति सीमा वाला एक क्रॉसिंग"],"explanation":"किसी पुलिस अधिकारी या फ्लैगर द्वारा नियंत्रित क्रॉसिंग पर, व्यावसायिक क्षेत्र में स्ट्रीटकार/औद्योगिक स्विचिंग पटरियों पर, 'Exempt' या 'Abandoned' अंकित क्रॉसिंग पर, और जहां एक कार्यरत राजमार्ग यातायात सिग्नल हरा दिखा रहा हो, वहां आवश्यक रुकाव से छूट है। स्रोत: N.C. CDL Driver Handbook; 49 CFR 392.10(b)।"},"77":{"q":"एक स्कूल बस नॉर्थ कैरोलाइना की ऐसी सड़क पर रुकती है जिसमें प्रत्येक दिशा में दो यात्रा लेन हैं, जो केवल एक सतत केंद्रीय दो-तरफ़ा बाएं-मोड़ लेन (एक पांच-लेन वाली सड़क) द्वारा अलग की गई हैं। क्या विपरीत दिशा के यातायात को रुकना चाहिए?","options":["नहीं, क्योंकि जब सड़क में कम से कम चार लेन हों तो एक केंद्रीय बाएं-मोड़ लेन एक विभाजक स्थान के रूप में योग्य होती है","हां, क्योंकि एक मोड़ लेन कोई भौतिक अवरोध नहीं है","हां, सभी सड़कों पर विपरीत दिशा के यातायात को रुकना आवश्यक है","नहीं, किसी भी बहु-लेन सड़क पर विपरीत दिशा के यातायात को कभी नहीं रुकना पड़ता"],"explanation":"G.S. 20-217(c) विपरीत दिशा के यातायात को आगे बढ़ने देता है जब सड़क किसी बीच के स्थान द्वारा विभाजित हो, और इसमें विशेष रूप से बाएं मोड़ के लिए एक केंद्रीय लेन शामिल है, यदि सड़कमार्ग में कम से कम चार लेन हों। केंद्रीय मोड़ लेन वाली एक पांच-लेन वाली सड़क इस कसौटी पर खरी उतरती है, इसलिए विपरीत दिशा के यातायात को रुकने की ज़रूरत नहीं है। स्रोत: N.C. Gen. Stat. 20-217(c)।"},"78":{"q":"नॉर्थ कैरोलाइना में एक चालक को तीन वर्षों के भीतर दूसरी बार रुकी हुई स्कूल बस को ओवरटेक करने का दोषी ठहराया जाता है। जुर्माने के अलावा लाइसेंस संबंधी परिणाम क्या है?","options":["एक वर्ष के लिए चालक लाइसेंस का निरस्तीकरण (revocation)","केवल 30-दिन का निलंबन","कोई लाइसेंस कार्रवाई नहीं, केवल अंक (points)","दूसरे अपराध पर स्थायी निरस्तीकरण"],"explanation":"N.C. Gen. Stat. 20-217(g1) के तहत, तीन वर्ष की अवधि के भीतर इस धारा के तहत दूसरी misdemeanor दोषसिद्धि के परिणामस्वरूप एक-वर्ष का लाइसेंस निरस्तीकरण होता है; एक CDL धारक को उस अवधि के लिए वाणिज्यिक वाहन चलाने से भी अयोग्य ठहराया जाता है। स्रोत: N.C. Gen. Stat. 20-217(g1)।"},"79":{"q":"नॉर्थ कैरोलाइना किसी विशिष्ट वाणिज्यिक वाहन के लिए किस परिस्थिति में एक कम निर्धारित गति सीमा निर्धारित कर सकता है?","options":["जब वाहन अपने वज़न या आयामों के कारण किसी विशेष ओवरसाइज़/ओवरवेट परमिट के तहत संचालन कर रहा हो","जब भी वाहन में दो से अधिक एक्सल हों","जब भी वाहन राज्य के बाहर पंजीकृत हो","जब भी ट्रेलर 40 फीट से अधिक लंबा हो"],"explanation":"N.C. Gen. Stat. 20-141(l) किसी ऐसे वाहन के लिए एक कम गति सीमा निर्धारित करने की अनुमति देता है जो वाहन या उसके भार के किसी वज़न या आयाम के कारण एक विशेष परमिट के तहत संचालन कर रहा हो। अन्यथा निर्धारित सीमा सभी प्रकार के वाहनों के लिए एक समान होती है। स्रोत: N.C. Gen. Stat. 20-141(l); NCDOT oversize/overweight permit rules।"},"80":{"q":"नॉर्थ कैरोलाइना में वाणिज्यिक चालक लाइसेंस (CDL) कौन-सी एजेंसी जारी करती है?","options":["संघीय मोटर वाहक सुरक्षा प्रशासन (Federal Motor Carrier Safety Administration, FMCSA)","नॉर्थ कैरोलाइना सार्वजनिक सुरक्षा विभाग (North Carolina Department of Public Safety)","नॉर्थ कैरोलाइना परिवहन विभाग हाईवे पैट्रोल (North Carolina Department of Transportation Highway Patrol)","नॉर्थ कैरोलाइना मोटर वाहन प्रभाग (North Carolina Division of Motor Vehicles, NCDMV)"],"explanation":"नॉर्थ कैरोलाइना में, CDL नॉर्थ कैरोलाइना मोटर वाहन प्रभाग (NCDMV) द्वारा जारी और प्रशासित किए जाते हैं, जो NCDOT का एक प्रभाग है। FMCSA संघीय मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: NCDMV Commercial Driver License page और N.C. CDL Manual, Section 1।"},"81":{"q":"नॉर्थ कैरोलाइना CDL या वाणिज्यिक शिक्षार्थी परमिट (commercial learner permit) प्राप्त करने के लिए, एक आवेदक को किन दो प्रकार की परीक्षाएं पास करनी होती हैं?","options":["एक लिखित परीक्षा और एक वाहन वज़न परीक्षा","ज्ञान परीक्षाएं (knowledge tests) और कौशल परीक्षाएं (skills tests)","एक शारीरिक फुर्ती परीक्षा और एक एंडोर्समेंट परीक्षा","एक नियोक्ता रोड टेस्ट और एक संघीय परीक्षा"],"explanation":"N.C. CDL Manual (Section 1.1) बताता है कि CDL या CLP प्राप्त करने के लिए आपको ज्ञान परीक्षाएं और कौशल परीक्षाएं पास करनी होंगी। कौशल परीक्षा उस वर्ग के वाहन में दी जाती है जिसके लिए आप लाइसेंस प्राप्त करना चाहते हैं। स्रोत: N.C. CDL Manual, Section 1.1।"},"82":{"q":"नॉर्थ कैरोलाइना CDL कौशल परीक्षा (skills test) में कौन-से तीन भाग होते हैं?","options":["लिखित ज्ञान, दृष्टि जांच, और एक रोड टेस्ट","एयर ब्रेक जांच, कपलिंग टेस्ट, और एक राजमार्ग टेस्ट","वाहन (पूर्व-यात्रा) निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क-पर ड्राइविंग","बैकिंग, समानांतर पार्किंग, और एक रात-ड्राइविंग टेस्ट"],"explanation":"N.C. CDL Manual (Section 1.1.2) के अनुसार, कौशल परीक्षा के तीन भाग होते हैं: वाहन (पूर्व-यात्रा) निरीक्षण परीक्षा, बुनियादी वाहन नियंत्रण परीक्षा, और सड़क-पर ड्राइविंग परीक्षा। तीनों को वाहन के उपयुक्त वर्ग में पास करना होता है। स्रोत: N.C. CDL Manual, Section 1.1.2।"},"83":{"q":"वर्ग या एंडोर्समेंट चाहे जो भी हो, हर नॉर्थ कैरोलाइना CDL आवेदक को कौन-सी ज्ञान परीक्षा देनी होती है?","options":["सामान्य ज्ञान परीक्षा (general knowledge test)","संयोजन वाहन परीक्षा (combination vehicles test)","एयर ब्रेक परीक्षा (air brakes test)","खतरनाक सामग्री परीक्षा (hazardous materials test)"],"explanation":"N.C. CDL Manual (Section 1.1.1) बताता है कि सामान्य ज्ञान परीक्षा सभी आवेदकों द्वारा दी जाती है। अन्य परीक्षाएं (संयोजन, एयर ब्रेक, हैज़मैट, आदि) केवल विशिष्ट वर्गों या एंडोर्समेंट पर लागू होती हैं। स्रोत: N.C. CDL Manual, Section 1.1.1।"},"84":{"q":"प्रत्येक नॉर्थ कैरोलाइना CDL ज्ञान परीक्षा पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["70% सही","80% सही","75% सही","85% सही"],"explanation":"नॉर्थ कैरोलाइना प्रत्येक CDL ज्ञान परीक्षा पर कम से कम 80% सही होना आवश्यक करता है (उदाहरण के लिए, सामान्य ज्ञान परीक्षा पर 50 में से 40, संयोजन या एयर ब्रेक पर 20 में से 16), जिन्हें अलग-अलग अंकित किया जाता है। स्रोत: NCDMV CDL knowledge testing standards (N.C. द्वारा अपनाया गया FMCSA न्यूनतम)।"},"85":{"q":"नॉर्थ कैरोलाइना वाणिज्यिक शिक्षार्थी परमिट (CLP) कितने समय तक वैध रहता है?","options":["30 दिन, बिना किसी नवीनीकरण की अनुमति के","180 दिन, अतिरिक्त 180 दिनों के लिए एक नवीनीकरण के साथ","1 वर्ष, असीमित नवीनीकरण के साथ","60 दिन, 60 दिनों के लिए एक बार नवीनीकरण योग्य"],"explanation":"एक नॉर्थ कैरोलाइना CLP 180 दिनों के लिए वैध होता है और सामान्य ज्ञान परीक्षा दोबारा दिए बिना अतिरिक्त 180 दिनों के लिए एक बार नवीनीकृत किया जा सकता है। स्रोत: NCDMV Commercial Driver License page; N.C. CDL Manual (CLP), 49 CFR 383.25 के अनुरूप।"},"86":{"q":"नॉर्थ कैरोलाइना CLP जारी होने के बाद, एक आवेदक को CDL कौशल परीक्षा देने से पहले कितने समय तक प्रतीक्षा करनी होती है?","options":["कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन","कम से कम 14 दिन"],"explanation":"एक CLP धारक को CDL कौशल परीक्षा देने से पहले CLP जारी होने के बाद कम से कम 14 दिन प्रतीक्षा करनी होती है। यह संघीय नियम (49 CFR 383.25) NCDMV द्वारा लागू किया जाता है। स्रोत: NCDMV Commercial Driver License page; 49 CFR 383.25।"},"87":{"q":"किसी पहली-बार के नॉर्थ कैरोलाइना Class A या Class B आवेदक के CDL कौशल परीक्षा देने से पहले, कौन-सा संघीय प्रशिक्षण पूरा होना चाहिए?","options":["किसी NCDMV कार्यालय में राज्य-संचालित बचावात्मक ड्राइविंग पाठ्यक्रम","किसी भी लाइसेंस प्राप्त CDL धारक के साथ दर्ज 120 घंटे का स्टीयरिंग-के-पीछे का समय","FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT)","एक OSHA कार्यस्थल सुरक्षा प्रमाणन"],"explanation":"किसी पहली-बार के Class A/B CDL के लिए परीक्षण से पहले (और P, S, व H एंडोर्समेंट या B-से-A उन्नयन के लिए) FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता के माध्यम से संघीय एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) पूरी होनी चाहिए। स्रोत: NCDMV CDL page; FMCSA ELDT rule (49 CFR Part 380)।"},"88":{"q":"पहली-बार के Class A और Class B आवेदकों के अलावा, ELDT किन एंडोर्समेंट के लिए परीक्षण से पहले भी आवश्यक है?","options":["टैंक (N), डबल्स/ट्रिपल्स (T), और एयर ब्रेक","संयोजन, एयर ब्रेक, और टैंक (N)","यात्री (P), स्कूल बस (S), और खतरनाक सामग्री (H)","केवल खतरनाक सामग्री (H)"],"explanation":"ELDT पहली-बार के Class A/B जारी करने से पहले, एक B-से-A उन्नयन, और यात्री (P), स्कूल बस (S), व खतरनाक सामग्री (H) एंडोर्समेंट से पहले लागू होता है। H एंडोर्समेंट के लिए केवल-सिद्धांत (theory-only) ELDT आवश्यक है। स्रोत: NCDMV CDL page; FMCSA ELDT rule (49 CFR Part 380)।"},"89":{"q":"नॉर्थ कैरोलाइना CDL आवेदकों को अपने वाणिज्यिक ड्राइविंग के प्रकार को स्वयं-प्रमाणित (self-certify) करना होता है। स्वयं-प्रमाणन की कितनी श्रेणियां होती हैं?","options":["चार","दो","तीन","पांच"],"explanation":"स्वयं-प्रमाणन की चार श्रेणियां होती हैं: अंतरराज्यीय गैर-अपवादित (interstate non-excepted), अंतरराज्यीय अपवादित (interstate excepted), राज्यांतरिक गैर-अपवादित (intrastate non-excepted), और राज्यांतरिक अपवादित (intrastate excepted)। आवेदक उस बॉक्स पर निशान लगाता है जो उसके संचालन से मेल खाता हो। स्रोत: N.C. CDL Manual, Section 1.2.3।"},"90":{"q":"नॉर्थ कैरोलाइना की कौन-सी स्वयं-प्रमाणन श्रेणी में चालक को एक संघीय DOT चिकित्सा परीक्षक प्रमाणपत्र (medical examiner's certificate) प्रदान करना और बनाए रखना आवश्यक है?","options":["अंतरराज्यीय अपवादित (Interstate excepted)","अंतरराज्यीय गैर-अपवादित (Interstate non-excepted)","राज्यांतरिक अपवादित (Intrastate excepted)","अपवादित निजी यात्री (Excepted private passenger)"],"explanation":"एक अंतरराज्यीय गैर-अपवादित चालक प्रमाणित करता है कि वह 49 CFR Part 391 के तहत संघीय DOT चिकित्सा आवश्यकताओं के अधीन है और उन्हें पूरा करता है, और उसे एक चिकित्सा परीक्षक प्रमाणपत्र प्राप्त करना होता है। अधिकांश अंतरराज्यीय CDL धारक गैर-अपवादित होते हैं। स्रोत: N.C. CDL Manual, Section 1.2.3।"},"91":{"q":"एक नॉर्थ कैरोलाइना चालक जो केवल अंतरराज्यीय वाणिज्य में, लेकिन विशेष रूप से 49 CFR Part 391 से अपवादित संचालन में काम करता है, उसे स्वयं को इस रूप में प्रमाणित करना चाहिए:","options":["अंतरराज्यीय गैर-अपवादित (Interstate non-excepted)","राज्यांतरिक गैर-अपवादित (Intrastate non-excepted)","अंतरराज्यीय अपवादित (Interstate excepted)","राज्यांतरिक अपवादित (Intrastate excepted)"],"explanation":"एक अंतरराज्यीय अपवादित चालक प्रमाणित करता है कि वह अंतरराज्यीय वाणिज्य में काम करता है लेकिन विशेष रूप से 49 CFR 390.3(f), 391.2, 391.68 या 398.3 के तहत अपवादित संचालन में संलग्न है, और उसे एक चिकित्सा परीक्षक प्रमाणपत्र प्राप्त करना आवश्यक नहीं है। स्रोत: N.C. CDL Manual, Section 1.2.3।"},"92":{"q":"नॉर्थ कैरोलाइना नियमों के तहत, यदि एक चालक अंतरराज्यीय और राज्यांतरिक दोनों वाणिज्य में काम करता है, तो उसे कौन-सी श्रेणी चुननी चाहिए?","options":["राज्यांतरिक वाणिज्य (Intrastate commerce)","अंतरराज्यीय वाणिज्य (Interstate commerce) (अधिक मांग वाली श्रेणी)","जिसे वह सबसे अधिक चलाता हो","वे किसी को भी स्वतंत्र रूप से चुन सकते हैं"],"explanation":"N.C. CDL Manual (Section 1.2.1) बताता है कि अंतरराज्यीय और राज्यांतरिक दोनों वाणिज्य में काम करने वाले चालक को अंतरराज्यीय वाणिज्य चुनना चाहिए, क्योंकि इसमें सख्त योग्यता आवश्यकताएं होती हैं। स्रोत: N.C. CDL Manual, Section 1.2.1।"},"93":{"q":"अब नॉर्थ कैरोलाइना द्वारा उपयोग की जा रही FMCSA National Registry प्रक्रिया के तहत, एक गैर-अपवादित चालक का DOT चिकित्सा परीक्षक प्रमाणपत्र सामान्यतः NCDMV तक कैसे पहुंचता है?","options":["चालक को हर दो वर्ष में सीधे NCDMV को एक कागज़ी प्रति डाक से भेजनी चाहिए","नियोक्ता मेडिकल कार्ड को NCDMV मुख्यालय को फैक्स करता है","चालक का डॉक्टर परिणामों की रिपोर्ट करने के लिए NCDMV चिकित्सा इकाई को कॉल करता है","प्रमाणित चिकित्सा परीक्षक परीक्षा परिणामों को इलेक्ट्रॉनिक रूप से FMCSA National Registry को प्रस्तुत करता है, जो उन्हें NCDMV को प्रेषित करता है"],"explanation":"FMCSA National Registry / NRII प्रक्रिया (2025 में अनुपालन) के तहत, प्रमाणित चिकित्सा परीक्षक CDL/CLP परीक्षा परिणामों को इलेक्ट्रॉनिक रूप से National Registry को प्रस्तुत करते हैं, और FMCSA चिकित्सा प्रमाणन स्थिति को राज्य (NCDMV) को प्रेषित करता है। चालकों को अब NCDMV को कागज़ी कार्ड पहुंचाने की ज़रूरत नहीं है। स्रोत: FMCSA National Registry rule; NCDMV medical certification guidance।"},"94":{"q":"नॉर्थ कैरोलाइना में एक चालक की वाणिज्य श्रेणी का स्वयं-प्रमाणन इनमें से किन समयों पर आवश्यक है?","options":["केवल एक बार, जब मूल CDL पहली बार जारी किया जाता है","केवल जब चालक नियोक्ता बदलता है","CLP के लिए आवेदन करते समय, और CDL का नवीनीकरण, उन्नयन, एंडोर्समेंट जोड़ने, या स्थानांतरण करते समय","केवल जब चालक 65 वर्ष का हो जाता है"],"explanation":"चालकों को राज्य को स्वयं-प्रमाणन जानकारी CLP के लिए आवेदन करते समय, और CDL का नवीनीकरण, उन्नयन, एंडोर्समेंट जोड़ने, या स्थानांतरण करते समय प्रदान करनी होती है। स्रोत: N.C. CDL Manual, Section 1.2 (संघीय चिकित्सा प्रमाणन आवश्यकताएं)।"},"95":{"q":"नॉर्थ कैरोलाइना CDL की मानक वैधता अवधि क्या है (एक नवीनीकृत लाइसेंस के लिए, 65 से कम उम्र के चालक के लिए)?","options":["5 वर्ष","4 वर्ष","8 वर्ष","10 वर्ष"],"explanation":"N.C.G.S. 20-7 के तहत, एक नवीनीकृत वाणिज्यिक चालक लाइसेंस नवीनीकृत किए जा रहे लाइसेंस की समाप्ति तिथि के पांच वर्ष बाद समाप्त होता है। CDL ऑनलाइन नवीनीकृत नहीं किए जा सकते और इन्हें किसी NCDMV कार्यालय में व्यक्तिगत रूप से नवीनीकृत किया जाना चाहिए। स्रोत: N.C.G.S. 20-7; NCDMV license renewal page।"},"96":{"q":"नॉर्थ कैरोलाइना CDL नवीनीकरण एक मानक (Class C) लाइसेंस नवीनीकरण से कैसे भिन्न है?","options":["एक CDL को समाप्ति के बाद दो वर्ष तक ऑनलाइन नवीनीकृत किया जा सकता है","एक CDL नियोक्ता के मोटर वाहक द्वारा स्वचालित रूप से नवीनीकृत हो जाता है","एक बार चालक रोड टेस्ट पास कर ले तो एक CDL कभी समाप्त नहीं होता","एक CDL को किसी NCDMV चालक लाइसेंस कार्यालय में व्यक्तिगत रूप से नवीनीकृत किया जाना चाहिए; इसे ऑनलाइन या डाक द्वारा नवीनीकृत नहीं किया जा सकता"],"explanation":"नॉर्थ कैरोलाइना CDL को किसी NCDMV चालक लाइसेंस कार्यालय में व्यक्तिगत रूप से नवीनीकृत किया जाना चाहिए और इन्हें कई मानक लाइसेंसों के विपरीत, ऑनलाइन या डाक द्वारा नवीनीकृत नहीं किया जा सकता। स्रोत: NCDMV license renewal/replacement page; N.C.G.S. 20-7।"},"97":{"q":"नॉर्थ कैरोलाइना CLP के लिए आवेदन करते समय, आवेदन के हिस्से के रूप में निम्न में से कौन-सा दस्तावेज़ आवश्यक है?","options":["पहचान/आयु का प्रमाण, सामाजिक सुरक्षा नंबर, निवास, और देयता बीमा (liability insurance) का प्रमाण","एक हाई स्कूल डिप्लोमा और एक नोटरीकृत नियोक्ता पत्र","केवल एक पासपोर्ट, बिना किसी अन्य दस्तावेज़ के","वाहन स्वामित्व का प्रमाण और एक वाहन शीर्षक (title)"],"explanation":"NCDMV एक CLP आवेदक से पहचान और आयु का प्रमाण, सामाजिक सुरक्षा नंबर का प्रमाण, दो निवास दस्तावेज़ (गैर-नागरिकों के लिए कानूनी-उपस्थिति प्रमाण), और एक नॉर्थ कैरोलाइना-लाइसेंस प्राप्त प्रदाता से देयता बीमा का प्रमाण प्रस्तुत करने की मांग करता है। स्रोत: NCDMV Commercial Driver License page।"},"98":{"q":"नॉर्थ कैरोलाइना में, एक दिन में किसी एकल CDL ज्ञान परीक्षा के कितने प्रयासों की अनुमति है?","options":["प्रति परीक्षा प्रति दिन एक प्रयास","प्रति परीक्षा प्रति दिन तीन प्रयास","एक दिन में असीमित प्रयास","प्रति परीक्षा प्रति दिन दो प्रयास"],"explanation":"N.C. CDL Manual बताता है कि प्रति दिन प्रत्येक ज्ञान परीक्षा के केवल एक प्रयास की अनुमति है। सामान्य ज्ञान परीक्षा में तीन असफल प्रयासों के बाद, अगले तीन प्रयासों के लिए एक और आवेदन शुल्क आवश्यक होता है। स्रोत: N.C. CDL Manual, Section 1.1।"},"99":{"q":"एक बार पास हो जाने पर, नॉर्थ कैरोलाइना CDL परीक्षा अंक NCDMV कंप्यूटर फ़ाइलों में कितने समय तक वैध रहते हैं?","options":["परीक्षा तिथि से 30 दिन","परीक्षा तिथि से 180 दिन","परीक्षा तिथि से 1 वर्ष","परीक्षा तिथि से 90 दिन"],"explanation":"N.C. CDL Manual में उल्लेख है कि सभी परीक्षा अंक NCDMV कंप्यूटर फ़ाइलों में परीक्षा तिथि से 90 दिनों के लिए वैध रहते हैं। एक आवेदक को उस अवधि के भीतर शेष आवश्यकताएं पूरी करनी होती हैं। स्रोत: N.C. CDL Manual, Section 1.1।"}},"ar":{"0":{"q":"على الطرق السريعة في نورث كارولينا، ما هو أقصى عرض قانوني للمركبة التجارية أو حمولتها بدون تصريح للحجم الزائد؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"تحدد نورث كارولينا إجمالي العرض الخارجي للمركبة أو حمولتها بـ 102 inches (8 feet 6 inches) على جميع الطرق؛ وأي شيء أعرض من ذلك يتطلب تصريحاً. المصدر: N.C. Gen. Stat. 20-116(a) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"1":{"q":"ما هو أقصى ارتفاع قانوني للمركبة على الطرق السريعة في نورث كارولينا بدون تصريح؟","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"يحدد قانون نورث كارولينا أقصى ارتفاع للمركبة، فارغة أو محمّلة، بـ 14 feet. المصدر: N.C. Gen. Stat. 20-116(c) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"2":{"q":"في نورث كارولينا، ما هو أقصى وزن إجمالي مسموح به على محور مفرد؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","25,000 pounds"],"explanation":"تحدد نورث كارولينا الحد الأقصى لوزن المحور المفرد بـ 20,000 pounds، بما يتطابق مع المعيار الفيدرالي. المصدر: N.C. Gen. Stat. 20-118(b)(1) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"3":{"q":"في نورث كارولينا، ما هو أقصى وزن إجمالي مسموح به على محور مزدوج (tandem)؟","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"تحدد نورث كارولينا الحد الأقصى للمحور المزدوج بـ 38,000 pounds (الحد الفيدرالي هو 34,000؛ والرقم القانوني في نورث كارولينا هو 38,000). المصدر: N.C. Gen. Stat. 20-118(b)(2) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"4":{"q":"ما هو أقصى طول إجمالي لمركبة مفردة (ذات محورين أو أكثر) في نورث كارولينا بدون تصريح؟","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"لا يجوز أن يتجاوز طول المركبة المفردة ذات المحورين أو أكثر 40 feet إجمالاً، بما في ذلك المصدّات الأمامية والخلفية. المصدر: N.C. Gen. Stat. 20-116(d)(1) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"5":{"q":"ما هو الحد الأقصى العام للطول لتركيبة من مركبتين موصولتين معاً في نورث كارولينا؟","options":["55 feet","60 feet","65 feet","75 feet"],"explanation":"لا يجوز أن تتجاوز أي تركيبة من مركبتين طولاً إجمالياً قدره 60 feet بما في ذلك المصدّات الأمامية والخلفية، باستثناء ما هو منصوص عليه بخلاف ذلك. المصدر: N.C. Gen. Stat. 20-116(e) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"6":{"q":"في نورث كارولينا، تُعفى القاطرة الشاحنة التي تجر نصف مقطورة واحدة من حد طول التركيبة البالغ 60-foot طالما أن نصف المقطورة لا يتجاوز أي طول؟","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"يجوز للقاطرة الشاحنة (وحدة القدرة) التي تجر نصف مقطورة واحدة بطول لا يزيد عن 53 feet أن تتجاوز الحد الأقصى الإجمالي البالغ 60-foot على جميع الطرق في نورث كارولينا. المصدر: N.C. Gen. Stat. 20-116(e) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"7":{"q":"ما هو أقصى وزن إجمالي للمركبة لقاطرة ونصف مقطورة نموذجية بخمسة محاور على الطرق السريعة في نورث كارولينا بدون تصريح للوزن الزائد؟","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"أقصى وزن إجمالي للمركبة في نورث كارولينا هو 80,000 pounds، خاضعاً لحدود المحور وصيغة الجسر (bridge formula). المصدر: N.C. Gen. Stat. 20-118 ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"8":{"q":"كيف تحدد نورث كارولينا الوزن الإجمالي المسموح به بناءً على تباعد المحاور على طرقها السريعة؟","options":["بمضاعِف ثابت لكل محور تحدده المقاطعة","بصيغة الجسر الفيدرالية (federal bridge formula) بناءً على قياس المحور الأقصى","بمعدل وزن المركبة الإجمالي (GVWR) من الشركة المصنّعة فقط","بعدد الإطارات الملامسة للطريق"],"explanation":"يُحدَّد الوزن الإجمالي بناءً على قياس المحور الأقصى وفق صيغة الجسر الفيدرالية (قانون الجسر). ينطبق بدل 23 U.S.C. 127 على جميع طرق الولاية ما لم يكن هناك تحديد مُعلَن. المصدر: N.C. Gen. Stat. 20-118(c)(19) ودليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"9":{"q":"أي جهة في نورث كارولينا تصدر تصاريح الحجم الزائد/الوزن الزائد للمركبات التي تتجاوز الحدود القانونية للحجم أو الوزن؟","options":["شعبة المركبات الآلية في نورث كارولينا (DMV)","وحدة تصاريح الحجم الزائد/الوزن الزائد التابعة لإدارة النقل في نورث كارولينا (NCDOT)","دورية الطرق السريعة بولاية نورث كارولينا","مكتب مأمور المقاطعة التي تبدأ منها الرحلة"],"explanation":"تُصدِر تصاريح الحجم الزائد/الوزن الزائد وحدةُ تصاريح الحجم الزائد/الوزن الزائد التابعة لـ NCDOT (مكتب التصاريح المركزي في Garner, NC). المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT."},"10":{"q":"كم مدة صلاحية تصريح الرحلة الواحدة للحجم الزائد/الوزن الزائد في نورث كارولينا؟","options":["5 calendar days لرحلة واحدة","10 calendar days لرحلة واحدة منفردة","30 calendar days لرحلة واحدة","سنة واحدة من تاريخ السريان"],"explanation":"يكون تصريح الرحلة الواحدة صالحاً لمدة 10 calendar days لرحلة واحدة منفردة؛ وتتراوح رسوم الولاية من $12 إلى $48. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (تصريح الرحلة الواحدة)."},"11":{"q":"بموجب تصريح الرحلة الواحدة في نورث كارولينا، ما هو أقصى وزن مسموح به على مجموعة محاور مزدوجة (أوزان المحاور، وليس الوزن الإجمالي)؟","options":["44,000 pounds","46,000 pounds","50,000 pounds","60,000 pounds"],"explanation":"بموجب تصريح الرحلة الواحدة، تكون أوزان المحاور المسموح بها كالتالي: محور التوجيه 20,000؛ المفرد 25,000؛ المزدوج 50,000؛ الثلاثي 60,000؛ ومجموعة أربعة محاور أو أكثر 68,000 pounds. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (أوزان محاور تصريح الرحلة الواحدة)."},"12":{"q":"للتأهل لتصريح الوزن الزائد في نورث كارولينا الذي يسمح بنقل حمولة تصل إلى 90,000 pounds لقطعة واحدة، يجب أن يكون لدى المركبة عموماً على الأقل أي حد أدنى من قاعدة العجلات (wheelbase)؟","options":["قاعدة عجلات 41-foot","قاعدة عجلات 48-foot","قاعدة عجلات 51-foot","قاعدة عجلات 57-foot"],"explanation":"يمكن لتركيبة مركبات ذات قاعدة عجلات لا تقل عن 51-foot التأهل للنقل حتى 90,000 pounds؛ وما يزيد عن 90,000 pounds يكون التصريح محدداً بمسار معين. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (التصريح السنوي / الوزن الزائد)."},"13":{"q":"في نورث كارولينا، تُصنَّف الحمولة التي تتجاوز أي وزن إجمالي على أنها 'حمولة فائقة' (superload) تتطلب طلباً خطياً للحمولة الفائقة ومراجعة هندسية للجسور؟","options":["الوزن الإجمالي يتجاوز 90,000 pounds","الوزن الإجمالي يتجاوز 112,000 pounds","الوزن الإجمالي يتجاوز 122,000 pounds","الوزن الإجمالي يتجاوز 132,000 pounds"],"explanation":"يُطلَب تصريح الحمولة الفائقة عندما يتجاوز الوزن الإجمالي 132,000 pounds (أو يتجاوز وزن محور التوجيه 20,000 pounds، أو يتجاوز العرض 16 feet). ويحمل رسم طلب غير قابل للاسترداد قدره $100 بالإضافة إلى رسوم إضافية. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (تصريح الحمولة الفائقة)."},"14":{"q":"عندما يكون لحمولة مصرّح بها في نورث كارولينا بروز خلفي يزيد عن 4 feet، ماذا يجب عرضه للسفر النهاري؟","options":["ضوء كهرماني وامض في الخلف","علم أحمر مربع بحجم 18-inch-square","لافتة 'WIDE LOAD'","عاكس مثلث أحمر"],"explanation":"يجب أن يعرض البروز الخلفي الذي يزيد عن 4 feet علماً أحمر مربعاً بحجم 18-inch-square للسفر النهاري وأضواء تحديد ليلاً؛ ولا يجوز أن تمتد الحمولة أكثر من 14 feet خلف مؤخرة المركبة، والحد الأقصى للبروز هو 14 feet. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (البروز)."},"15":{"q":"على تصريح في نورث كارولينا، يجب أن تكون أعلام التحذير التي تحدد أعرض نقطة في حمولة زائدة العرض بأي حجم ولون؟","options":["12 inches square، أصفر","16 inches square، برتقالي فقط","18 inches square، أحمر أو برتقالي","24 inches square، أحمر فقط"],"explanation":"يجب أن تكون الأعلام بحجم 18 inches square، باللون الأحمر أو البرتقالي، موضوعة عند أعرض نقطة من الحمولة زائدة العرض أو وفقاً لما هو محدد في التصريح. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (الأعلام)."},"16":{"q":"على طريق سريع ثنائي المسار وذي اتجاهين في نورث كارولينا، يُطلَب عموماً مركبة مرافقة أمامية عندما تتجاوز الحمولة المصرّح بها أي عرض؟","options":["بعرض 10 feet","بعرض 12 feet","بعرض 14 feet","بعرض 16 feet"],"explanation":"يُطلَب مرافق أمامي للحمولات المصرّح بها التي يزيد عرضها عن 12 feet على الطرق السريعة الثنائية المسار وذات الاتجاهين، مع مرافق خلفي على الطرق السريعة متعددة المسارات أو وفقاً لما هو منصوص عليه في التصريح. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (المرافقون)."},"17":{"q":"بموجب قواعد التصاريح في نورث كارولينا، يُطلَب مرافق أمامي لأي حمولة مصرّح بها يزيد وزنها عن أي حد؟","options":["أكثر من 80,000 pounds","أكثر من 112,000 pounds","أكثر من 132,000 pounds","أكثر من 149,999 pounds"],"explanation":"يُطلَب مرافق أمامي للوزن الذي يزيد عن 149,999 pounds؛ ويُطلَب مرافقان أمامي وخلفي للطول الإجمالي البالغ 150 feet أو أكثر. المصدر: دليل تصاريح الحجم الزائد/الوزن الزائد التابع لـ NCDOT (المرافقون)."},"18":{"q":"يوفر قانون نورث كارولينا تبايناً أعلى في الوزن خارج الطرق السريعة الفيدرالية (Interstate) للمنتجات الزراعية ومنتجات الغابات. ما هو حد المحور المفرد المرتفع بموجب هذا التباين؟","options":["20,000 pounds","21,500 pounds","22,000 pounds","26,000 pounds"],"explanation":"بالنسبة للمنتجات الزراعية ومنتجات الغابات المؤهلة المنقولة خارج نظام الطرق السريعة الفيدرالية (Interstate)، تسمح نورث كارولينا بما يصل إلى 22,000 pounds للمحور المفرد، و42,000 pounds للمحور المزدوج، و90,000 pounds للوزن الإجمالي. المصدر: N.C. Gen. Stat. 20-118(c)(12)."},"19":{"q":"ينطبق بدل تسامح الوزن البالغ 10 في المئة في نورث كارولينا على أي من الحدود؟","options":["حدود المحور المفرد والمحور المزدوج","حد الوزن الإجمالي البالغ 80,000-pound وحدود محاور الطرق الفيدرالية (Interstate)","أوزان مجموعة المحاور فقط، باستثناء المحاور المفردة/المزدوجة، والحد الأقصى للوزن الإجمالي البالغ 80,000-pound، والجسور المُعلَن عنها، والطرق الفيدرالية (Interstates)","جميع حدود وزن الجسور المُعلَن عنها على مستوى الولاية"],"explanation":"ينطبق تسامح الـ 10 في المئة على أوزان مجموعة المحاور (صيغة الجسر) فقط؛ ولا ينطبق على حدود المحور المفرد أو المحور المزدوج، أو الحد الأقصى للوزن الإجمالي البالغ 80,000-pound، أو الجسور المُعلَن عنها، أو الطرق السريعة الفيدرالية (Interstate). المصدر: N.C. Gen. Stat. 20-118(h)."},"20":{"q":"في نورث كارولينا، أي فئة من رخص القيادة التجارية (CDL) مطلوبة لتشغيل تركيبة من المركبات بمعدل وزن إجمالي للمركبة (GVWR) قدره 26,001 pounds أو أكثر، شريطة أن يكون للمركبة المقطورة معدل GVWR يزيد عن 10,000 pounds؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تتبع نورث كارولينا التصنيف الفيدرالي: تُطلَب رخصة CDL من الفئة A لأي تركيبة من المركبات بمعدل GVWR قدره 26,001 lbs أو أكثر حيث تتجاوز الوحدة (الوحدات) المقطورة 10,000 lbs من GVWR. المصدر: صفحة رخصة القيادة التجارية في NCDMV ودليل رخصة القيادة التجارية في نورث كارولينا."},"21":{"q":"بموجب قواعد نورث كارولينا، مركبة مفردة بمعدل GVWR قدره 26,001 pounds أو أكثر، تقطر وحدة لا تتجاوز 10,000 pounds من GVWR، تتطلب أي فئة من CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"تغطي رخصة CDL من الفئة B مركبة مفردة مصنّفة بـ 26,001 lbs من GVWR أو أكثر، بالإضافة إلى أي مركبة مقطورة لا تتجاوز 10,000 lbs من GVWR. المصدر: صفحة رخصة القيادة التجارية في NCDMV ودليل CDL في نورث كارولينا."},"22":{"q":"أي فئة من CDL في نورث كارولينا تنطبق على مركبة لا تستوفي حدود وزن الفئة A أو B ولكنها مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق) أو تحمل مواد خطرة تتطلب لافتات (placards)؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"في نورث كارولينا تُطلَب رخصة CDL من الفئة C للمركبات التي لا تستوفي الفئة A أو B والمصممة لنقل 16 شخصاً أو أكثر (بما في ذلك السائق) أو التي تنقل مواد خطرة تتطلب لافتات (placards). المصدر: صفحة رخصة القيادة التجارية في NCDMV ودليل CDL في نورث كارولينا."},"23":{"q":"في نورث كارولينا، ما هو الحد الأدنى للعمر للحصول على رخصة CDL مقيدة بالقيادة التجارية داخل الولاية (intrastate) فقط؟","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"تسمح نورث كارولينا برخصة CDL عند سن 18 للتشغيل داخل الولاية (intrastate) فقط. يجب أن يكون عمر السائقين 21 للتجارة بين الولايات (interstate) أو لنقل المواد الخطرة. المصدر: متطلبات رخصة القيادة التجارية في NCDMV؛ N.C.G.S. Chapter 20, Article 2C."},"24":{"q":"كم يجب أن يكون عمر السائق في نورث كارولينا على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات (interstate) أو لحمل تظهير المواد الخطرة؟","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"تتطلب نورث كارولينا حداً أدنى للعمر قدره 21 للقيادة التجارية بين الولايات (interstate) ولتظهير المواد الخطرة (H)؛ و18 هو الحد الأدنى للتشغيل داخل الولاية (intrastate) فقط. المصدر: متطلبات رخصة القيادة التجارية في NCDMV؛ N.C.G.S. Chapter 20, Article 2C."},"25":{"q":"أي تظهير يحتاجه حامل رخصة CDL في نورث كارولينا لنقل المواد الخطرة بكميات تتطلب لافتات (placards)؟","options":["تظهير N","تظهير H","تظهير T","تظهير P"],"explanation":"يُطلَب تظهير H (المواد الخطرة - HazMat) لنقل كميات من المواد الخطرة تتطلب لافتات (placards). ويتطلب اختبار معرفة بالإضافة إلى تقييم تهديد أمني من TSA. المصدر: تظهيرات CDL في NCDMV؛ 49 CFR 383.93."},"26":{"q":"في نورث كارولينا، أي تظهير مطلوب لقيادة مركبة صهريج مصممة لحمل حمولة سائلة أو غازية في خزان بسعة لا تقل عن 1,000 gallons؟","options":["تظهير H","تظهير T","تظهير N","تظهير X"],"explanation":"يُطلَب تظهير N (مركبة الصهريج - Tank Vehicle) لمركبات الصهريج ذات السعة المصنّفة الفردية البالغة 1,000 gallons أو أكثر التي تحمل سوائل أو غازات. المصدر: تظهيرات CDL في NCDMV؛ دليل CDL في نورث كارولينا؛ 49 CFR 383.5/383.93."},"27":{"q":"سائق CDL في نورث كارولينا الذي يجر تركيبات مقطورات مزدوجة أو ثلاثية يجب أن يحمل أي تظهير؟","options":["تظهير T","تظهير N","تظهير P","تظهير S"],"explanation":"يُجيز تظهير T تشغيل تركيبات المقطورات المزدوجة والثلاثية. ويُحصَل عليه باجتياز اختبار معرفة؛ ولا يُطلَب اختبار مهارات منفصل. المصدر: تظهيرات CDL في NCDMV؛ دليل CDL في نورث كارولينا."},"28":{"q":"أي تظهير مدمج يظهر على رخصة CDL في نورث كارولينا عندما يكون السائق مخوّلاً بتشغيل مركبة صهريج تحمل أيضاً مواد خطرة؟","options":["تظهير HT","تظهير X","تظهير NP","تظهير Z"],"explanation":"تُصدِر نورث كارولينا تظهير X لتمثيل الجمع بين تظهير الصهريج (N) وتظهير المواد الخطرة (H) على رخصة CDL واحدة. المصدر: تظهيرات/قيود CDL في NCDMV."},"29":{"q":"في نورث كارولينا، أي تظهيرات CDL تتطلب اجتياز اختبار مهارات خلف عجلة القيادة (SKILLS test) (وليس مجرد اختبار معرفة)؟","options":["H و N","N و T","P و S","H و T"],"explanation":"يتطلب تظهير الركاب (P) وتظهير الحافلة المدرسية (S) اختبار مهارات/طريق في المركبة المناسبة، بينما يُحصَل على H و N و T باختبارات معرفة فقط. المصدر: تظهيرات CDL في NCDMV؛ دليل CDL في نورث كارولينا."},"30":{"q":"قبل أن يتمكن مقدّم الطلب في نورث كارولينا من الحصول على تظهير الحافلة المدرسية (S)، أي تظهير آخر يجب أن يحمله أولاً؟","options":["H (المواد الخطرة - HazMat)","N (الصهريج)","T (المزدوجات/الثلاثيات)","P (الركاب)"],"explanation":"بموجب القواعد الفيدرالية وقواعد نورث كارولينا، يتطلب تظهير الحافلة المدرسية (S) أن يكون السائق مؤهلاً أولاً لتظهير الركاب (P). المصدر: تظهيرات CDL في NCDMV؛ 49 CFR 383.93(b)."},"31":{"q":"كم مدة صلاحية تصريح المتعلم التجاري (CLP) في نورث كارولينا قبل أن يجب تجديده؟","options":["90 days","180 days","سنة واحدة","30 days"],"explanation":"يكون CLP في نورث كارولينا صالحاً لمدة 180 days ويمكن تجديده مرة واحدة لمدة إضافية قدرها 180 days بدون إعادة اجتياز اختبار المعرفة العامة. المصدر: صفحة رخصة القيادة التجارية في NCDMV؛ 49 CFR 383.25."},"32":{"q":"بموجب القواعد الفيدرالية المعتمدة من نورث كارولينا، ما هو الحد الأدنى للمدة التي يجب أن يحمل فيها مقدّم طلب CDL تصريح المتعلم التجاري قبل خوض اختبار مهارات CDL (الطريق)؟","options":["7 days","14 days","30 days","60 days"],"explanation":"يجب أن يحمل مقدّم الطلب CLP لمدة لا تقل عن 14 days قبل السماح له بخوض اختبار مهارات CDL. وتطبّق نورث كارولينا هذا المتطلب الفيدرالي. المصدر: صفحة CDL في NCDMV؛ 49 CFR 383.25(e)."},"33":{"q":"عند التشغيل بموجب تصريح المتعلم التجاري في نورث كارولينا، يجب أن يكون حامل CLP مصحوباً بشخص يحمل أي اعتماد؟","options":["أي رخصة قيادة سارية من الفئة C","رخصة CDL سارية من نفس الفئة أو فئة أعلى مع التظهيرات المناسبة","تصريح تعليم من نورث كارولينا","لا يُطلَب سائق مرافق"],"explanation":"يجب أن يكون حامل CLP مصحوباً دائماً بشخص يحمل رخصة CDL سارية من الفئة والتظهيرات المناسبة، جالساً في المقعد الأمامي. المصدر: صفحة CDL في NCDMV؛ 49 CFR 383.25."},"34":{"q":"أي متطلب لتدريب السائق المبتدئ (ELDT) ينطبق في نورث كارولينا على شخص يحصل على رخصة CDL لأول مرة؟","options":["تدريب من أي مدرّب خاص يختاره السائق","تدريب من مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA","فقط دورة فيديو عبر الإنترنت معتمدة من NCDMV","لا يُطلَب تدريب رسمي، فقط الاختبارات"],"explanation":"منذ Feb. 7, 2022، يجب على مقدّمي طلبات CDL لأول مرة (والذين يرفّعون من B إلى A أو يسعون للحصول على تظهيرات P أو S أو H) إكمال ELDT من مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل الاختبار. المصدر: قاعدة ELDT التابعة لـ FMCSA؛ صفحة CDL في NCDMV."},"35":{"q":"بالنسبة لتظهير المواد الخطرة (H) في نورث كارولينا، أي نوع من ELDT يجب إكماله ومتى؟","options":["تدريب نظري فقط قبل اختبار المعرفة","تدريب خلف عجلة القيادة قبل اختبار المهارات","كلا التدريب النظري وخلف عجلة القيادة قبل اختبار الطريق","لا يُطلَب ELDT للمواد الخطرة"],"explanation":"ELDT لتظهير H هو تدريب نظري (معرفة) فقط، يُكمَل من خلال مزوّد في سجل مزوّدي التدريب قبل اختبار المعرفة التابع للولاية؛ ولا يوجد مكوّن خلف عجلة القيادة لـ H. المصدر: قاعدة ELDT التابعة لـ FMCSA (49 CFR Part 380, Subpart F)."},"36":{"q":"بالإضافة إلى اجتياز اختبار المعرفة، ماذا تتطلب نورث كارولينا قبل إصدار تظهير المواد الخطرة (H)؟","options":["إعفاء من فحص النظر من NCDMV","تقييم تهديد أمني من TSA يشمل البصمات","خمس سنوات من خبرة القيادة","اختبار مهارات منفصل خلف عجلة القيادة"],"explanation":"يتطلب تظهير H فحص خلفية ضمن برنامج تقييم تهديد تظهير المواد الخطرة التابع لـ TSA مع البصمات؛ ويُجدَّد التظهير عموماً كل خمس سنوات. المصدر: صفحة CDL في NCDMV؛ برنامج HME التابع لـ TSA؛ 49 CFR 1572."},"37":{"q":"عند التقدم بطلب للحصول على رخصة CDL في نورث كارولينا، أي مجموعة من المستندات يجب على مقدّم الطلب تقديمها؟","options":["فقط بطاقة الضمان الاجتماعي","إثبات الهوية/العمر، ورقم الضمان الاجتماعي، والإقامة في نورث كارولينا، والوجود القانوني","جواز سفر ولا شيء آخر","فقط إثبات تأمين المسؤولية"],"explanation":"تتطلب NCDMV توثيق الهوية/تاريخ الميلاد، ورقم الضمان الاجتماعي، والإقامة في نورث كارولينا، والوجود القانوني (الجنسية الأمريكية أو الوضع القانوني)، بالإضافة إلى إثبات تأمين المسؤولية. المصدر: متطلبات مستندات رخصة القيادة التجارية في NCDMV."},"38":{"q":"كم عدد فئات التصديق الذاتي الطبي التي يجب على مقدّم طلب CDL في نورث كارولينا الاختيار من بينها عند التصديق على نوع العملية التجارية التي يؤديها؟","options":["اثنتان","ثلاث","أربع","خمس"],"explanation":"يصدّق حاملو رخص CDL في نورث كارولينا ذاتياً ضمن واحدة من أربع فئات: بين الولايات غير مستثناة، بين الولايات مستثناة، داخل الولاية غير مستثناة، أو داخل الولاية مستثناة. المصدر: التصديق الذاتي الطبي لـ CDL في NCDMV (Form CDL-MED-1)."},"39":{"q":"أي فئة تصديق ذاتي لرخصة CDL في نورث كارولينا تتطلب من السائق الاحتفاظ بشهادة فاحص طبي سارية مسجّلة لدى NCDMV؟","options":["بين الولايات مستثناة","بين الولايات غير مستثناة","داخل الولاية مستثناة","لا توجد فئة تتطلب شهادة طبية"],"explanation":"السائق الذي يصدّق على أنه بين الولايات غير مستثنى يخضع لـ 49 CFR Part 391 ويجب أن يحصل ويحتفظ بشهادة فاحص طبي لدى NCDMV؛ والفئات المستثناة غير مطالبة بذلك. المصدر: التصديق الذاتي لـ CDL في NCDMV؛ 49 CFR 391.41 / 383.71."},"40":{"q":"في نورث كارولينا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده لشخص أن يشغّل قانونياً مركبة آلية تجارية؟","options":["0.02","0.04","0.08","0.10"],"explanation":"تحدد نورث كارولينا عتبة الضعف للمركبة الآلية التجارية بـ 0.04 BAC بموجب G.S. 20-138.2، أي نصف حد الـ 0.08 للسائقين العاديين. ويدرج دليل CDL في نورث كارولينا قيادة مركبة آلية تجارية بـ BAC قدره 0.04 أو أكثر كمخالفة كبرى."},"41":{"q":"بالنسبة لأول مخالفة كبرى (مثل القيادة تحت تأثير الكحول DWI أو BAC قدره 0.04+) ارتُكبت في مركبة لا تحمل مواد خطرة تتطلب لافتات (placards)، كم مدة فقدان أهلية حامل رخصة CDL في نورث كارولينا؟","options":["60 days","120 days","سنة واحدة","3 years"],"explanation":"بموجب G.S. 20-17.4 ودليل CDL في نورث كارولينا (الذي يعكس 49 CFR 383.51)، تُفقِد المخالفة الكبرى الأولى السائق الأهلية لمدة لا تقل عن سنة واحدة عندما لا تكون هناك مواد خطرة تتطلب لافتات (placards)."},"42":{"q":"إذا ارتكب حامل رخصة CDL في نورث كارولينا أول مخالفة كبرى أثناء تشغيل مركبة تحمل لافتات (placards) للمواد الخطرة، فإلى أي مدة تزداد فترة فقدان الأهلية؟","options":["سنة واحدة","2 years","3 years","5 years"],"explanation":"ينص G.S. 20-17.4 ودليل CDL في نورث كارولينا على أن أول مخالفة كبرى أثناء نقل مواد خطرة تحمل لافتات (placards) تؤدي إلى فقدان الأهلية لمدة 3 years بدلاً من السنة الواحدة القياسية."},"43":{"q":"بموجب قانون نورث كارولينا، ما هو فقدان الأهلية لحامل رخصة CDL المُدان بمخالفة كبرى ثانية (DWI ثانية، أو رفض، أو ما شابه) ناشئة عن حادثة منفصلة؟","options":["3 years","5 years","10 years","مدى الحياة"],"explanation":"يفرض G.S. 20-17.4 ودليل CDL في نورث كارولينا فقدان أهلية CDL مدى الحياة لمخالفة كبرى ثانية ناشئة عن حادثة منفصلة. وقد تكون إعادة الإصدار المحدودة ممكنة بعد 10 years في بعض الحالات، لكن فقدان الأهلية نفسه يكون مدى الحياة."},"44":{"q":"يُوقَف حامل رخصة CDL في نورث كارولينا بتهمة القيادة تحت تأثير الكحول في مركبة آلية تجارية ويرفض الخضوع لاختبار كيميائي (نَفَس أو دم). كيف يُعامَل الرفض لأغراض فقدان أهلية CDL؟","options":["لا يحمل عقوبة على CDL، فقط عقوبة على الرخصة الشخصية","يُعتبر مخالفة مرورية خطيرة (فقدان أهلية لمدة 60-day)","يُعتبر مخالفة كبرى (فقدان أهلية لمدة لا تقل عن سنة واحدة)","يؤدي إلى فقدان أهلية مدى الحياة عند أول رفض"],"explanation":"بموجب قانون الموافقة الضمنية في نورث كارولينا و G.S. 20-17.4، يُعتبر رفض الاختبار الكيميائي مخالفة كبرى، تُفقِد السائق الأهلية لمدة لا تقل عن سنة واحدة (3 years إذا كان ينقل مواد خطرة تحمل لافتات placards)، مثلها مثل الإدانة."},"45":{"q":"بموجب قانون الموافقة الضمنية في نورث كارولينا، فإن سائق CDL، بتشغيله مركبة تجارية على طرق الولاية، يُعتبر قد وافق على أي مما يلي عند إيقافه بشكل قانوني بتهمة القيادة تحت التأثير؟","options":["اختبار رصانة ميداني فقط","اختبار كيميائي للنَّفَس أو الدم أو البول","تفتيش المركبة بدون أمر قضائي","تسليم رخصة CDL على الفور"],"explanation":"ينص قانون الموافقة الضمنية في نورث كارولينا (G.S. 20-16.2) على أن أي سائق يوافق ضمنياً على تحليل كيميائي للنَّفَس أو الدم أو سائل جسدي آخر عند اتهامه بمخالفة موافقة ضمنية؛ ويؤدي الرفض إلى إلغاء الرخصة وفقدان أهلية CDL."},"46":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3 years (في مركبة آلية تجارية) التي يجب أن يرتكبها حامل رخصة CDL في نورث كارولينا قبل مواجهة فقدان أهلية لمدة 60-day؟","options":["1","2","3","4"],"explanation":"يفقد G.S. 20-17.4 ودليل CDL في نورث كارولينا السائق الأهلية لمدة 60 days عند ارتكاب مخالفة مرورية خطيرة ثانية ناشئة عن حوادث منفصلة خلال 3 years."},"47":{"q":"في نورث كارولينا، تؤدي مخالفة مرورية خطيرة ثالثة خلال فترة 3 years إلى فقدان أهلية CDL لمدة كم؟","options":["60 days","120 days","180 days","سنة واحدة"],"explanation":"بموجب G.S. 20-17.4 ودليل CDL في نورث كارولينا، تؤدي مخالفة مرورية خطيرة ثالثة (حوادث منفصلة) خلال 3 years إلى فقدان أهلية لمدة 120 days، تُنفَّذ في نهاية أي فقدان أهلية سابق."},"48":{"q":"أي مما يلي يُصنَّف على أنه 'مخالفة مرورية خطيرة' لحامل رخصة CDL في نورث كارولينا؟","options":["السرعة الزائدة بمقدار 15 mph أو أكثر فوق الحد المُعلَن","مخالفة وقوف في مركبة آلية تجارية","القيادة بسرعة 5 mph فوق الحد","تسجيل مركبة منتهي الصلاحية"],"explanation":"يعرّف دليل CDL في نورث كارولينا و 49 CFR 383.51 السرعة الزائدة المفرطة (15 mph أو أكثر فوق الحد) على أنها مخالفة مرورية خطيرة. ومخالفات الوقوف والتسجيل مستثناة صراحةً من تلك الفئة."},"49":{"q":"بموجب قواعد نورث كارولينا، أي من هذه لا يُحتسَب كمخالفة مرورية خطيرة لأغراض فقدان أهلية CDL؟","options":["القيادة المتهورة","اتباع مسافة قريبة جداً","تغييرات المسار غير السليمة أو غير المنتظمة","قيادة مركبة آلية تجارية بمصباح أمامي محترق"],"explanation":"يدرج دليل CDL في نورث كارولينا القيادة المتهورة، واتباع مسافة قريبة جداً، وتغييرات المسار غير السليمة/غير المنتظمة ضمن المخالفات المرورية الخطيرة بموجب G.S. 20-17.4 / 49 CFR 383.51. أما عيب في المعدات مثل مصباح أمامي محترق فليس على تلك القائمة."},"50":{"q":"تُعامَل قيادة مركبة آلية تجارية في نورث كارولينا بدون الفئة الصحيحة من رخصة CDL أو التظهير المطلوب على أنها أي نوع من المخالفات؟","options":["مخالفة كبرى (فقدان أهلية لمدة سنة واحدة)","مخالفة مرورية خطيرة","مخالفة أمر خارج الخدمة (out-of-service)","مخالفة معدات غير قابلة للإبلاغ"],"explanation":"يدرج دليل CDL في نورث كارولينا و 49 CFR 383.51 قيادة مركبة آلية تجارية بدون الفئة الصحيحة من CDL أو التظهير (أو بدون حمل رخصة CDL) كمخالفة مرورية خطيرة، يمكن أن تؤدي إلى فقدان أهلية لمدة 60/120-day عند دمجها مع مخالفات خطيرة أخرى."},"51":{"q":"بالنسبة لحامل رخصة CDL في نورث كارولينا، تُصنَّف الكتابة النصية أثناء قيادة مركبة آلية تجارية على أنها ماذا لأغراض فقدان الأهلية؟","options":["مخالفة كبرى","مخالفة مرورية خطيرة","مخالفة أمر خارج الخدمة (out-of-service)","مخالفة معبر سكة حديد"],"explanation":"بموجب G.S. 20-137.4A ودليل CDL في نورث كارولينا (بما يتسق مع 49 CFR 383.51 و 392.80)، تُعتبر الكتابة النصية أثناء قيادة مركبة آلية تجارية مخالفة مرورية خطيرة، تسهم في فقدان أهلية لمدة 60/120-day."},"52":{"q":"يقيّد قانون نورث كارولينا استخدام سائق المركبة الآلية التجارية للهاتف المحمول أثناء القيادة بأي مما يلي؟","options":["الاستخدام دون استعمال اليدين (hands-free) فقط","الاستخدام فقط عند التوقف عند إشارة حمراء","المكالمات التي تقل عن دقيقة واحدة","استخدام أي هاتف محمول باليد للمكالمات الصوتية"],"explanation":"يحظر G.S. 20-137.4A على مشغّلي المركبات الآلية التجارية الخاضعين لـ FMCSA Parts 390/392 استخدام هاتف محمول باليد؛ ويُسمَح فقط بالتشغيل دون استعمال اليدين (hands-free). وتُعتبر مخالفة الهاتف المحمول باليد في مركبة آلية تجارية مخالفة مرورية خطيرة."},"53":{"q":"ما هي فترة فقدان الأهلية لأول إدانة لحامل رخصة CDL في نورث كارولينا بمخالفة أمر خارج الخدمة (out-of-service) أثناء تشغيل مركبة آلية تجارية (غير حاملة للمواد الخطرة)؟","options":["لا تقل عن 30 days","لا تقل عن 60 days","لا تقل عن 90 days","لا تقل عن 180 days"],"explanation":"يحدد G.S. 20-17.4 ودليل CDL في نورث كارولينا أول مخالفة لأمر خارج الخدمة بما لا يقل عن 180 days (حتى سنة واحدة) لمركبة آلية تجارية قياسية، وهو ما يفوق بكثير عقوبة معظم المخالفات الخطيرة."},"54":{"q":"إذا انتهك حامل رخصة CDL في نورث كارولينا أمراً خارج الخدمة أثناء نقل مواد خطرة تحمل لافتات (placards) أو 16+ راكباً، فإن المخالفة الأولى تحمل فقدان أهلية لمدة لا تقل عن كم؟","options":["90 days","180 days","سنة واحدة","3 years"],"explanation":"بموجب G.S. 20-17.4، تكون أول مخالفة لأمر خارج الخدمة أثناء نقل مواد خطرة تحمل لافتات (placards) أو حمل 16 راكباً أو أكثر بما لا يقل عن 180 days (وحتى 2 years)، وهو حد أقصى أطول من مخالفة أمر خارج الخدمة القياسية."},"55":{"q":"بموجب قانون نورث كارولينا، تؤدي مخالفة ثانية لأمر خارج الخدمة (out-of-service) خلال فترة 10 years إلى فقدان أهلية حامل رخصة CDL لأي حد أدنى من المدة؟","options":["180 days","سنة واحدة","2 years","5 years"],"explanation":"يفقد G.S. 20-17.4 ودليل CDL في نورث كارولينا السائق الأهلية لمدة لا تقل عن 2 years (حتى 5 years) لمخالفة ثانية لأمر خارج الخدمة خلال أي فترة 10 years."},"56":{"q":"في نورث كارولينا، ما هو فقدان الأهلية لأول مخالفة لحامل رخصة CDL عند معبر السكة الحديدية مع الطريق السريع (railroad-highway grade crossing) ارتُكبت في مركبة آلية تجارية؟","options":["لا تقل عن 30 days","لا تقل عن 60 days","لا تقل عن 120 days","لا تقل عن سنة واحدة"],"explanation":"يفرض G.S. 20-17.4 ودليل CDL في نورث كارولينا فقدان أهلية لمدة لا تقل عن 60 days لأول مخالفة عند معبر السكة الحديدية مع الطريق السريع في مركبة آلية تجارية."},"57":{"q":"يرتكب حامل رخصة CDL في نورث كارولينا مخالفة ثالثة عند معبر السكة الحديدية مع الطريق السريع (railroad-highway grade crossing) خلال فترة 3 years. ما هو فقدان الأهلية؟","options":["60 days","120 days","لا تقل عن سنة واحدة","مدى الحياة"],"explanation":"بموجب G.S. 20-17.4 ودليل CDL في نورث كارولينا، تحمل مخالفات معبر السكة الحديدية 60 days (الأولى)، و120 days (الثانية خلال 3 years)، ولا تقل عن سنة واحدة (الثالثة خلال 3 years)."},"58":{"q":"عندما يرتكب سائق CDL في نورث كارولينا مخالفة مرورية متحركة في مركبة تجارية تُحتسَب عنها نقاط، كيف تعامل المحكمة الغرامة مقارنة بسائق غير تجاري؟","options":["تُعفى الغرامة لحاملي رخص CDL","يجوز مضاعفة الغرامة","تُخفَّض الغرامة بمقدار النصف","الغرامة هي نفسها لأي سائق"],"explanation":"بموجب قانون نورث كارولينا، يجوز للمحكمة مضاعفة الغرامة لمشغّل مركبة آلية تجارية يرتكب مخالفة مركبة آلية تُحتسَب عنها نقاط، بما يعكس المعيار الأعلى المفروض على السائقين التجاريين."},"59":{"q":"عندما يرفض سائق CDL في نورث كارولينا اختباراً كيميائياً أو يسجّل 0.04 أو أكثر في مركبة آلية تجارية أثناء إيقاف بموجب الموافقة الضمنية، ما الإجراء الفوري قبل المحاكمة الذي ينطبق عادةً على رخصة قيادة السائق قبل أي إدانة؟","options":["تعليق إداري لمدة 10-day","إلغاء مدني لمدة 30-day","تعليق لمدة 90-day","لا إجراء حتى الإدانة"],"explanation":"يفرض قانون الموافقة الضمنية في نورث كارولينا (G.S. 20-16.5) إلغاءً مدنياً (قبل المحاكمة) لمدة 30-day لرخصة قيادة السائق عند نتيجة اختبار مؤهِّلة أو رفض، بشكل منفصل عن فقدان أهلية CDL الذي يتبع الإدانة."},"60":{"q":"على طريق سريع محدود الوصول في ولاية كارولاينا الشمالية يتكوّن من ست حارات أو أكثر، ما القيد الذي ينطبق على شاحنة يبلغ تصنيف وزنها الإجمالي للمركبة (GVWR) 26,001 رطل أو أكثر؟","options":["لا يجوز لها السير في الحارة اليسرى القصوى إلا عند الدخول أو الخروج، أو التجاوز، أو تجنّب خطر","يجب أن تسير دائماً في الحارة اليمنى القصوى فقط","يجوز لها استخدام أي حارة طالما تواكب حركة المرور","يجوز لها استخدام الحارة اليسرى القصوى فقط بين الساعة 9 مساءً و6 صباحاً"],"explanation":"تحظر المادة G.S. 20-146 في كارولاينا الشمالية على مركبة يبلغ تصنيف وزنها الإجمالي 26,001 رطل أو أكثر السير في الحارة اليسرى القصوى من طريق سريع محدود الوصول يتكوّن من ست حارات أو أكثر، إلا عند الدخول إلى الطريق أو الخروج منه، أو التجاوز، أو تجنّب خطر. المصدر: N.C. Gen. Stat. 20-146."},"61":{"q":"بموجب قانون \"التنحّي جانباً\" (Move Over) في كارولاينا الشمالية، ماذا يجب على السائق فعله عند الاقتراب من مركبة طوارئ أو مركبة خدمة عامة متوقفة تُظهر أضواء تحذير وامضة على طريق متعدد الحارات؟","options":["الانتقال إلى حارة ليست الأقرب إلى المركبة المتوقفة، إذا أمكن فعل ذلك بأمان","التوقف توقفاً تاماً في الحارة الحالية حتى تغادر المركبة","إطلاق البوق باستمرار أثناء المرور","المرور بسرعة لا تزيد عن 5 mph تحت حد السرعة المحدد"],"explanation":"بموجب المادة N.C. Gen. Stat. 20-157، على طريق به حارتان أو أكثر في اتجاه السير، يجب على السائق الانتقال إلى حارة ليست الأقرب إلى مركبة الطوارئ/الخدمة العامة المتوقفة عندما يمكن فعل ذلك بأمان. وعلى طريق ذي حارة واحدة يجب على السائق بدلاً من ذلك أن يبطئ السرعة ويكون مستعداً للتوقف. المصدر: N.C. Gen. Stat. 20-157."},"62":{"q":"يقترب سائق في كارولاينا الشمالية يقود مركبة تحمل لافتات مواد خطرة من معبر سكة حديد على مستوى الطريق. أين يجب على السائق التوقف؟","options":["ضمن 50 قدماً من أقرب قضيب، ولكن ليس أقرب من 15 قدماً منه","ضمن 25 قدماً من أقرب قضيب، ولكن ليس أقرب من 5 أقدام منه","ضمن 100 قدم من أقرب قضيب، ولكن ليس أقرب من 50 قدماً منه","على بُعد 10 أقدام بالضبط من أقرب قضيب"],"explanation":"يجب على الحافلات والمركبات الحاملة للافتات/المواد الخطرة التوقف ضمن 50 قدماً من أقرب قضيب، وليس أقرب من 15 قدماً منه، قبل العبور، ثم النظر والإصغاء. هذا المعيار الفيدرالي (49 CFR 392.10) يُدرَّس في دليل CDL لكارولاينا الشمالية وينطبق في الولاية. المصدر: N.C. CDL Driver Handbook; 49 CFR 392.10."},"63":{"q":"على طريق ذي حارتين في كارولاينا الشمالية (حارة واحدة في كل اتجاه)، تتوقف حافلة مدرسية وأضواؤها الحمراء وامضة وذراع التوقف ممدودة لتحميل الأطفال. أي المركبات يجب أن تتوقف؟","options":["يجب أن تتوقف حركة المرور القادمة من كلا الاتجاهين","يجب أن تتوقف فقط حركة المرور خلف الحافلة","يجب أن تتوقف فقط حركة المرور في الاتجاه المعاكس","لا يلزم توقف أحد إذا أبطأ السائقون إلى 20 mph"],"explanation":"بموجب المادة N.C. Gen. Stat. 20-217، على طريق ذي حارتين يجب على كل مركبة تقترب من الحافلة المدرسية المتوقفة من أي اتجاه على الطريق نفسه أن تتوقف توقفاً تاماً وتبقى متوقفة حتى تُسحب إشارة التوقف وتتحرك الحافلة. المصدر: N.C. Gen. Stat. 20-217(a)."},"64":{"q":"بموجب قانون توقّف الحافلة المدرسية في كارولاينا الشمالية، متى لا يكون على سائق مركبة تسير في الاتجاه المعاكس لحافلة مدرسية متوقفة أن يتوقف؟","options":["عندما يكون الطريق مقسوماً إلى طريقين بمساحة فاصلة أو حاجز مادي (وتُحتسب حارة الانعطاف الوسطى فقط إذا كان الطريق به أربع حارات على الأقل)","كلما كان للطريق خط وسطي مطلي من أي نوع","كلما كان هناك حارة واحدة في كل اتجاه","كلما أبطأ السائق المقابل إلى 15 mph أو أقل"],"explanation":"تُعفي المادة N.C. Gen. Stat. 20-217(c) حركة المرور المقابلة فقط حيث يكون الطريق مقسوماً إلى طريقين بمساحة فاصلة (بما في ذلك حارة وسطى للانعطاف لليسار إذا كان الطريق يتكوّن من أربع حارات إضافية على الأقل) أو بحاجز مادي. أما الخط الوسطي المطلي البسيط على طريق غير مقسوم فلا يستوفي الشرط. المصدر: N.C. Gen. Stat. 20-217(c)."},"65":{"q":"ما هو الحد الأقصى لحد السرعة الذي يجوز لوزارة النقل في كارولاينا الشمالية (North Carolina DOT) تحديده على طريق بين الولايات أو طريق محدود الوصول؟","options":["70 mph","65 mph","75 mph","60 mph"],"explanation":"بموجب المادة N.C. Gen. Stat. 20-141(b)، لا يجوز أن يتجاوز حد السرعة المحدد على نظام الطرق بين الولايات أو الطرق محدودة الوصول 70 ميلاً في الساعة. المصدر: N.C. Gen. Stat. 20-141."},"66":{"q":"على طريق في كارولاينا الشمالية حُدِّد فيه حد السرعة المعلن ليكون موحَّداً لجميع أنواع المركبات، كيف يقارَن حد سرعة الشاحنات بحد سرعة السيارات؟","options":["تخضع الشاحنات والسيارات لحد السرعة المعلن نفسه","تُقيَّد الشاحنات بحد أقل بمقدار 10 mph عن حد السيارات","تُقيَّد الشاحنات بـ 55 mph بغض النظر عن الحد المعلن","يجوز للشاحنات السير أسرع من السيارات بمقدار 5 mph على المنحدرات"],"explanation":"لا تحدد كارولاينا الشمالية حداً منفصلاً وأدنى للسرعة على مستوى الولاية للشاحنات؛ فالمادة G.S. 20-141(l) تجعل الحد المعلن منطبقاً بشكل موحّد على جميع أنواع المركبات الآلية. (يمكن أن ينطبق حد أدنى على مركبة معينة تسير بموجب تصريح للحجم/الوزن الزائد.) المصدر: N.C. Gen. Stat. 20-141(l)."},"67":{"q":"لماذا تُمنع الشاحنات التجارية على طريق Blue Ridge Parkway في كارولاينا الشمالية؟","options":["لأنه طريق ذو منظر خلاب ضيق ومتعرّج بحارتين دون حارات للشاحنات أو منحدرات هروب","لأنه طريق برسوم خاص مفتوح فقط لسيارات الركاب","لأنه يعبر إلى ولاية أخرى دون محطات وزن","لأن فيه جسوراً مقيّدة الوزن كل ميل"],"explanation":"تُمنع المركبات التجارية من طريق Blue Ridge Parkway لأنه طريق ذو منظر خلاب تابع لخدمة المتنزهات الوطنية، ضيق وبحارتين، بمنحدرات متغيّرة ومنعطفات ومسافة رؤية محدودة، ودون حارات للشاحنات أو منحدرات هروب للشاحنات. المصدر: National Park Service / Blue Ridge Parkway regulations."},"68":{"q":"تتعطّل شاحنة على طريق سريع مقسوم في كارولاينا الشمالية. أين ينبغي وضع أجهزة التحذير الطارئة الثلاثة (المثلثات العاكسة)؟","options":["على بُعد 10 أقدام و100 قدم و200 قدم إلى الخلف، جميعها باتجاه حركة المرور القادمة","على بُعد 10 أقدام و50 قدماً و150 قدماً، اثنان إلى الخلف وواحد إلى الأمام","على بُعد 5 أقدام و75 قدماً و250 قدماً إلى الخلف","على بُعد 25 قدماً و100 قدم و300 قدم إلى الخلف"],"explanation":"على طريق باتجاه واحد أو طريق مقسوم، تُوضع أجهزة التحذير الثلاثة جميعها باتجاه حركة المرور القادمة على بُعد 10 و100 و200 قدم من المركبة المتوقفة. (وعلى طريق ثنائي الاتجاه، يُوضع واحد على بُعد 10 أقدام إلى الخلف، وواحد على بُعد 100 قدم إلى الخلف، وواحد على بُعد 100 قدم إلى الأمام.) المصدر: N.C. CDL Driver Handbook; 49 CFR 392.22."},"69":{"q":"يمتد قانون \"التنحّي جانباً\" (Move Over) في كارولاينا الشمالية إلى ما هو أبعد من الشرطة والإطفاء وسيارات الإسعاف ليشمل أي فئة إضافية من المركبات؟","options":["مركبات المرافق وصيانة الطرق والمركبات المعطّلة/سيارات السحب التي تُظهر أضواء كهرمانية وامضة","أي سيارة ركاب تستخدم أضواءها الرباعية الوامضة","مركبات توصيل البريد فقط","مركبات الطوارئ من خارج الولاية فقط"],"explanation":"تشمل المادة N.C. Gen. Stat. 20-157 أيضاً \"مركبات الخدمة العامة\" التي تُظهر أضواء كهرمانية وامضة، بما في ذلك مركبات المرافق (الكهرباء والغاز والمياه والاتصالات) وصيانة الطرق والنفايات والمركبات المعطّلة/خدمة السحب. ويجب على السائقين التنحّي جانباً أو إبطاء السرعة لها. المصدر: N.C. Gen. Stat. 20-157."},"70":{"q":"بعد التوقف عند معبر سكة حديد، أي مما يلي ينبغي أن يفعله سائق حافلة أو سائق مركبة تحمل لافتات في كارولاينا الشمالية أثناء العبور؟","options":["العبور بترس لا يستلزم تبديل الغيار على القضبان","التبديل إلى ترس أدنى في منتصف العبور لاكتساب التحكم","التوقف مرة أخرى عند منتصف القضبان لإعادة التحقق","الانزلاق عبر القضبان في الوضع المحايد لتوفير الوقود"],"explanation":"يوجّه دليل CDL لكارولاينا الشمالية السائقين إلى اختيار ترس يتيح لهم العبور بالكامل دون تبديل الغيار، وعدم تبديل الغيار أبداً أثناء وجودهم على القضبان، تجنّباً لتعطّل المحرك. المصدر: N.C. CDL Driver Handbook; 49 CFR 392.10/392.11."},"71":{"q":"ما هو الحد الأدنى للغرامة في كارولاينا الشمالية لتجاوز حافلة مدرسية متوقفة تقوم بتحميل الأطفال أو إنزالهم بصورة غير قانونية؟","options":["$500 وجنحة من الدرجة الأولى (Class 1 misdemeanor)","$100 ومخالفة","$250 وجنحة من الدرجة الثالثة (Class 3 misdemeanor)","$1,000 وجنحة من الدرجة الثانية (Class 2 misdemeanor)"],"explanation":"بموجب المادة N.C. Gen. Stat. 20-217(e)، يُعد تجاوز حافلة مدرسية متوقفة جنحة من الدرجة الأولى (Class 1) تستوجب غرامة لا تقل عن $500، ولا يُسمح بتأجيل النطق بالحكم. ويؤدي إصابة شخص إلى رفعها إلى جناية مع غرامات دنيا أعلى. المصدر: N.C. Gen. Stat. 20-217(e),(g)."},"72":{"q":"على طريق Triangle Expressway وغيره من مرافق الرسوم التابعة لهيئة الطرق ذات الرسوم في كارولاينا الشمالية (مثل I-540)، كيف تُجمع الرسوم؟","options":["رسوم إلكترونية بالكامل دون أكشاك رسوم، باستخدام أجهزة الإرسال NC Quick Pass أو الفوترة بالبريد","أكشاك رسوم نقدية فقط عند كل تقاطع","رسم ملصق سنوي ثابت لجميع الشاحنات","تُجمع الرسوم فقط عند حدود الولاية"],"explanation":"تستخدم الطرق ذات الرسوم في كارولاينا الشمالية نظام رسوم إلكترونية بالكامل بنسبة 100% دون أكشاك؛ يدفع السائقون عبر جهاز إرسال/حساب NC Quick Pass أو يتلقّون فاتورة بالبريد. وتُفرض على الشاحنات رسوم أعلى بناءً على عدد المحاور. المصدر: NCDOT Turnpike Authority / NC Quick Pass."},"73":{"q":"ما هي الغرامة المعتادة لمخالفة أساسية لقانون \"التنحّي جانباً\" (Move Over) في كارولاينا الشمالية (دون إصابة أو ضرر بالممتلكات)؟","options":["مخالفة بقيمة $250","مخالفة بقيمة $50","جنحة من الدرجة الأولى بقيمة $500","جناية بقيمة $1,000"],"explanation":"تُعد المخالفة الأساسية للمادة N.C. Gen. Stat. 20-157 مخالفة يُعاقَب عليها بغرامة قدرها $250. وتتصاعد إلى جنحة عند وجود ضرر بالممتلكات يتجاوز $500 أو إصابة، وإلى جناية من الدرجة F إذا تسببت في إصابة خطيرة أو وفاة. المصدر: N.C. Gen. Stat. 20-157."},"74":{"q":"بموجب قاعدة الالتزام باليمين في كارولاينا الشمالية، أين يجب عادةً قيادة مركبة تسير بسرعة أبطأ من الحد الأقصى القانوني للسرعة؟","options":["في الحارة اليمنى المتاحة لحركة المرور العابرة، أو أقرب ما يمكن عملياً إلى الحافة اليمنى","في أي حارة تكون الأقل ازدحاماً","في الحارة الوسطى من طريق ذي ثلاث حارات","في الحارة اليسرى لترك الحارة اليمنى مفتوحة للاندماج"],"explanation":"تشترط المادة N.C. Gen. Stat. 20-146 أن تسير أي مركبة تتحرك بسرعة أقل من الحد الأقصى القانوني في حارة المرور العابرة اليمنى، أو أقرب ما يمكن عملياً إلى الحافة اليمنى، إلا عند التجاوز أو الاستعداد للانعطاف لليسار. المصدر: N.C. Gen. Stat. 20-146."},"75":{"q":"لأغراض قانون توقّف الحافلة المدرسية في كارولاينا الشمالية، أي مما يلي يُعامَل بوصفه \"حافلة مدرسية\" تستوجب توقّف حركة المرور الأخرى؟","options":["حافلة مدرسية عامة تنقل كبار السن بموجب المادة G.S. 115C-243 ومُعلَّمة بعبارة \"school bus\" من الأمام والخلف","أي شاحنة (فان) صفراء تستخدمها حضانة، سواء أكانت مُعلَّمة أم لا","حافلة سياحية مستأجرة بنوافذ معتمة","أي مركبة بأضواء فرملة حمراء"],"explanation":"تُعرّف المادة N.C. Gen. Stat. 20-217(b) الحافلة المدرسية المشمولة بأنها تشمل حافلة مدرسية عامة تنقل أطفالاً أو موظفين، أو حافلة مدرسية عامة تنقل كبار السن بموجب المادة G.S. 115C-243، أو حافلة مملوكة ملكية خاصة تنقل أطفالاً، ولكن فقط عندما تحمل لافتات \"school bus\" واضحة الرؤية من الأمام والخلف. المصدر: N.C. Gen. Stat. 20-217(b)."},"76":{"q":"عند أي معبر سكة حديد في كارولاينا الشمالية لا يُطلب من سائق CDL التوقف، حتى عند نقل مواد خطرة تحمل لافتات؟","options":["معبر يقوم فيه ضابط شرطة أو موجِّه إشارات بتوجيه حركة المرور عبره","أي معبر به علامات تقاطع (crossbucks) دون بوابات","معبر على طريق ريفي ذي حارتين","معبر بحد سرعة معلن يتجاوز 45 mph"],"explanation":"يُعفى من التوقف الإلزامي عند المعابر التي يتحكم فيها ضابط شرطة أو موجِّه إشارات، وعند مسارات الترام/التبديل الصناعي في منطقة تجارية، وعند المعابر المُعلَّمة بـ \"Exempt\" أو \"Abandoned\"، وحيث تُظهر إشارة مرور عاملة على الطريق اللون الأخضر. المصدر: N.C. CDL Driver Handbook; 49 CFR 392.10(b)."},"77":{"q":"تتوقف حافلة مدرسية على طريق في كارولاينا الشمالية به حارتا سير في كل اتجاه يفصل بينهما فقط حارة انعطاف وسطى مستمرة لليسار في الاتجاهين (طريق من خمس حارات). هل يجب أن تتوقف حركة المرور المقابلة؟","options":["لا، لأن حارة الانعطاف الوسطى لليسار تُعد مساحة فاصلة عندما يكون للطريق أربع حارات على الأقل","نعم، لأن حارة الانعطاف ليست حاجزاً مادياً","نعم، جميع الطرق تستوجب توقّف حركة المرور المقابلة","لا، حركة المرور المقابلة لا يلزمها التوقف أبداً على أي طريق متعدد الحارات"],"explanation":"تتيح المادة G.S. 20-217(c) لحركة المرور المقابلة المتابعة عندما يكون الطريق مقسوماً بمساحة فاصلة، وتشمل تحديداً حارة وسطى للانعطاف لليسار إذا كان الطريق يتكوّن من أربع حارات على الأقل. والطريق ذو الخمس حارات بحارة انعطاف وسطى يستوفي هذا الشرط، لذا لا يلزم توقّف حركة المرور المقابلة. المصدر: N.C. Gen. Stat. 20-217(c)."},"78":{"q":"يُدان سائق للمرة الثانية خلال ثلاث سنوات بتجاوز حافلة مدرسية متوقفة في كارولاينا الشمالية. ما هي العاقبة المتعلقة بالرخصة إضافةً إلى الغرامة؟","options":["إلغاء رخصة القيادة لمدة سنة واحدة","تعليق لمدة 30 يوماً فقط","لا يُتخذ أي إجراء بشأن الرخصة، مجرد نقاط","إلغاء دائم عند المخالفة الثانية"],"explanation":"بموجب المادة N.C. Gen. Stat. 20-217(g1)، تؤدي الإدانة الثانية بجنحة بموجب هذا القسم خلال فترة ثلاث سنوات إلى إلغاء الرخصة لمدة سنة واحدة؛ كما يُحرَم حامل CDL من قيادة مركبة تجارية خلال تلك الفترة. المصدر: N.C. Gen. Stat. 20-217(g1)."},"79":{"q":"يجوز لكارولاينا الشمالية تحديد حد سرعة معلن أدنى لمركبة تجارية معينة في أي من الحالات؟","options":["عندما تسير المركبة بموجب تصريح خاص للحجم/الوزن الزائد بسبب وزنها أو أبعادها","كلما كان للمركبة أكثر من محورين","كلما كانت المركبة مسجَّلة خارج الولاية","كلما كانت المقطورة أطول من 40 قدماً"],"explanation":"تتيح المادة N.C. Gen. Stat. 20-141(l) تحديد حد سرعة أدنى لمركبة تسير بموجب تصريح خاص بسبب أي وزن أو بُعد للمركبة أو حمولتها. وفيما عدا ذلك يكون الحد المعلن موحَّداً لجميع أنواع المركبات. المصدر: N.C. Gen. Stat. 20-141(l); NCDOT oversize/overweight permit rules."},"80":{"q":"ما هي الجهة التي تُصدر رخص القيادة التجارية (CDLs) في كارولاينا الشمالية؟","options":["الإدارة الفيدرالية لسلامة الناقلات الآلية (FMCSA)","وزارة السلامة العامة في كارولاينا الشمالية","دورية الطرق السريعة بوزارة النقل في كارولاينا الشمالية","شعبة المركبات الآلية في كارولاينا الشمالية (NCDMV)"],"explanation":"في كارولاينا الشمالية، تُصدر رخص CDL وتديرها شعبة المركبات الآلية في كارولاينا الشمالية (NCDMV)، وهي شعبة تابعة لـ NCDOT. وتضع FMCSA المعايير الفيدرالية لكنها لا تُصدر الرخص. المصدر: NCDMV Commercial Driver License page و N.C. CDL Manual, Section 1."},"81":{"q":"للحصول على رخصة CDL أو تصريح متعلّم تجاري في كارولاينا الشمالية، ما نوعا الاختبارين اللذين يجب على مقدّم الطلب اجتيازهما؟","options":["اختبار تحريري واختبار وزن المركبة","اختبارات المعرفة واختبارات المهارات","اختبار للياقة البدنية واختبار التصديق","اختبار طريق لدى صاحب العمل واختبار فيدرالي"],"explanation":"ينص دليل CDL لكارولاينا الشمالية (Section 1.1) على أنه للحصول على رخصة CDL أو CLP يجب اجتياز اختبارات المعرفة واختبارات المهارات. ويُجرى اختبار المهارات في فئة المركبة التي ترغب في الترخيص لها. المصدر: N.C. CDL Manual, Section 1.1."},"82":{"q":"يتكوّن اختبار مهارات CDL في كارولاينا الشمالية من أي ثلاثة أجزاء؟","options":["معرفة تحريرية، وفحص نظر، واختبار طريق","فحص فرامل الهواء، واختبار الوصل، واختبار طريق سريع","فحص المركبة (قبل الرحلة)، والتحكم الأساسي بالمركبة، والقيادة على الطريق","الرجوع للخلف، والركن الموازي، واختبار قيادة ليلية"],"explanation":"وفقاً لدليل CDL لكارولاينا الشمالية (Section 1.1.2)، يتكوّن اختبار المهارات من ثلاثة أجزاء: اختبار فحص المركبة (قبل الرحلة)، واختبار التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. ويجب اجتياز الأجزاء الثلاثة جميعها في الفئة المناسبة من المركبات. المصدر: N.C. CDL Manual, Section 1.1.2."},"83":{"q":"أي اختبار معرفة يجب على كل مقدّم طلب CDL في كارولاينا الشمالية أن يجتازه، بغض النظر عن الفئة أو التصديقات؟","options":["اختبار المعرفة العامة","اختبار المركبات المركّبة","اختبار فرامل الهواء","اختبار المواد الخطرة"],"explanation":"ينص دليل CDL لكارولاينا الشمالية (Section 1.1.1) على أن اختبار المعرفة العامة يخضع له جميع مقدّمي الطلبات. أما الاختبارات الأخرى (المركّبة، فرامل الهواء، المواد الخطرة، إلخ) فتنطبق فقط على فئات أو تصديقات محددة. المصدر: N.C. CDL Manual, Section 1.1.1."},"84":{"q":"ما هو الحد الأدنى لدرجة النجاح في كل اختبار معرفة CDL في كارولاينا الشمالية؟","options":["70% إجابات صحيحة","80% إجابات صحيحة","75% إجابات صحيحة","85% إجابات صحيحة"],"explanation":"تشترط كارولاينا الشمالية ما لا يقل عن 80% من الإجابات الصحيحة في كل اختبار معرفة CDL (على سبيل المثال، 40 من 50 في اختبار المعرفة العامة، و16 من 20 في المركّبة أو فرامل الهواء)، وتُحتسب كل منها على حدة. المصدر: NCDMV CDL knowledge testing standards (الحد الأدنى لـ FMCSA المعتمد من قبل الولاية)."},"85":{"q":"ما هي مدة صلاحية تصريح المتعلّم التجاري (CLP) في كارولاينا الشمالية؟","options":["30 يوماً، دون السماح بالتجديد","180 يوماً، مع تجديد واحد لمدة 180 يوماً إضافية","سنة واحدة، مع عدد غير محدود من التجديدات","60 يوماً، قابلة للتجديد مرة واحدة لمدة 60 يوماً"],"explanation":"يكون تصريح CLP في كارولاينا الشمالية صالحاً لمدة 180 يوماً ويمكن تجديده مرة واحدة لمدة 180 يوماً إضافية دون إعادة اجتياز اختبار المعرفة العامة. المصدر: NCDMV Commercial Driver License page؛ N.C. CDL Manual (CLP)، بما يتسق مع 49 CFR 383.25."},"86":{"q":"بعد إصدار تصريح CLP في كارولاينا الشمالية، كم يجب أن ينتظر مقدّم الطلب قبل إجراء اختبار مهارات CDL؟","options":["30 يوماً على الأقل","7 أيام على الأقل","60 يوماً على الأقل","14 يوماً على الأقل"],"explanation":"يجب على حامل CLP الانتظار 14 يوماً على الأقل بعد إصدار CLP قبل إجراء اختبار مهارات CDL. وتطبّق NCDMV هذه القاعدة الفيدرالية (49 CFR 383.25). المصدر: NCDMV Commercial Driver License page; 49 CFR 383.25."},"87":{"q":"قبل أن يتمكن مقدّم طلب من الفئة A أو الفئة B لأول مرة في كارولاينا الشمالية من إجراء اختبار مهارات CDL، ما التدريب الفيدرالي الذي يجب إكماله؟","options":["دورة قيادة دفاعية تديرها الولاية في مكتب NCDMV","120 ساعة من القيادة الفعلية مسجَّلة مع أي حامل رخصة CDL","تدريب السائقين المبتدئين (ELDT) من مزوّد مدرَج في سجل مزوّدي التدريب لدى FMCSA","شهادة سلامة في مكان العمل من OSHA"],"explanation":"يجب إكمال تدريب السائقين المبتدئين الفيدرالي (ELDT) عبر مزوّد مدرَج في سجل مزوّدي التدريب لدى FMCSA قبل اختبار رخصة CDL من الفئة A/B لأول مرة (وكذلك لتصديقات P و S و H أو الترقية من B إلى A). المصدر: NCDMV CDL page؛ FMCSA ELDT rule (49 CFR Part 380)."},"88":{"q":"إلى جانب مقدّمي طلبات الفئة A والفئة B لأول مرة، يُشترط ELDT أيضاً قبل الاختبار لأي تصديقات؟","options":["الصهريج (N)، والمزدوجة/الثلاثية (T)، وفرامل الهواء","المركّبة، وفرامل الهواء، والصهريج (N)","الركاب (P)، والحافلة المدرسية (S)، والمواد الخطرة (H)","المواد الخطرة (H) فقط"],"explanation":"ينطبق ELDT قبل إصدار الفئة A/B لأول مرة، والترقية من B إلى A، وتصديقات الركاب (P) والحافلة المدرسية (S) والمواد الخطرة (H). ويتطلب تصديق H تدريب ELDT النظري فقط. المصدر: NCDMV CDL page؛ FMCSA ELDT rule (49 CFR Part 380)."},"89":{"q":"يجب على مقدّمي طلبات CDL في كارولاينا الشمالية أن يقرّوا ذاتياً بنوع قيادتهم التجارية. كم عدد فئات الإقرار الذاتي؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"هناك أربع فئات للإقرار الذاتي: بين الولايات غير مستثناة، وبين الولايات مستثناة، وداخل الولاية غير مستثناة، وداخل الولاية مستثناة. ويؤشّر مقدّم الطلب على الخانة التي تطابق عمليته. المصدر: N.C. CDL Manual, Section 1.2.3."},"90":{"q":"أي فئة من فئات الإقرار الذاتي في كارولاينا الشمالية تتطلب من السائق تقديم شهادة فاحص طبي فيدرالي تابع لـ DOT والحفاظ عليها؟","options":["بين الولايات مستثناة","بين الولايات غير مستثناة","داخل الولاية مستثناة","خاصة بنقل الركاب مستثناة"],"explanation":"يقرّ السائق ضمن فئة \"بين الولايات غير مستثناة\" بأنه خاضع للمتطلبات الطبية الفيدرالية لـ DOT بموجب 49 CFR Part 391 ومستوفٍ لها، ويجب عليه الحصول على شهادة فاحص طبي. ومعظم حاملي رخص CDL بين الولايات هم ضمن فئة غير مستثناة. المصدر: N.C. CDL Manual, Section 1.2.3."},"91":{"q":"السائق في كارولاينا الشمالية الذي يعمل في التجارة بين الولايات فقط ولكن حصراً في عمليات مستثناة من 49 CFR Part 391 ينبغي أن يقرّ ذاتياً بأنه:","options":["بين الولايات غير مستثنى","داخل الولاية غير مستثنى","بين الولايات مستثنى","داخل الولاية مستثنى"],"explanation":"يقرّ السائق ضمن فئة \"بين الولايات مستثنى\" بأنه يعمل في التجارة بين الولايات لكنه يمارس حصراً عمليات مستثناة بموجب 49 CFR 390.3(f)، 391.2، 391.68 أو 398.3، ولا يُطلب منه الحصول على شهادة فاحص طبي. المصدر: N.C. CDL Manual, Section 1.2.3."},"92":{"q":"بموجب قواعد كارولاينا الشمالية، إذا كان السائق يعمل في التجارة بين الولايات وداخل الولاية معاً، أي فئة يجب أن يختار؟","options":["التجارة داخل الولاية","التجارة بين الولايات (الفئة الأكثر تطلّباً)","أيهما يقود في الغالب","يجوز له اختيار أي منهما بحرية"],"explanation":"ينص دليل CDL لكارولاينا الشمالية (Section 1.2.1) على أن السائق الذي يعمل في التجارة بين الولايات وداخل الولاية معاً يجب أن يختار التجارة بين الولايات، لأنها تحمل متطلبات التأهيل الأكثر صرامة. المصدر: N.C. CDL Manual, Section 1.2.1."},"93":{"q":"بموجب إجراء السجل الوطني لـ FMCSA المستخدم الآن في كارولاينا الشمالية، كيف تصل شهادة الفاحص الطبي لـ DOT لسائق غير مستثنى إلى NCDMV عادةً؟","options":["يجب على السائق إرسال نسخة ورقية مباشرة بالبريد إلى NCDMV كل سنتين","يرسل صاحب العمل البطاقة الطبية بالفاكس إلى مقر NCDMV","يتصل طبيب السائق بالوحدة الطبية في NCDMV للإبلاغ عن النتائج","يقدّم الفاحص الطبي المعتمد نتائج الفحص إلكترونياً إلى السجل الوطني لـ FMCSA، الذي ينقلها إلى NCDMV"],"explanation":"بموجب إجراء السجل الوطني لـ FMCSA / NRII (الامتثال في عام 2025)، يقدّم الفاحصون الطبيون المعتمدون نتائج فحوص CDL/CLP إلكترونياً إلى السجل الوطني، وتنقل FMCSA حالة التصديق الطبي إلى الولاية (NCDMV). ولم يعد على السائقين تسليم البطاقة الورقية إلى NCDMV. المصدر: FMCSA National Registry rule؛ NCDMV medical certification guidance."},"94":{"q":"يُطلب الإقرار الذاتي بفئة تجارة السائق في كارولاينا الشمالية في أي من هذه الأوقات؟","options":["مرة واحدة فقط، عند إصدار رخصة CDL الأصلية لأول مرة","فقط عندما يغيّر السائق أصحاب العمل","عند التقديم لـ CLP، وعند التجديد أو الترقية أو إضافة تصديقات أو نقل رخصة CDL","فقط عندما يبلغ السائق 65 عاماً"],"explanation":"يجب على السائقين تقديم معلومات الإقرار الذاتي إلى الولاية عند التقديم لـ CLP، وعند تجديد رخصة CDL أو ترقيتها أو إضافة تصديقات إليها أو نقلها. المصدر: N.C. CDL Manual, Section 1.2 (المتطلبات الفيدرالية للتصديق الطبي)."},"95":{"q":"ما هي مدة الصلاحية المعتادة لرخصة CDL في كارولاينا الشمالية (لرخصة مجدَّدة، لسائق دون 65 عاماً)؟","options":["5 سنوات","4 سنوات","8 سنوات","10 سنوات"],"explanation":"بموجب المادة N.C.G.S. 20-7، تنتهي صلاحية رخصة القيادة التجارية المجدَّدة بعد خمس سنوات من تاريخ انتهاء الرخصة الجاري تجديدها. ولا يمكن تجديد رخص CDL عبر الإنترنت ويجب تجديدها شخصياً في مكتب NCDMV. المصدر: N.C.G.S. 20-7؛ NCDMV license renewal page."},"96":{"q":"كيف يختلف تجديد رخصة CDL في كارولاينا الشمالية عن تجديد رخصة قياسية (الفئة C)؟","options":["يمكن تجديد رخصة CDL عبر الإنترنت لمدة تصل إلى سنتين بعد انتهاء صلاحيتها","تُجدَّد رخصة CDL تلقائياً عبر الناقل الآلي لصاحب العمل","لا تنتهي صلاحية رخصة CDL أبداً بمجرد اجتياز السائق لاختبار الطريق","يجب تجديد رخصة CDL شخصياً في مكتب رخص القيادة التابع لـ NCDMV؛ ولا يمكن تجديدها عبر الإنترنت أو بالبريد"],"explanation":"يجب تجديد رخص CDL في كارولاينا الشمالية شخصياً في مكتب رخص القيادة التابع لـ NCDMV ولا يمكن تجديدها عبر الإنترنت أو بالبريد، على عكس العديد من الرخص القياسية. المصدر: NCDMV license renewal/replacement page؛ N.C.G.S. 20-7."},"97":{"q":"عند التقديم للحصول على CLP في كارولاينا الشمالية، أي من المستندات التالية مطلوب كجزء من الطلب؟","options":["إثبات الهوية/العمر، ورقم الضمان الاجتماعي، والإقامة، وإثبات تأمين المسؤولية","شهادة الثانوية العامة وخطاب موثّق من صاحب العمل","جواز سفر فقط، دون أي وثائق أخرى","إثبات ملكية المركبة وسند ملكية المركبة"],"explanation":"تشترط NCDMV على مقدّم طلب CLP تقديم إثبات الهوية والعمر، وإثبات رقم الضمان الاجتماعي، ومستندَي إقامة (إثبات الوجود القانوني لغير المواطنين)، وإثبات تأمين المسؤولية من مزوّد مرخَّص في كارولاينا الشمالية. المصدر: NCDMV Commercial Driver License page."},"98":{"q":"في كارولاينا الشمالية، كم عدد المحاولات المسموح بها في اختبار معرفة CDL واحد في اليوم نفسه؟","options":["محاولة واحدة لكل اختبار في اليوم","ثلاث محاولات لكل اختبار في اليوم","محاولات غير محدودة في اليوم نفسه","محاولتان لكل اختبار في اليوم"],"explanation":"ينص دليل CDL لكارولاينا الشمالية على أنه يُسمح بمحاولة واحدة فقط لكل اختبار معرفة في اليوم. وبعد ثلاث محاولات فاشلة في اختبار المعرفة العامة، يلزم دفع رسم طلب آخر للمحاولات الثلاث التالية. المصدر: N.C. CDL Manual, Section 1.1."},"99":{"q":"بمجرد اجتيازها، كم مدة صلاحية درجات اختبار CDL في كارولاينا الشمالية ضمن ملفات حاسوب NCDMV؟","options":["30 يوماً من تاريخ الاختبار","180 يوماً من تاريخ الاختبار","سنة واحدة من تاريخ الاختبار","90 يوماً من تاريخ الاختبار"],"explanation":"يشير دليل CDL لكارولاينا الشمالية إلى أن جميع درجات الاختبار صالحة لمدة 90 يوماً من تاريخ الاختبار ضمن ملفات حاسوب NCDMV. ويجب على مقدّم الطلب إكمال المتطلبات المتبقية خلال تلك المدة. المصدر: N.C. CDL Manual, Section 1.1."}}};
